  Tensor* output_indices;
  TF_RETURN_IF_ERROR(
      c->allocate_temp(DT_INT64, output_tensor->shape(), &output_indices));
  auto output_flat = output_indices->flat<int64_t>();
  auto output_tensor_flat = output_tensor->flat<T>();
