	int len;

	if (parse_config_key(var, "submodule.", &key, &np, &len) < 0)
		return 0;

	if (len && !value)
		return report(opts, NULL, "submodule %.*s is missing value",
			       len, key);

	if (check_submodule_name(opts, key, np, value))
		return -1;

	return 0;
