	if (IS_ERR(rt)) {
		atomic_long_inc(&ip_forward_errors);
		kfree_skb(skb);
		return PTR_ERR(rt);
	}

	skb_dst_drop(skb);
	skb->dst = (struct dst_entry *)rt;

	skb->tstamp.tv64 = 0;
	NF_HOOK(NFPROTO_IPV4, NF_INET_POST_ROUTING, skb, NULL, dev,
		ip_forward_finish);
