	if (unlikely(skb->len < sizeof(*iph))))
		goto out;

	/* If the packet is to or from a loopback interface, drop it */
	if (unlikely(skb->pkt_type == PACKET_LOOPBACK))
		goto out;

	if (unlikely(!skb->dst->output))
		return -ENODEV;

	if (IPCB(skb)->flags&IPCB_ROUTED)
