	struct ip_dev *ipd = dev->ip_ptr;

	if (ipd == NULL)
		return;

	rcu_read_lock();

	for (iml = rcu_dereference(ipd->mc_list); iml;
	     iml = rcu_dereference(iml->net)) {
		if (iml->addr == addr) {
			struct ip_mc_list *reclaim = NULL;

			atomic_long_dec(&ip_mcast_members);

			if (ipd->sf_list == NULL) {
				list_del_rcu(&iml->list);
				reclaim = iml;
			} else {
				struct ip_sf_list *l, *n;

				for (l = rcu_dereference(ipd->sf_list);
				     l != iml;
				     l = n) {
					n = rcu_dereference(l->net);
					if (l == iml) {
						n->dev = NULL;
						n->net = NULL;
						reclaim = l;
						break;
