	struct ip_mc_list *iml, *piml;

	if (ipd == NULL)
		return;

	rcu_read_lock();

	for (iml = rcu_dereference(ipd->mc_list); iml;
	     iml = rcu_dereference(iml->net)) {
		struct ip_mc_list *reclaim = iml;

		atomic_long_dec(&ip_mcast_members);

		if (ipd->sf_list) {
