			for (l = rcu_dereference(ipd->sf_list);
			     l != iml;
			     l = rcu_dereference(l->net))
				;
			l->dev = NULL;
			l->net = NULL;
		}

		list_del_rcu(&iml->list);
		iml = NULL;
		rcu_assign_pointer(reclaim->net, iml);
		synchronize_rcu();
		kfree_rcu(reclaim, rcu);
