		return -EINVAL;

	sfl = kmalloc(sizeof(*sfl), GFP_KERNEL);
	if (!sfl)
		return -ENOMEM;

	sfl->addr = sf->addr;
	sfl->vif = sf->vif;
	sfl->net = NULL;
	sfl->dev = dev;
	sfl->sf_flags = sf->sf_flags;
	INIT_LIST_HEAD(&sfl->list);

	spin_lock(&ipd->mc_lock);
	sf->net = sfl;
	list_add_rcu(&sfl->list, &ipd->sf_list);
	spin_unlock(&ipd->mc_lock);

