	struct ip_sf_list *sfl;

	if (ipd == NULL)
		return -EINVAL;

	spin_lock(&ipd->mc_lock);
	for (sfl = rcu_dereference(ipd->sf_list); sfl;
	     sfl = rcu_dereference(sfl->net)) {
		if (sfl == sf) {
			list_del_rcu(&sfl->list);
			sf->net = NULL;
			break;
		}
	}
	spin_unlock(&ipd->mc_lock);

