		}
		spin_unlock(&ipd->sf_lock);
	} else if (event == NETDEV_POST_TYPE_CHANGE) {
		struct net_device *old_dev = ptr;

		if (old_dev != dev)
			return NOTIFY_DONE;

		ip_mc_handle_src_change(dev);
	}

	return NOTIFY_DONE;
}static int ip_mc_net_event(struct notifier_block *this, unsigned long event,
			    void *ptr)
{
	struct net *net = ptr;
	struct ip_mc_list *iml, *iml1;
	struct ip_sf_list *psf;
	int err = 0;

	if (event == RTM_NEWLINK) {
		struct netlink_notify *nlnotify = ptr;

		ip_mc_init_net(net);

		if (nlnotify->ifinde) {
			struct net_device *dev;

			dev = __dev_get_by_index(net, nlnotify->ifinde);
			if (dev)
				ip_mc_init_dev(dev);
		}
	} else if (event == RTM_DELLINK) {
		if (nlmsg_notify_netlink(&rtmsg_netlink, net, 0, 0,
					  nlnotify->portid, GFP_ATOMIC))
			err = -ENOBUFS;
	} else if (event == RTM_IFINFO) {
		struct netlink_notify *nlnotify = ptr;
		struct net_device *dev;

		dev = __dev_get_by_index(net, nlnotify->ifinde);
		if (!dev)
			return NOTIFY_DONE;

		if (dev->flags&IFF_UP)
			ip_mc_init_dev(dev);
		else
			ip_mc_uninit_dev(dev);

		if (nlnotify->change&~IFF_UP)
			return NOTIFY_DONE;

		if (dev->flags&IFF_UP) {
			ip_mc_start_timer(dev);
			ip6_mc_start_timer(dev);
		} else {
			ip_mc_stop_timer(dev);
			ip6_mc_stop_timer(dev);
		}
	} else if (event == RTM_NEWROUTE) {
		struct rtmsg *rtm = ptr;

		if (rtm->rtm_family == AF_INET && rtm->rtm_table == RT_TABLE_DEFAULT)
			atomic_long_inc(&ip_forwarding);
	} else if (event == RTM_DELROUTE) {
		struct rtmsg *rtm = ptr;

		if (rtm->rtm_family == AF_INET && rtm->rtm_table == RT_TABLE_DEFAULT)
			atomic_long_dec(&ip_forwarding);
	}

	return err;
}static int __net_init ip_net_init(struct net *net)
{
	spin_lock_init(&net->ipv4.ime->lock);
	net->ipv4.ime->mcfree = NULL;
	atomic_long_set(&net->ipv4.ime->mcast_members, 0);
	net->ipv4.ime->flags = ip_defaults.sysctl_flags;
	net->ipv4.ime->mc_max_vif = 0;
	net->ipv4.ime->mcast_rejoin = 0;
	return 0;
}static void __net_exit ip_net_exit(struct net *net)
{
	struct ip_mc_list *iml, *iml1;
	struct ip_sf_list *psf, *psf1;
	struct ip_dev *ipd;
	int i;

	/* Release all multicast address records. */
	for (i = 0; i < IP_MCAST_MAX_HASH; i++) {
		hlist_for_each_entry(iml, &net->ipv4.ime->mcast_hash[i], hlist) {
			hlist_del_rcu(&iml->hlist);
			kfree_rcu(iml, rcu);
		}
	}

	for (i = 0; i < 8; i++) {
		hlist_for_each_entry(iml, &net->ipv4.ime->mcast_vif_hash[i], vif_hlist) {
			hlist_del_rcu(&iml->vif_hlist);
			kfree_rcu(iml, rcu);
		}
	}

	/* Release all source address records. */
	list_for_each_entry(ipd, &net->ipv4.ime->dev_list, dev_list) {
		for (psf = ipd->sf_list; psf; psf = psf1) {
			psf1 = psf->net;
			list_del_rcu(psf);
			kfree_rcu(psf, rcu);
		}
	}

	/* Release the loopback device entry. */
	ipd = net->ipv4.ime->loopback;
	if (ipd) {
		ipd->net = NULL;
		list_del_rcu(ipd);
		kfree_rcu(ipd, rcu);
	}
}static struct pernet_operations ip_net_ops = {
	.init = ip_net_init,
	.exit = ip_net_exit,
	.size = sizeof(struct ip_dev),
};static int __init ip_init(void)
{
	int err;

	err = register_pernet_operation(&ip_net_ops);
	if (err < 0)
		goto out;

	err = -ENOMEM;

	ip_rt_init();

	ip_mc_init();

	ip_init_early();

	ip_fib_init();

	ip6_init();

	ip_vs_init();

	ip_tunnel_init();

	ip_forward_init();

	igmp_init();

	/* Start software GSO and GRO timers */
	open_softnet_controller();

out:
	return err;
}static void ip_cleanup(void)
{
	rtnl_link_unregister(&ip6_rtnl_link_ops);
	rtnl_link_unregister(&ip_rtnl_link_ops);

	ip6_cleanup();
	ip_fib_cleanup();
	ip_forward_cleanup();
	igmp_cleanup();
	ip_vs_cleanup();
	ip_tunnel_cleanup();
	/* Stop software GSO and GRO timers */
	close_softnet_controller();
}late_initcall(ip_init);
module_exit(ip_cleanup);

static struct notifier_block ip_netdev_notifier = {
	.notifier_call = ip_mc_dev_net_event,
};

static struct notifier_block ip_notifier = {
	.notifier_call = ip_mc_net_event,
};

static int __init ip_mc_init(void)
{
	int err;

	err = register_netdevice_notifier(&ip_netdev_notifier);
	if (err < 0)
		goto out;

	err = register_netdevice_notifier(&ip_notifier);
	if (err < 0)
		goto out1;

	err = netlink_register(&rtmsg_netlink);
	if (err < 0)
		goto out2;

	rtnl_link_register(&ip6_rtnl_link_ops);
	rtnl_link_register(&ip_rtnl_link_ops);

	return 0;

out2:
	register_netdevice_notifier(&ip_notifier);
out1:
	register_netdevice_notifier(&ip_netdev_notifier);
out:
	return err;
}static void ip_mc_cleanup(void)
{
	rtnl_link_unregister(&ip_rtnl_link_ops);
	rtnl_link_unregister(&ip6_rtnl_link_ops);
	netlink_unregister(&rtmsg_netlink);
	unregister_netdevice_notifier(&ip_notifier);
	unregister_netdevice_notifier(&ip_netdev_notifier);
}subsys_initcall(ip_mc_init);
module_exit(ip_mc_cleanup);

