{
	struct proto *prot;
	int err;

	/* Init per-net namespaces book-keeping */
	err = ipip_net_init(net);
	if (err)
		goto out;

	err = xfrm4_net_init(net);
	if (err)
		goto out_ipip;

	err = tnl4_net_init(net);
	if (err)
		goto out_xfrm;

	err = mib_net_init(net);
	if (err)
		goto out_tnl;

	/* Create virtual devices */
	prot = &udp_protocol;
	err = __udp4_register_net(net, prot);
	if (err < 0)
		goto out_mib;

	prot = &tcp_protocol;
	err = __tcp4_register_net(net, prot);
	if (err < 0)
		goto out_udp;

	prot = &icmp_protocol;
	err = __icmpv4_register_net(net, prot);
	if (err < 0)
		goto out_tcp;

	prot = &icmpv6_protocol;
	err = __icmpv6_register_net(net, prot);
	if (err < 0)
		goto out_icmp;

	prot = &igmp_protocol;
	err = __igmp_register_net(net, prot);
	if (err < 0)
		goto out_icmpv6;

	prot = &ip_protocol;
	err = __ip_register_net(net, prot);
	if (err < 0)
		goto out_igmp;

	/* This has to be called last, because the IPv6 handler is used
	 * by the IPv4 code for sysctl parameters out of range values.
	 */
	err = ip6_dst_ops_init(net);
	if (err)
		goto out_ip;

out_netdev:	
	ipv4_dev_init(net);
out:
	return err;

out_ip6_dst:
	ip6_dst_ops_exit(net);
out_ip:
	__ip_unregister_net(net);
out_igmp:
	__igmp_unregister_net(net);
out_icmpv6:
	__icmpv6_unregister_net(net);
out_icmp:
	__icmpv4_unregister_net(net);
out_tcp:
	__tcp4_unregister_net(net);
out_udp:
	__udp4_unregister_net(net);
out_mib:
	mib_net_exit(net);
out_tnl:
	tnl4_net_exit(net);
out_xfrm:
	xfrm4_net_exit(net);
out_ipip:
	ipip_net_exit(net);
	goto out_netdev;
}static void __net_exit ipv4_net_exit(struct net *net)
{
	ip6_dst_ops_exit(net);

	__ip_unregister_net(net);

	__igmp_unregister_net(net);

	__icmpv6_unregister_net(net);

	__icmpv4_unregister_net(net);

	__tcp4_unregister_net(net);

	__udp4_unregister_net(net);

	mib_net_exit(net);

