	if (!stsd || !stsd->child_bo) return GF_BAD_PARAM;
	entry = (GF_MPEGVisualSampleEntryBo *)gf_list_get(stsd->child_bo, 0);
	if (!entry || entry->type != GF_ISOM_BOX_TYPE_ENCA) return GF_BAD_PARAM;
	sample_size = entry->sample_size;
