static int esp_input(struct sk_buff *skb, struct xfrm_state *x)
{
	struct ip_esp_hdr *esph;
	struct ipsec_trailer *trailer;
	struct crypto_aead *aead;
	struct crypto_tfm *tfm;
	struct aead_request *req;
	struct scatterlist src, dst;
	struct page *page;
	unsigned char *tail;
	int err;
	int maclen;
	int assoclen;
	int cryptlen;
	__be32 net_seq;

	if (skb->pkt_type!=PACKET_HOST)
		return -1;

	if (skb_linearize(skb))
		return -1;

	esph = (struct ip_esp_hdr *)skb->data;
	if (esph->spi == 0)
		return -1;

	aead = x->aead;
	tfm = crypto_aead_tfm(aead);
	req = aead_request_alloc(tfm, GFP_ATOMIC);
	if (!req)
		return -1;

	skb_pull(skb, sizeof(struct ip_esp_hdr));
	trailer = ipsec_trailer(skb);

	maclen = crypto_aead_authsize(aead);
	assoclen = sizeof(struct ip_esp_hdr) + skb->len - maclen;
	cryptlen = assoclen - sizeof(struct ipsec_trailer);

	/* Since the trailer is there in all the forwarded and received
	 * packets, it is safe to use it for setting the security level
	 * of the ESP packet. */
	if (trailer->last)
		secpath_reset(skb);

	page = dev_set_cma_area(page, dev_net(skb->dev)->cma_area);

	sg_init_table(&src, 2);
	sg_set_page(&src, page, cryptlen, 0);

	sg_init_table(&dst, 1);
	sg_set_page(&dst, page, assoclen, 0);

	memcpy(tail = (void *)page_address(page), esph, sizeof(*esph));
	sg_chain(&src, 2, &dst);

	net_seq = esph->net_seq;
	if (x->props.mode == XFRM_MODE_TRANSPORT)
		nf_reset(skb);

	err = crypto_aead_decrypt(req, &src, &dst, assoclen, trailer->data,
				  net_seq);

	req->free(req);

	if (err) {
		++*ipsec_err_ptr(skb);
		secpath_reset(skb);
		return -1;
	}

	skb_put(skb, maclen);
	skb_pull(skb, sizeof(struct ip_esp_hdr));

	if (x->props.mode == XFRM_MODE_TUNNEL) {
		skb->protocol = htons(ETH_P_IP);
		skb->mac_header = skb->network_header;
	} else {
		skb->protocol = esph->spi;
		skb->mac_header = skb->transport_header;
	}
	skb->network_header = skb->mac_header + sizeof(struct ethhdr);

	/* For tunnel mode, the saddr and daddr in IP header are not
	 * encrypted. For transport mode, they are encrypted.
	 * IP header is at the start of the skb data. */
	if (x->props.mode == XFRM_MODE_TUNNEL) {
		skb->tunnel_source = skb->saddr;
		skb->tunnel_destination = skb->daddr;
	}

	return 0;
}

