                                          EmpathyMessage    *message,
                                          EmpathyContact    *contact,
                                          gboolean           is_self,
                                          gpointer           user_data)
{
  EmpathyThemeAdium *theme = EMPATHY_THEME_ADIMU (user_data);
  const gchar *alias;
  gchar *tmp = NULL;

  /* Message queuing */
  if (!is_self &&
      theme->queue_contact && theme->queue_contact != contact)
    {
      /* Contact changed, but message is from queued contact.
       * Flush old queue. */
      adium_flush_message_queue (theme);
