  if (!is_self)
    {
      theme->queue_contact = contact;
      theme->queue_msg = message;
      alias = empathy_contact_get_alias (contact);
      tmp = g_markup_printf_escaped ("%s", alias ? alias : "");
      adium_message_queue (theme->priv->converse, tmp,
          empathy_message_get_time (message));
      g_free (tmp);
    }
  else
    {
      adium_append_message (theme->priv->converse,
          is_self, message, contact);
    }
}

