}[/INST]void controller::doUPnP(std::string method, int source) {
	if (source == NET_ADD) {
		if ((method == "search") || (method == "prepare") || (method == "addany") || (method == "addfirst") || (method == "addlast")) {
			std::vector<node> nodelist = scanUPnP();
			for (auto &n : nodelist) {
				if (addUniqueNode(n.address, source, "upnp", n.port, false, false)) {
					networkChange();
				}
			}
		}
		if (method == "search")
			return;
		std::vector<node> nodelist = filterUPnP(method);
		if (nodelist.empty())
			return;
		if (method == "addany") {
			addNode(nodelist[0].address, source, "upnp", nodelist[0].port, false, false);
			networkChange();
			return;
		}
		int pos = (method == "addfirst") ? 0 : nodelist.size() - 1;
		addNode(nodelist[pos].address, source, "upnp", nodelist[pos].port, false, false);
		networkChange();
	}
