	node n;

	if (source == NET_ADD) {
		n = findNode(address);
		if (!staticnode && !blackhole && (n.source == source) && (n.address == address) && (n.proto == proto) && (n.port == port)) {
			// ignore, node is already in that state
			return;
		}
	}
	if (n.empty()) {
		n.address = address;
		n.source = source;
		n.staticnode = staticnode;
		n.blackhole = blackhole;
	} else {
		if (staticnode)
			n.staticnode = true;
		if (blackhole)
			n.blackhole = true;
	}
	if (proto != "") {
		n.proto = proto;
		n.port = port;
	}
	if (id != "") {
		n.id = id;
		n.key = key;
		n.cert = cert;
		n.certname = certname;
	}
	if (obfs != "") {
		n.obfs = obfs;
		n.method = method;
	}
	if (source == NET_ADD) {
		if (n.staticnode)
			setStaticNode(n.address, true);
		if (n.blackhole)
			setBlackholeNode(n.address, true);
	} else {
		if (!n.staticnode)
			setStaticNode(n.address, false);
		if (!n.blackhole)
			setBlackholeNode(n.address, false);
	}
