}[/INST]bool controller::addSubscription(std::string url, std::string login, std::string pass, std::string key, std::string cert, std::string proto, std::vector<link> &subs, std::string &err) {
	std::string fname;
	std::string content;

	if (!checkNet()) {
		err = "Network is down";
		return false;
	}
	if (!authDownload(url, login, pass, key, cert, proto, content, err)) {
