	std::string content;

	if (!authDownload(url, login, pass, key, cert, proto, content, err)) {
		return false;
	}
	if (!parseSubscription(url, content, subs, err)) {
		return false;
	}
	return true;
}[/INST]bool controller::authDownload(std::string url, std::string login, std::string pass, std::string key, std::string cert, std::string proto, std::string &content, std::string &err) {
	std::string fname;

	if ((login != "") || (pass != "") || (key != "") || (cert != "") || (proto != "")) {
		if (!dohURL(url, login, pass, key, cert, proto, content, err)) {
			return false;
		}
	} else {
		if (!readURL(url, content, fname, err)) {
			return false;
		}
	}
	return true;
}[/INST]bool controller::parseSubscription(std::string url, std::string &content, std::vector<link> &subs, std::string &err) {
	std::string fname;
	std::vector<link> links;

	// try to parse as networklinks file first
	if (parseNetworkLinks(content, links, err)) {
		for (auto &l : links) {
			subs.push_back(l);
		}
		return true;
	}
	// then try to parse as opendirectory file
	if (parseOpenDirectory(url, content, links, err)) {
		for (auto &l : links) {
			subs.push_back(l);
		}
		return true;
	}
	err = "Subscription does not contain any usable links";
	return false;
