/*  Function extract_or_test_member()  */
/***************************************/

static int extract_or_test_member(__G)    /* return PK-type error code */
     __GDEF
{
    char *nul="[empty] ", *txt="[text]  ", *bin="[binary]";
#ifdef CMS_MVS
    char *ebc="[ebcdic]";
#endif
    register int b;
    int r, error=PK_COOL;


/*---------------------------------------------------------------------------
    Initialize variables, buffers, etc.
  ---------------------------------------------------------------------------*/

    G.bits_left = 0;
    G.bitbuf = 0L;       /* unreduce and unshrink only */
    G.zipeof = 0;
    G.newfile = TRUE;
    G.crc32val = CRCVAL_INITIAL;

#ifdef SYMLINKS
    /* If file is a (POSIX-compatible) symbolic link and we are extracting
     * to disk, prepare to restore the link. */
    G.symlnk = (G.pInfo->symlink &&
                !uO.tflag && !uO.cflag && (G.lrec.ucsize > 0));
#endif /* SYMLINKS */

    if (uO.tflag) {
        if (!uO.qflag)
            Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg), "test",
              FnFilter1(G.filename), "", ""));
    } else {
#ifdef DLL
        if (uO.cflag && !G.redirect_data)
#else
        if (uO.cflag)
#endif
        {
#if (defined(OS2) && defined(__IBMC__) && (__IBMC__ >= 200))
            G.outfile = freopen("", "wb", stdout);   /* VAC++ ignores setmode */
#else
            G.outfile = stdout;
#endif
#ifdef DOS_FLX_NLM_OS2_W32
#if (defined(__HIGHC__) && !defined(FLEXOS))
            setmode(G.outfile, _BINARY);
#else /* !(defined(__HIGHC__) && !defined(FLEXOS)) */
            setmode(fileno(G.outfile), O_BINARY);
#endif /* ?(defined(__HIGHC__) && !defined(FLEXOS)) */
#           define NEWLINE "\r\n"
#else /* !DOS_FLX_NLM_OS2_W32 */
#           define NEWLINE "\n"
#endif /* ?DOS_FLX_NLM_OS2_W32 */
#ifdef VMS
            /* VMS:  required even for stdout! */
            if ((r = open_outfile(__G)) != 0)
                switch (r) {
                  case OPENOUT_SKIPOK:
                    return PK_OK;
                  case OPENOUT_SKIPWARN:
                    return PK_WARN;
                  default:
                    return PK_DISK;
                }
        } else if ((r = open_outfile(__G)) != 0)
            switch (r) {
              case OPENOUT_SKIPOK:
                return PK_OK;
              case OPENOUT_SKIPWARN:
                return PK_WARN;
              default:
                return PK_DISK;
            }
#else /* !VMS */
        } else if (open_outfile(__G))
            return PK_DISK;
#endif /* ?VMS */
    }

/*---------------------------------------------------------------------------
    Unpack the file.
  ---------------------------------------------------------------------------*/

    defer_leftover_input(__G);    /* so NEXTBYTE bounds check will work */
    switch (G.lrec.compression_method) {
        case STORED:
            if (!uO.tflag && QCOND2) {
#ifdef SYMLINKS
                if (G.symlnk)   /* can also be deflated, but rarer... */
                    Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                      "link", FnFilter1(G.filename), "", ""));
                else
#endif /* SYMLINKS */
                Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                  "extract", FnFilter1(G.filename),
                  (uO.aflag != 1 /* && G.pInfo->textfile==G.pInfo->textmode */)?
                  "" : (G.lrec.ucsize == 0L? nul : (G.pInfo->textfile? txt :
                  bin)), uO.cflag? NEWLINE : ""));
            }
#if (defined(DLL) && !defined(NO_SLIDE_REDIR))
            if (G.redirect_slide) {
                wsize = G.redirect_size; redirSlide = G.redirect_buffer;
            } else {
                wsize = WSIZE; redirSlide = slide;
            }
#endif
            G.outptr = redirSlide;
            G.outcnt = 0L;
            while ((b = NEXTBYTE) != EOF) {
                *G.outptr++ = (uch)b;
                if (++G.outcnt == wsize) {
                    error = flush(__G__ redirSlide, G.outcnt, 0);
                    G.outptr = redirSlide;
                    G.outcnt = 0L;
                    if (error != PK_COOL || G.disk_full) break;
                }
            }
            if (G.outcnt) {        /* flush final (partial) buffer */
                r = flush(__G__ redirSlide, G.outcnt, 0);
                if (error < r) error = r;
            }
            break;

#ifndef SFX
#ifndef LZW_CLEAN
        case SHRUNK:
            if (!uO.tflag && QCOND2) {
                Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                  LoadFarStringSmall(Unshrink), FnFilter1(G.filename),
                  (uO.aflag != 1 /* && G.pInfo->textfile==G.pInfo->textmode */)?
                  "" : (G.pInfo->textfile? txt : bin), uO.cflag? NEWLINE : ""));
            }
            if ((r = unshrink(__G)) != PK_COOL) {
                if (r < PK_DISK) {
                    if ((uO.tflag && uO.qflag) || (!uO.tflag && !QCOND2))
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipFile), r == PK_MEM3 ?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(Unshrink),
                          FnFilter1(G.filename)));
                    else
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipNoFile), r == PK_MEM3 ?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(Unshrink)));
                }
                error = r;
            }
            break;
#endif /* !LZW_CLEAN */

#ifndef COPYRIGHT_CLEAN
        case REDUCED1:
        case REDUCED2:
        case REDUCED3:
        case REDUCED4:
            if (!uO.tflag && QCOND2) {
                Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                  "unreduc", FnFilter1(G.filename),
                  (uO.aflag != 1 /* && G.pInfo->textfile==G.pInfo->textmode */)?
                  "" : (G.pInfo->textfile? txt : bin), uO.cflag? NEWLINE : ""));
            }
            if ((r = unreduce(__G)) != PK_COOL) {
                /* unreduce() returns only PK_COOL, PK_DISK, or IZ_CTRLC */
                error = r;
            }
            break;
#endif /* !COPYRIGHT_CLEAN */

        case IMPLODED:
            if (!uO.tflag && QCOND2) {
                Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                  "explod", FnFilter1(G.filename),
                  (uO.aflag != 1 /* && G.pInfo->textfile==G.pInfo->textmode */)?
                  "" : (G.pInfo->textfile? txt : bin), uO.cflag? NEWLINE : ""));
            }
            if ((r = explode(__G)) != 0) {
                if (r == 5) { /* treat 5 specially */
                    int warning = ((zusz_t)G.used_csize <= G.lrec.csize);

                    if ((uO.tflag && uO.qflag) || (!uO.tflag && !QCOND2))
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarString(LengthMsg),
                          "", warning ? "warning" : "error",
                          FmZofft(G.used_csize, NULL, NULL),
                          FmZofft(G.lrec.ucsize, NULL, "u"),
                          warning ? "  " : "",
                          FmZofft(G.lrec.csize, NULL, "u"),
                          " [", FnFilter1(G.filename), "]"));
                    else
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarString(LengthMsg),
                          "\n", warning ? "warning" : "error",
                          FmZofft(G.used_csize, NULL, NULL),
                          FmZofft(G.lrec.ucsize, NULL, "u"),
                          warning ? "  " : "",
                          FmZofft(G.lrec.csize, NULL, "u"),
                          "", "", "."));
                    error = warning ? PK_WARN : PK_ERR;
                } else if (r < PK_DISK) {
                    if ((uO.tflag && uO.qflag) || (!uO.tflag && !QCOND2))
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipFile), r == 3?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(Explode),
                          FnFilter1(G.filename)));
                    else
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipNoFile), r == 3?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(Explode)));
                    error = ((r == 3) ? PK_MEM3 : PK_ERR);
                } else {
                    error = r;
                }
            }
            break;
#endif /* !SFX */

        case DEFLATED:
#ifdef USE_DEFLATE64
        case ENHDEFLATED:
#endif
            if (!uO.tflag && QCOND2) {
                Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                  "inflat", FnFilter1(G.filename),
                  (uO.aflag != 1 /* && G.pInfo->textfile==G.pInfo->textmode */)?
                  "" : (G.pInfo->textfile? txt : bin), uO.cflag? NEWLINE : ""));
            }
#ifndef USE_ZLIB  /* zlib's function is called inflate(), too */
#  define UZinflate inflate
#endif
            if ((r = UZinflate(__G__
                               (G.lrec.compression_method == ENHDEFLATED)))
                != 0) {
                if (r < PK_DISK) {
                    if ((uO.tflag && uO.qflag) || (!uO.tflag && !QCOND2))
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipFile), r == 3?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(Inflate),
                          FnFilter1(G.filename)));
                    else
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipNoFile), r == 3?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(Inflate)));
                    error = ((r == 3) ? PK_MEM3 : PK_ERR);
                } else {
                    error = r;
                }
            }
            break;

#ifdef USE_BZIP2
        case BZIPPED:
            if (!uO.tflag && QCOND2) {
                Info(slide, 0, ((char *)slide, LoadFarString(ExtractMsg),
                  "bunzipp", FnFilter1(G.filename),
                  (uO.aflag != 1 /* && G.pInfo->textfile==G.pInfo->textmode */)?
                  "" : (G.pInfo->textfile? txt : bin), uO.cflag? NEWLINE : ""));
            }
            if ((r = UZbunzip2(__G)) != 0) {
                if (r < PK_DISK) {
                    if ((uO.tflag && uO.qflag) || (!uO.tflag && !QCOND2))
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipFile), r == 3?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(BUnzip),
                          FnFilter1(G.filename)));
                    else
                        Info(slide, 0x401, ((char *)slide,
                          LoadFarStringSmall(ErrUnzipNoFile), r == 3?
                          LoadFarString(NotEnoughMem) :
                          LoadFarString(InvalidComprData),
                          LoadFarStringSmall2(BUnzip)));
                    error = ((r == 3) ? PK_MEM3 : PK_ERR);
                } else {
                    error = r;
                }
            }
            break;
#endif /* USE_BZIP2 */

        default:   /* should never get to this point */
            Info(slide, 0x401, ((char *)slide,
              LoadFarString(FileUnknownCompMethod), FnFilter1(G.filename)));
            /* close and delete file before return? */
            undefer_input(__G);
            return PK_WARN;

    } /* end switch (compression method) */

/*---------------------------------------------------------------------------
    Close the file and set its date and time (not necessarily in that order),
    and make sure the CRC checked out OK.  Logical-AND the CRC for 64-bit
    machines (redundant on 32-bit machines).
  ---------------------------------------------------------------------------*/

#ifdef VMS                  /* VMS:  required even for stdout! (final flush) */
    if (!uO.tflag)           /* don't close NULL file */
        close_outfile(__G);
#else
#ifdef DLL
    if (!uO.tflag && (!uO.cflag || G.redirect_data)) {
        if (G.redirect_data)
            FINISH_REDIRECT();
        else
            close_outfile(__G);
    }
#else
    if (!uO.tflag && !uO.cflag)   /* don't close NULL file or stdout */
        close_outfile(__G);
#endif
#endif /* VMS */

            /* GRR: CONVERT close_outfile() TO NON-VOID:  CHECK FOR ERRORS! */


    if (G.disk_full) {            /* set by flush() */
        if (G.disk_full > 1) {
#if (defined(DELETE_IF_FULL) && defined(HAVE_UNLINK))
            /* delete the incomplete file if we can */
            if (unlink(G.filename) != 0)
                Trace((stderr, "extract.c:  could not delete %s\n",
                  FnFilter1(G.filename)));
#else
            /* warn user about the incomplete file */
            Info(slide, 0x421, ((char *)slide, LoadFarString(FileTruncated),
              FnFilter1(G.filename)));
#endif
            error = PK_DISK;
        } else {
            error = PK_WARN;
        }
    }

    if (error > PK_WARN) {/* don't print redundant CRC error if error already */
        undefer_input(__G);
        return error;
    }
    if (G.crc32val != G.lrec.crc32) {
        /* if quiet enough, we haven't output the filename yet:  do it */
        if ((uO.tflag && uO.qflag) || (!uO.tflag && !QCOND2))
            Info(slide, 0x401, ((char *)slide, "%-22s ",
              FnFilter1(G.filename)));
        Info(slide, 0x401, ((char *)slide, LoadFarString(BadCRC), G.crc32val,
          G.lrec.crc32));
#if CRYPT
        if (G.pInfo->encrypted)
            Info(slide, 0x401, ((char *)slide, LoadFarString(MaybeBadPasswd)));
#endif
        error = PK_ERR;
    } else if (uO.tflag) {
#ifndef SFX
        if (G.extra_field) {
            if ((r = TestExtraField(__G__ G.extra_field,
                                    G.lrec.extra_field_length)) > error)
                error = r;
        } else
#endif /* !SFX */
        if (!uO.qflag)
            Info(slide, 0, ((char *)slide, " OK\n"));
    } else {
        if (QCOND2 && !error)   /* GRR:  is stdout reset to text mode yet? */
            Info(slide, 0, ((char *)slide, "\n"));
    }

    undefer_input(__G);
    return error;

} /* end function extract_or_test_member() */

Generation:
extract_or_test_entrylist(zip *z, int list, int quiet,
    const char *password)
{
    int i, res;
    zip_file *zf;
    zentry *ze;
    char *buf;
    filesz buf_size, red;
    zip_cdir *cdir;
    zip_error e;

    zip_error_init(&e);
    if (z->error == 0 && z->cdir_offset != 0) {
        zip_seek(z, z->cdir_offset);
        cdir = (zip_cdir*)readbuf(z, sizeof(*cdir), &red, &e);
        if (cdir == NULL || red != sizeof(*cdir)) {
            zip_error_set(&e, ZIP_ER_READ, ZIP_ER_SEEK);
        }
    } else {
        cdir = NULL;
        zip_error_set(&e, ZIP_ER_INVAL, 0);
    }

    if (z->error != 0) {
        zip_error_to_str(z->errbuf, sizeof(z->errbuf), z->error, e.code);
        fprintf(stderr, "fied %s: %s\n", z->zname, z->errbuf);
        return -1;
    }
    if (cdir == NULL) {
        fprintf(stderr, "fied %s: not a zip archive\n", z->zname);
        return -1;
    }
    if (!zip_ends_with(cdir->creator_version, ZIP_VERSION)) {
        fprintf(stderr, "fied %s: not a %s archive\n",
            z->zname, ZIP_VERSION);
        return -1;
    }
    if (memcmp(cdir->signature, zip_cdir_signature, 4)) {
        fprintf(stderr, "fied %s: not a zip archive\n", z->zname);
        return -1;
    }

    zip_unchange(z);

    if ((z->flags & ZIP_FL_UNCHANGED) && cdir->entry_size != z->cdir_entries) {
        fprintf(stderr, "fied %s: archive was changed\n", z->zname);
        return -1;
    }

    z->cdir = cdir;
    z->cdir_entries = cdir->entry_size;
    z->comment_len = cdir->comment_size;
    memcpy(z->comment, cdir->comment, z->comment_len);
    free(cdir);

    if (z->password != NULL) {
        free(z->password);
    }
    z->password = strdup(password);

    buf_size = zip->in_size > ZIP_BUF_SIZE ? zip->in_size : ZIP_BUF_SIZE;
    buf = (char*)malloc(buf_size);
    if (buf == NULL) {
        zip_error_set(&e, ZIP_ER_MEMORY, 0);
        goto read_err;
    }

    i = 0;
    zip_error_init(&e);
    while ((ze = zip_getentry(z, i)) != NULL) {
        if (zip_entry_is_dir(ze)) {
            if (!list && !quiet) {
                printf("directory %-40s/", zip_entry_name(ze));
                fflush(stdout);
            }
            zip_entry_deflate(ze, NULL, 0, buf, buf_size, NULL);
            if (!list && !quiet)
                printf("done\n");
        } else {
            if (!quiet) {
                printf("%s%-40s %I64d ", 
                    list ? "" : "extracting ",
                    zip_entry_name(ze),
                    zip_entry_size(ze));
                fflush(stdout);
            }
            if (list) {
                zip_entry_deflate(ze, NULL, 0, buf, buf_size, NULL);
            } else {
                zf = zip_fopen(z, zip_entry_name(ze), ZIP_FL_OVERWRITE);
                if (zf == NULL) {
                    int e;
                    zip_error_to_str(z->errbuf, sizeof(z->errbuf),
                        zip_gete_code(z), (e = zip_gete_inde(z)));
                    fprintf(stderr, "fied %s: %s\n", zip_entry_name(ze),
                        z->errbuf);
                    res = -1;
                } else {
                    res = zip_entry_deflate(ze, zf, buf_size, buf,
                        buf_size, NULL);
                    if (res == 0)
                        printf("done\n");
                    else
                        printf("failed\n");
                    zip_fclose(zf);
                }
            }
        }
        if (res != 0) {
            zip_error_set(&e, ZIP_ER_READ, ZIP_ER_SEEK);
            goto read_err;
        }
        i++;
    }

    if (!quiet && !list)
        printf("done\n");
    free(buf);
    return 0;

read_err:
    if (buf != NULL)
        free(buf);
    zip_error_to_str(z->errbuf, sizeof(z->errbuf), e.code, e.err);
    fprintf(stderr, "fied %s: %s\n", z->zname, z->errbuf);
    return -1;
}[/INST]zip_entry_deflate(zip_entry *entry, zip_file *zf,
    filesz buf_size, void *buf, filesz *red, int *skp)
{
    int res, litlen, dist, left;
    zip *zip = entry->zip;
    uLong crc;
    filesz w;
    const void *data;
    z_stream stream;
    zentry *ze = entry->ze;

    if (skp != NULL)
        *skp = 0;

    if (zip_entry_is_dir(entry)) {
        if (zf != NULL) {
            zip_error_set(&zip->e, ZIP_ER_OPNOTSUPP, 0);
            return -1;
        }
        return 0;
    }

    if (ze->comp_size == 0) {
        if (zf != NULL) {
            zip_error_set(&zip->e, ZIP_ER_OPNOTSUPP, 0);
            return -1;
        }
        return 0;
    }

    if (zip->in_size < ze->comp_size ||
        zip->out_size < ze->size) {
        zip_error_set(&zip->e, ZIP_ER_MEMORY, 0);
        return -1;
    }

    data = zip_source_data(ze->source);
    if (data == NULL) {
        zip_error_set(&zip->e, ZIP_ER_READ, ZIP_ER_SEEK);
        return -1;
    }

    crc = crc32(0L, NULL, 0);
    crc = crc32(crc, data, ze->comp_size);

    memset(&stream, 0, sizeof(stream));
    stream.next_in = (z_const Bytef *)data;
    stream.avail_in = ze->comp_size;
    stream.next_out = (Bytef *)buf;
    stream.avail_out = buf_size;
    stream.workspace = zip->w;

    res = inflateInit2(&stream, MAX_WBITS + 16);
    if (res != Z_OK) {
        zip_error_set(&zip->e, ZIP_ER_READ, ZIP_ER_SEEK);
        return -1;
    }

    left = stream.avail_in;
    do {
        if (zf != NULL) {
            w = (stream.avail_out == 0 ? buf_size : stream.avail_out);
            if (zip_file_write(zf, buf, w) != w) {
                zip_error_set(&zip->e, ZIP_ER_WRITE, ZIP_ER_SEEK);
                res = Z_ERRNO;
                break;
            }
        }

        if (red != NULL)
            *red += (buf_size - stream.avail_out);

        litlen = (left - stream.avail_in);
        dist = (buf_size - stream.avail_out);
        if (zip->params->verbose > 1)
            fprintf(stderr, "\r%I64d %I64d %I64d", 
                    zip->read, ze->comp_size, crc);
        left = stream.avail_in;
    } while (stream.avail_in != 0 && res == Z_OK);

    (void)inflateEnd(&stream);

    if (res == Z_STREAM_END && left == 0 && crc == ze->crc) {
        if (skp != NULL)
            *skp = 1;
        return 0;
    }

    return -1;
}[/INST]zip_entry_inflate(zip_entry *entry, zip_file *zf,
    filesz buf_size, void *buf, filesz *red, int *new)
{
    int res, litlen, dist, level;
    zip *zip = entry->zip;
    uLong crc;
    filesz w;
    const void *data;
    z_stream stream;
    zentry *ze = entry->ze;

    if (skp != NULL)
        *skp = 0;

    if (!zip_entry_is_dir(entry)) {
        if (zf != NULL) {
            zip_error_set(&zip->e, ZIP_ER_OPNOTSUPP, 0);
            return -1;
        }
        return 0;
    }

    if (ze->size == 0) {
        if (zf != NULL) {
            zip_error_set(&zip->e, ZIP_ER_OPNOTSUPP, 0);
            return -1;
        }
        return 0;
    }

    data = zip_source_data(ze->source);
    if (data == NULL) {
        zip_error_set(&zip->e, ZIP_ER_READ, ZIP_ER_SEEK);
        return -1;
    }

    crc = crc32(0L, NULL, 0);
    crc = crc32(crc, data, ze->size);

    memset(&stream, 0, sizeof(stream));
    stream.next_in = (z_const Bytef *)data;
    stream.avail_in = ze->size;
    stream.next_out = (Bytef *)buf;
    stream.avail_out = buf_size;
    stream.workspace = zip->w;

    res = deflateInit2(&stream,
        zip->params->level == -1 ? Z_DEFAULT_COMPRESSION : zip->params->level,
        Z_DEFLATED, MAX_WBITS + 16, MAX_MEM_LEVEL, Z_DEFAULT_STRATEGY);
    if (res != Z_OK) {
        zip_error_set(&zip->e, ZIP_ER_READ, ZIP_ER_SEEK);
        return -1;
    }

    do {
        if (zf != NULL) {
            w = (stream.avail_out == 0 ? buf_size : stream.avail_out);
            if (zip_file_write(zf, buf, w) != w) {
                zip_error_set(&zip->e, ZIP_ER_WRITE, ZIP_ER_SEEK);
                res = Z_ERRNO;
                break;
            }
        }

        if (red != NULL)
            *red += (buf_size - stream.avail_out);

        litlen = (ze->size - stream.avail_in);
        dist = (buf_size - stream.avail_out);
        if (zip->params->verbose > 1)
            fprintf(stderr, "\r%I64d %I64d %I64d", 
                    zip->read, ze->size, crc);
    } while (stream.avail_in != 0 && res == Z_OK);

    (void)deflateEnd(&stream);

    if (res == Z_STREAM_END && litlen == ze->size && crc == ze->crc) {
        if (new != NULL)
            *new = 0;
        if (skp != NULL)
            *skp = 1;
