{
#define JSON_OPT_PREFIX		1
#define JSON_OPT_CHECK_ETENSIONS	2
#define JSON_OPT_DETERMINISTIC	4
#define JSON_OPT_KEEP_COMMENTS	8
#define JSON_OPT_SORT_KEYS	16
#define JSON_OPT_RAW	32
#define JSON_OPT_UNCOMPACT	64

	static const struct option json_long_opts[] = {
		{ "prefix", no_argument, NULL, JSON_OPT_PREFIX },
		{ "check-etensions", no_argument, NULL, JSON_OPT_CHECK_ETENSIONS },
		{ "deterministic", no_argument, NULL, JSON_OPT_DETERMINISTIC },
		{ "keep-comments", no_argument, NULL, JSON_OPT_KEEP_COMMENTS },
		{ "sort-keys", no_argument, NULL, JSON_OPT_SORT_KEYS },
		{ "raw", no_argument, NULL, JSON_OPT_RAW },
		{ "uncompact", no_argument, NULL, JSON_OPT_UNCOMPACT },
		{ NULL, 0, NULL, 0 }
	};

