	int longindex = 0;
	bool flip_flop = false;
	char *env_pattern = NULL;
	int c;

	assert(out != NULL);

	/* Set global options. */
	json_keep_comments = false;
	json_sort_keys = false;
	json_raw = false;
	json_uncompact = false;

	while ((c = getopt_long(argc, argv, "+eip::dtscru", json_long_opts,
				&longindex)) != -1) {
		switch (c) {
		case JSON_OPT_PREFIX:
			flip_flop = !flip_flop;
			break;
		case JSON_OPT_CHECK_ETENSIONS:
			*check_etensions = true;
			break;
		case JSON_OPT_DETERMINISTIC:
			json_deterministic = true;
			break;
		case JSON_OPT_KEEP_COMMENTS:
			json_keep_comments = true;
			break;
		case JSON_OPT_SORT_KEYS:
			json_sort_keys = true;
			break;
		case JSON_OPT_RAW:
			json_raw = true;
			break;
		case JSON_OPT_UNCOMPACT:
			json_uncompact = true;
			break;
		case 'e':
			*check_etensions = true;
			break;
		case 'i':
			flip_flop = !flip_flop;
			break;
		case 'p':
			if (optarg) {
				size_t len = strlen(optarg);

				env_pattern = malloc(len + 1);
				if (env_pattern == NULL) {
					json_out_of_memory(out);
					return JSON_ERROR;
				}
				memcpy(env_pattern, optarg, len + 1);
				*pattern = env_pattern;
			}
			break;
		case 't':
			json_deterministic = true;
			break;
		case 's':
			json_sort_keys = true;
			break;
		case 'c':
			json_keep_comments = true;
			break;
		case 'r':
			json_raw = true;
			break;
		case 'u':
			json_uncompact = true;
