int imap_open_connection(struct ImapAccount *imap_acct)
{
  int rc;
  struct MuttSocket *sock = imap_acct->sock;

  rc = mutt_socket_open(sock);
  if (rc != 0)
  {
    mutt_perror("mutt_socket_open() failed!");
    return rc;
  }

  rc = imap_cmd_step(imap_acct, NULL, IMAP_CAPABILITY);
  if (rc != 0)
  {
    mutt_error("IMAP capability command failed, aborting.");
    return rc;
  }

  if (!mutt_socket_is_ssl(sock))
  {
    rc = mutt_ssl_starttls(sock);
    if (rc != 0)
    {
      mutt_error("STARTTLS failed, aborting.");
      return rc;
    }
  }

  rc = imap_cmd_step(imap_acct, NULL, IMAP_IDLE);
  if (rc != 0)
  {
    mutt_error("IMAP idle command failed, aborting.");
    return rc;
  }

  return 0;
}

