}static bool memory_region_is_access_allowed(MemoryRegion *mr,
                                            MemTAttrs attrs,
                                            hwaddr addr,
                                            hwaddr len)
{
    if (memory_region_is_iommu(mr)) {
        IOMMUMemoryRegionClass *imrc;
        IOMMUMemoryRegion *iommu_mr;

        iommu_mr = memory_region_get_iommu(mr);
        imrc = memory_region_get_iommu_class(mr);

        assert(imrc->translate);

        /* If the IOMMU implements IOMMU_NOTIFIER, it's supposed to
         * set up the notifier before translating the first address.
         * If the notifier is missing, something is really wrong and
         * we had better stop right here.
         */
        assert(ma_notifier.notify);

        /* We did not remember the IOMMU attributes.  Ask the IOMMU
         * to translate the address for us.  If it returns an
         * IOMMU_SUCCESS, the translation is read-only.  If it returns
         * IOMMU_NONE, the IOMMU doesn't know about this address
         * and we should perform a normal translation.  Any other
         * IOMMU status means the translation failed.
         */
        switch (imrc->translate(mr, iommu_mr, addr, len, attrs, NULL)) {
        case IOMMU_NONE:
            break;
        case IOMMU_SUCCESS:
            return false;
        default:
            return true;
        }
    }

    return !memory_region_is_untrusted(mr);
}static IOMMUResult memory_region_iommu_translate(MemoryRegion *mr,
                                                 IOMMUMemoryRegion *iommu_mr,
                                                 hwaddr addr,
                                                 hwaddr *translated,
                                                 MemTAttrs attrs,
                                                 int *non_translatable)
{
    IOMMUMemoryRegionClass *imrc;
    IOMMUResult r;

    imrc = memory_region_get_iommu_class(mr);
    assert(imrc->translate);

    r = imrc->translate(mr, iommu_mr, addr, translated, attrs, non_translatable);

    /*
     * IOMMU_NONE means the IOMMU doesn't know about this address
     * and we should perform a normal translation.
     * IOMMU_SUCCESS means the translation is read-only.
     * IOMMU_NOT_FOUND means the address is not translated.
     * IOMMU_DENIED means the transaction should be denied.
     */
    switch (r) {
    case IOMMU_NONE:
        break;
    case IOMMU_SUCCESS:
    case IOMMU_NOT_FOUND:
    case IOMMU_DENIED:
        *translated = addr;
        break;
    default:
        break;
    }

    return r;
}static IOMMUResult memory_region_translate_iommu(MemoryRegion *mr,
                                                 IOMMUMemoryRegion *iommu_mr,
                                                 hwaddr addr,
                                                 hwaddr *translated,
                                                 MemTAttrs attrs)
{
    IOMMUMemoryRegionClass *imrc;
    IOMMUResult r;

    imrc = memory_region_get_iommu_class(mr);
    assert(imrc->translate);

    r = imrc->translate(mr, iommu_mr, addr, translated, attrs, NULL);

    /*
     * IOMMU_NONE means the IOMMU doesn't know about this address
     * and we should perform a normal translation.
     * IOMMU_SUCCESS means the translation is read-only.
     * IOMMU_NOT_FOUND means the address is not translated.
     * IOMMU_DENIED means the transaction should be denied.
     */
    switch (r) {
    case IOMMU_NONE:
        break;
    case IOMMU_SUCCESS:
    case IOMMU_NOT_FOUND:
    case IOMMU_DENIED:
        *translated = addr;
        break;
    default:
        break;
    }

    return r;
}static IOMMUResult memory_region_handle_iommu(MemoryRegion *mr,
                                               IOMMUMemoryRegion *iommu_mr,
                                               hwaddr addr,
                                               hwaddr *translated,
                                               hwaddr len,
                                               MemTAttrs attrs,
                                               bool *non_translatable)
{
    IOMMUResult r;

    r = memory_region_translate_iommu(mr, iommu_mr, addr, translated, attrs);
    if (non_translatable) {
        *non_translatable = (r == IOMMU_NONE);
    }

    switch (r) {
    case IOMMU_NONE:
        /* The IOMMU doesn't know about this address.  This is
         * reported to the caller.  The IOMMU notifier will be called
         * later if the memory is mapped, so the IOMMU state can be
         * updated then.
         */
        break;
    case IOMMU_SUCCESS:
        /* The IOMMU knows about this address and the translation is
         * read-only.  We need to perform a normal read to update the
         * IOMMU state when the memory is written to.
         */
        break;
    case IOMMU_NOT_FOUND:
        /* The IOMMU knows about this address and it is not
         * translated.  This is a memory access error.
         */
        qemu_log_mask(LOG_GUEST_ERROR,
                      "IOMMU: unmapped device address " HWADDR_FMT_pld "\n",
                      *translated);
        r = IOMMU_MEMORY_ERROR;
        break;
    case IOMMU_DENIED:
        /* The IOMMU knows about this address but access is not
         * permitted.  This is a memory access error.
         */
        qemu_log_mask(LOG_GUEST_ERROR,
                      "IOMMU: access denied to device address " HWADDR_FMT_pld "\n",
                      *translated);
        r = IOMMU_MEMORY_ERROR;
        break;
    default:
        /* Something really went wrong.  */
        abort();
    }

    return r;
}static MemTResult memory_region_read(MemoryRegion *mr, hwaddr addr,
                                      MemTAttrs attrs, void *buf, hwaddr len)
{
    MemTResult r;

    assert(mr->ops->read);

    if (memory_region_is_iommu(mr)) {
        IOMMUMemoryRegion *iommu_mr;
        hwaddr translated;
        bool non_translatable;

        iommu_mr = memory_region_get_iommu(mr);
        r = memory_region_handle_iommu(mr, iommu_mr, addr, &translated,
                                        len, attrs, &non_translatable);
        if (r != MEMTX_OK) {
            return r;
        }

        if (non_translatable) {
            /* The IOMMU doesn't know about this address.  Fall back
             * to the normal memory region.  This is for IOMMU
             * devices that don't have IOMMU_NOTIFIER, e.g. for
             * memory regions marked IOMMU_DEVICE.
             */
            r = memory_region_read(mr, translated, attrs, buf, len);
            if (r == MEMTX_OK) {
                memory_region_notify_iommu(mr, IOMMU_NOTIFIER,
                                            iommu_mr, attrs);
            }
            return r;
        }
    }

    if (len > mr->ops->read(mr, addr, attrs, buf, len)) {
        return MEMTX_SHORT_READ;
    }

    return MEMTX_OK;
}static MemTResult memory_region_write(MemoryRegion *mr, hwaddr addr,
                                       MemTAttrs attrs, const void *buf,
                                       hwaddr len)
{
    MemTResult r;

    assert(mr->ops->write);

    if (memory_region_is_iommu(mr)) {
