        r = memory_region_handle_iommu(mr, iommu_mr, addr, &translated,
                                        len, attrs, &non_translatable);
        if (r != MEMTX_OK) {
            return r;
        }

        if (non_translatable) {
            /* The IOMMU doesn't know about this address.  Fall back
             * to the normal memory region.  This is for IOMMU
             * devices that don't have IOMMU_NOTIFIER, e.g. for
             * memory regions marked IOMMU_DEVICE.
             */
            r = memory_region_write(mr, translated, attrs, buf, len);
            if (r == MEMTX_OK) {
                memory_region_notify_iommu(mr, IOMMU_NOTIFIER,
                                            iommu_mr, attrs);
            }
            return r;
        }
    }

    if (len > mr->ops->write(mr, addr, attrs, buf, len)) {
        return MEMTX_SHORT_WRITE;
    }

    return MEMTX_OK;
}static MemTResult memory_region_set_subregion(MemoryRegion *mr,
                                               MemoryRegionSection *section)
{
    int i;
    hwaddr start = section->offset_within_region;
    hwaddr end = start + section->size;
    hwaddr subregion_start;
    hwaddr subregion_len;
    MemoryRegion *subregion;

    assert(is_power_of_2(section->page_size));
    assert(section->page_size <= mr->page_size);

    if (end <= mr->section_size) {
        /* The new section fits entirely within the region.  */
        mr->section = section;
        memory_region_update_iommu_notifiers(mr, section);
        return MEMTX_OK;
    }

    if (start < mr->section_size) {
        /* The new section overflows the region.  Split it into two
         * sections, one that fits and one that doesn't.  The
         * subsections must be of the same page size.
         */
        MemoryRegionSection sub1, sub2;
        MemoryRegion *sub_mr;

        sub1 = *section;
        sub1.size = mr->section_size - start;
        sub1.page_size = section->page_size;
        assert(sub1.size % sub1.page_size == 0);

        sub2 = sub1;
        sub2.offset_within_address_space = start + sub1.size;
        sub2.size = end - sub2.offset_within_address_space;
        sub2.page_size = section->page_size;
        assert(sub2.size % sub2.page_size == 0);

        subregion = flatview_to_memory_region(address_space_to_flatview(mr->as));
        subregion_start = section->offset_within_address_space;
        subregion_len = sub1.size + sub2.size;
    } else {
        /* The new section underflows the region.  Add padding to the
         * front of the section to make it fit.  The padding will be
         * passed to the subregion's read and write callbacks, so
         * that the subregion does not see the underflow.
         */
        MemoryRegionSection sub;
        MemoryRegion *sub_mr;

        sub = *section;
        sub.offset_within_address_space = start;
        sub.size = section->size;
        /* The padding is the difference between the region page size
         * and the section page size.  Since the region page size is
         * always a multiple of the section page size, the padding
         * must be a power of 2.
         */
        assert((mr->page_size % section->page_size) == 0);
        sub.page_size = mr->page_size;
        assert(is_power_of_2(sub.page_size / section->page_size));

        sub_mr = flatview_to_memory_region(address_space_to_flatview(mr->as));
        subregion = sub_mr;
        subregion_start = 0;
        subregion_len = section->size + (sub.page_size - section->page_size);
    }

    /* If the region has a read or write callback, pass it to the
     * subsection.  This allows the callback to see the underflow
     * (if any) as well as the overflow (if any).
     */
    if (subregion->c && (subregion->c->flags & MEMTX_FLAGS_READ)) {
        sub1.read = subregion->read;
        sub1.opaque = subregion->opaque;
    }
    if (subregion->c && (subregion->c->flags & MEMTX_FLAGS_WRITE)) {
        sub1.write = subregion->write;
        sub1.opaque = subregion->opaque;
    }

    /* If the region has a listener, pass it to the subsection so that
     * it continues to receive notifiers for the region as a whole.
     */
    if (ma_listener.notify) {
        sub1.iommu_attrs = ma_listener.iommu_attrs;
        sub1.iommu_mr = ma_listener.iommu_mr;
    }

    r = memory_region_set_subregion_common(mr, subregion, subregion_start,
                                          &sub1, start, end, subregion_len,
                                          section->page_size);
    if (r != MEMTX_OK) {
        return r;
    }

    /* The second subsection must use the same page size as the
     * region.
     */
    sub2.page_size = mr->page_size;

    /* If the region has a read or write callback, pass it to the
     * subsection.  This allows the callback to see the underflow
     * (if any) as well as the overflow (if any).
     */
    if (subregion->c && (subregion->c->flags & MEMTX_FLAGS_READ)) {
        sub2.read = subregion->read;
        sub2.opaque = subregion->opaque;
    }
    if (subregion->c && (subregion->c->flags & MEMTX_FLAGS_WRITE)) {
        sub2.write = subregion->write;
        sub2.opaque = subregion->opaque;
    }

    /* If the region has a listener, pass it to the subsection so that
     * it continues to receive notifiers for the region as a whole.
     */
    if (ma_listener.notify) {
        sub2.iommu_attrs = ma_listener.iommu_attrs;
        sub2.iommu_mr = ma_listener.iommu_mr;
    }

    r = memory_region_set_subregion_common(mr, subregion, subregion_start
                                          + sub1.size, &sub2, end,
                                          subregion_len, subregion_len,
                                          mr->page_size);
    if (r != MEMTX_OK) {
        /* If we run into a problem, split the region back into a single
         * subsection.
         */
        memory_region_set_subregion_common(mr, subregion, subregion_start,
                                          &sub1, start, sub1.size,
                                          sub1.size, section->page_size);
        return r;
    }

    return MEMTX_OK;
}static void memory_region_add_subregion(MemoryRegion *mr,
                                        hwaddr offset, MemoryRegion *subregion)
{
    MemoryRegionSection section;

    section.size = subregion->ma_length;
    section.offset_within_region = offset;
    section.offset_within_address_space = offset;
    section.page_size = mr->page_size;
    section.iommu_attrs = 0;
    section.iommu_mr = NULL;

    memory_region_update_iommu_notifiers(mr, NULL);
    memory_region_set_subregion(mr, &section);
    memory_region_update_iommu_notifiers(mr, NULL);
}static void memory_region_del_subregion(MemoryRegion *mr,
                                        MemoryRegion *subregion)
{
    MemoryRegionSection old_section, *new_section;

    old_section = *memory_region_find(mr, mr->as, 0);
    assert(old_section.mr == mr);

    /* We can't handle removing a subregion that is split across
     * two sections with different page sizes.
     */
    assert(old_section.page_size == mr->page_size);

    new_section = memory_region_find(mr, mr->as, old_section.offset_within_region - subregion->ma_length);
    assert((old_section.offset_within_region % subregion->ma_length) == 0);
    assert((old_section.size % subregion->ma_length) == 0);
    assert((new_section->size % subregion->ma_length) == 0);

    memory_region_update_iommu_notifiers(mr, NULL);
    memory_region_set_subregion(mr, new_section);
    memory_region_update_iommu_notifiers(mr, NULL);
