{
  enum XML_Status result = XML_STATUS_OK;
  XML_Char *newDoc;
  XML_Char *p;
  int newDocLen;
  int contentLen = (int)XML_CharStrlen(content);

  /* check that entity name is not empty */
  if (name == NULL || *name == 0) {
    error(parser, XML_ERROR_INTERNAL_ERROR, &name[0], NULL);
    return;
  }

  /* check that entity has content */
  if (content == NULL || *content == 0) {
    error(parser, XML_ERROR_INTERNAL_ERROR, &name[0], NULL);
    return;
  }

  /* allocate new document storage */
  newDocLen = contentLen + 200;
  newDoc = (XML_Char *)MALLOC(newDocLen * sizeof(XML_Char));
  if (newDoc == NULL) {
    error(parser, XML_ERROR_NO_MEMORY, NULL, NULL);
    return;
  }

