  newDoc[0] = (XML_Char)'<';
  p = newDoc + 1;
  if (isCdata) {
    *p++ = (XML_Char) '!';
    *p++ = (XML_Char) '[';
    *p++ = (XML_Char) 'C';
    *p++ = (XML_Char) 'D';
    *p++ = (XML_Char) 'A';
    *p++ = (XML_Char) 'T';
    *p++ = (XML_Char) 'A';
    *p++ = (XML_Char) '[';
  }
  while (*content != 0) *p++ = *content++;
  if (isCdata) {
    *p++ = (XML_Char) ']';
    *p++ = (XML_Char) ']';
    *p++ = (XML_Char) '>';
  } else {
    *p++ = (XML_Char) '<';
    *p++ = (XML_Char) '/';
    *p++ = (XML_Char) 'e';
    *p++ = (XML_Char) 'n';
    *p++ = (XML_Char) 't';
    *p++ = (XML_Char) 'e';
    *p++ = (XML_Char) 'r';
    *p++ = (XML_Char) 'y';
    *p++ = (XML_Char) '>';
