  updatePosition(parser, base, newDoc, p);

  /* parse content */
  if (parser->m_parsingStatus.parsing == XML_SUSPENDED)
    parser->m_parsingStatus.parsing = XML_PARSING;
  result = doProlog(parser, newDoc, parser->m_encoding);
  if (result == XML_STATUS_OK)
    result = doContent(parser, newDoc, parser->m_encoding);
