  parser->m_eventPtr = name;
  parser->m_eventEndPtr = name + XML_CharStrlen(name);

  /* the following call updates the position information */
  parser->m_positionPtr = base;
  updatePosition(parser, base, name, parser->m_eventEndPtr);

  /* call the start and end entity handlers */
  if (parser->m_startEntityHandler != NULL)
    parser->m_startEntityHandler(parser->m_handlerArg, name, 0, 0, 0, 0);

  if (parser->m_endEntityHandler != NULL)
    parser->m_endEntityHandler(parser->m_handlerArg, name, 0);
} /* processInternalEntity */

