Status ValidateInputs(const vector<RaggedTensorVariant>& ragged_splits,
                         const vector<RaggedTensorVariant>& ragged_values,
                         int dimension) {
    // Note: it's ok to use `ValueOrDie()` here, because if `StatusOr<T>` is
    // returned from a `REQUIRES` statement, the error is logged and the
    // program will crash anyway.
