    const Tensor& values = ragged_values[0].ValueOrDie().values;

    TF_RETURN_IF_ERROR(ragged_splits[0].Status());
    TF_RETURN_IF_ERROR(ragged_values[0].Status());

    for (int i = 1; i < ragged_splits.size(); ++i) {
      TF_RETURN_IF_ERROR(ragged_splits[i].Status());
      TF_RETURN_IF_ERROR(ragged_values[i].Status());
      const Tensor& other_splits = ragged_splits[i].ValueOrDie().splits;
      const Tensor& other_values = ragged_values[i].ValueOrDie().values;

      TF_RETURN_IF_ERROR(ragged_util::ValidateRaggedTensor(ragged_splits[i]));
      TF_RETURN_IF_ERROR(ragged_util::ValidateRaggedTensor(ragged_values[i]));

      if (splits.dtype() != other_splits.dtype()) {
        return errors::InvalidArgument(
            "all RaggedTensors must have the same split type");
      }
      if (values.dtype() != other_values.dtype()) {
        return errors::InvalidArgument(
            "all RaggedTensors must have the same value type");
      }
      if (other_splits.dim_size(0) != other_values.dim_size(0)) {
        return errors::InvalidArgument(
            "RaggedTensor splits and values must have the same number of "
            "rows (splits has ",
            other_splits.dim_size(0), ", values has ", other_values.dim_size(0),
            ")");
      }
    }

