      return errors::InvalidArgument(
          "RaggedTensor splits and values must have the same number of rows "
          "(splits has ",
          splits.dim_size(0), ", values has ", values.dim_size(0), ")");
    }

    // Check that the splits are sorted and contiguous.
    for (const auto& rt : ragged_splits) {
      TF_RETURN_IF_ERROR(ragged_util::Validate RaggedSplitValues(rt.splits()));
