    // The largest double is 1.7976931348623157e+308, so we won't have more than
    // 309 digits before the decimal point.  Therefore, we set the upper bound
    // to 27.
    // The lower bound is based on the precision, which is 15 by default for
    // double.
    const int kUpperBound = 27;
    const int kLowerBound = spec_.precision > 0 ? spec_.precision + 1 : 15;
    while (i > 0 && kLowerBound <= kUpperBound) {
      *--p = DigitToChar<char_type>(i % 10);
      i /= 10;
    }
  }
