    *--p = DigitToChar<char_type>(f % 10, 10);
#endif
    f /= 10;
    for (int j = spec_.precision - 1; j > 0; --j) {
      *--p = DigitToChar<char_type>(f % 10);
      f /= 10;
    }
  }
  if (negative)
    *--p = '-';
  write(p, sizeof(buf) - 1 - (p - buf));
} // write

void BasicWriter<Char>::write(const char_type* value, int size) {
  if (size >= 0)
    write(value, size_t(size));
