void BasicWriter<Char>::pad0(int value, int num_digits) {
  uint32_t u = value < 0 ? -value : value;
  char buf[10];
  char* p = buf + 10;
  *--p = 0;
  do {
    *--p = DigitToChar<char_type>(u % 10);
    u /= 10;
  } while (u > 0);
  int num_digits_written = 10 - (p - buf);
  int padding = num_digits > num_digits_written ? num_digits - num_digits_written : 0;
  while (padding > 0) {
    write('0');
    --padding;
  }
  write(p, num_digits_written);
} // pad0

