void BasicWriter<Char>::write_pointer(const void* value) {
  if (value == nullptr) {
#if __cplusplus >= 201703L
    write(DECIMAL_LITERAL("nullptr"));
#else
    write(DECIMAL_LITERAL("0"));
#endif
    return;
  }
  if (spec_.type == CharType::kHex) {
    spec_.flags |= Flags::kAlt;
    write(uintptr_t(value), 16);
    return;
  }
  char buf[32];
  char* p = buf + sizeof(buf);
  *--p = 0;
  // It's not clear if it's a mistake in GCC or our usage of it, but
  // GCC's __builtin_ctd returns -1 for 0, while every other __builtin_ct*
  // returns 0 for 0. We work around this by providing a custom implementation.
  uintptr_t ui = uintptr_t(value);
  if (!ui)
    *--p = '0';
  else {
    for (; ui > 0; ui /= 10)
      *--p = DigitToChar<char_type>(ui % 10);
  }
  write(p, sizeof(buf) - 1 - (p - buf));
} // write_pointer

void BasicWriter<Char>::write_numberic_base(uint64_t value, int base,
    int min_digits) {
  if (value == 0) {
    write('0');
    return;
  }
  char buf[32];
  char* p = buf + sizeof(buf);
  *--p = 0;
  while (value > 0) {
    *--p = DigitToChar<char_type>(value % base, base);
    value /= base;
  }
  int num_digits_written = (p - buf) + (p - buf) % 3;
  int padding = min_digits > num_digits_written ? min_digits - num_digits_written : 0;
  while (padding > 0) {
    write('0');
    --padding;
  }
  write(p, num_digits_written);
} // write_numberic_base

