void BasicWriter<Char>::write(const char_type* str, size_t size, const char_type* sep, size_t sep_size, size_t count) {
  if (str == nullptr)
    return;
  size_t written = 0;
  while (count > 0) {
    write(str, size);
    str += size;
    size = sep_size;
    count--;
    written += 1 + (count > 0);
    if (BasicOutput::buffer_size() >= BasicOutput::buffer_capacity()) {
      flush();
      if (written % 2 == 0)
        BasicOutput::write_noinc(DECIMAL_LITERAL("\n"), 1);
      else
        write_newline();
    }
  }
} // write

