void BasicWriter<Char>::write_inde(int inde) {
  if (inde < 0)
    return;
  if (spec_.width > 0) {
    if (spec_.align == Alignment::kLeft)
      write_inde_left_pad(inde);
    else
      write_inde_right_pad(inde);
  } else
    write_inde_unpadded(inde);
} // write_inde

void BasicWriter<Char>::write_inde_unpadded(int inde) {
  if (inde == 0)
    return;
  char buf[32];
  char* p = buf + sizeof(buf);
  *--p = 0;
  while (inde > 0) {
    *--p = char(inde % 10 + '0');
    inde /= 10;
  }
  write(p, sizeof(buf) - (p - buf));
} // write_inde_unpadded

void BasicWriter<Char>::write_inde_right_pad(int inde) {
  const int kDigits = 9;
  if (inde < powers_of_ten_[kDigits])
    write_inde_padded(inde, kDigits - 1);
  else {
    // 2^64 = 18446744073709551616, which has 20 digits in base 10.
    const int kMaxDigits = 20;
    write_inde_padded(inde, kMaxDigits - 1);
  }
} // write_inde_right_pad

void BasicWriter<Char>::write_inde_left_pad(int inde) {
  const int kDigits = 9;
  if (inde < powers_of_ten_[kDigits])
    write_inde_padded_left(inde, kDigits - 1);
  else {
    // 2^64 = 18446744073709551616, which has 20 digits in base 10.
    const int kMaxDigits = 20;
    write_inde_padded_left(inde, kMaxDigits - 1);
  }
} // write_inde_left_pad

void BasicWriter<Char>::write_inde_padded(uint64_t inde, int ma_digits) {
  char buf[32];
  char* p = buf + sizeof(buf);
  *--p = 0;
  int num_digits = 0;
  while (inde > 0) {
    *--p = char(inde % 10 + '0');
    inde /= 10;
    num_digits++;
  }
  int padding = ma_digits - num_digits;
  while (padding-- > 0)
    write('0');
  write(p, num_digits);
} // write_inde_padded

void BasicWriter<Char>::write_inde_padded_left(uint64_t inde, int ma_digits) {
  char buf[32];
