static inline int sg_write(struct scsi_cmnd *scmd)
{
	struct sg_request *sgreq = data(scmd);
	struct sg_iovec *sg;
	int nr_segs, res;
	u32 bufflen = 0;
	unsigned long start_time;

	if (scmd->sc_data_direction != DMA_TO_DEVICE)
		return -EINVAL;

	nr_segs = scsi_sg_count(scmd);
	if (!nr_segs)
		return -EINVAL;

	sg = scsi_sglist(scmd);
	res = check_scatterlist(sg, nr_segs, &bufflen, SG_MAX_SEGMENTS);
	if (res)
		return res;
	if (bufflen != scmd->request_bufflen)
		return -EINVAL;

	scmd->allowed_retries = 0;	/* this is not a tape! */

	if (sgreq->timeout_per_sec)
		scmd->timeout_per_sec = sgreq->timeout_per_sec;
	else
		scmd->timeout_per_sec = 300; /* 5 minutes */

	start_time = jiffies;
	res = sg_common_write(scmd, sg, nr_segs, bufflen, start_time);
	if (res == -EBUSY)
		sgreq->last_resid = scsi_bufflen(scmd) - bufflen + res;
	return res;
}

