void AveragePool(const PoolParams& params,
                   const RuntimeShape& input_shape, const float* input_data,
                   const RuntimeShape& filter_shape, const float* filter_data,
                   const RuntimeShape& output_shape, float* output_data) {
  const int input_height = input_shape.dims(1);
  const int input_width = input_shape.dims(2);
  const int output_height = output_shape.dims(1);
  const int output_width = output_shape.dims(2);
  const int pad_top = params.pad_top;
  const int pad_left = params.pad_left;
  const int stride_height = params.stride_height;
  const int stride_width = params.stride_width;
  const int filter_height = filter_shape.dims(1);
  const int filter_width = filter_shape.dims(2);

  // The last dimension of the filter is the depth.
  const int filter_depth = filter_shape.dims(3);
  const int input_depth = input_shape.dims(3);
  TFLITE_DCHECK_EQ(input_depth, filter_depth);

  // Setup output tensor.
  // TODO(andydavis) Consider making this a no-op if output is already zero.
  memset(output_data, 0, output_shape.FlatSize() * sizeof(float));

  // The average pooling operation is equivalent to convolution with an all
  // ones filter. The convolution implementation handles the zero-padding
  // and stride directly, so we use those to compute the output height and
  // width.
  //
  // The output height and width are re-computed from the input shape,
  // filter shape, and convolution parameters. This approach allows the
  // convolution implementation to change without breaking the average
  // pooling implementation.
  for (int b = 0; b < input_shape.dims(0); ++b) {
    for (int h = 0; h < input_height; ++h) {
      for (int w = 0; w < input_width; ++w) {
        for (int c = 0; c < input_depth; ++c) {
          const int output_y_origin =
              (h - pad_top) / stride_height + 1 - filter_height;
          const int output_x_origin =
              (w - pad_left) / stride_width + 1 - filter_width;
          // (1) If the location (output_y_origin, output_x_origin) is outside
          // the output tensor, then no contribution will be made to the
          // output, so we skip computing the contribution indices.
          //
          // (2) If the convolution operation is anchored, then the location
          // (output_y_origin, output_x_origin) must be within the output
          // tensor. If it is not, then the input tensor is too small and
          // we should throw an error.
          const bool is_outside_output =
              output_y_origin < 0 || output_y_origin >= output_height ||
              output_x_origin < 0 || output_x_origin >= output_width;
          if (is_outside_output) {
            continue;
          }
          // Since the filter is all ones, the contribution is simply the
          // input value at this location.
          const int input_index = (b * input_height + h) * input_width + w;
          for (int fh = 0; fh < filter_height; ++fh) {
            for (int fw = 0; fw < filter_width; ++fw) {
              // The location (output_y, output_x) is the location being
              // updated. The location (fh, fw) is the filter value being
              // used to update it.
              //
              // The location (conv_y, conv_x) is the location in the input
              // tensor being read from. It is derived from the location
              // being updated and the location of the filter value being
              // used to update it.
              const int conv_y = output_y_origin + fh;
              const int conv_x = output_x_origin + fw;
              // The location (conv_y, conv_x) falls outside the input tensor
              // if the convolution operation is not anchored.
              if (conv_y < 0 || conv_y >= input_height || conv_x < 0 ||
                  conv_x >= input_width) {
                continue;
              }
              const int filter_index =
                  (fh * filter_width + fw) * filter_depth + c;
              const int conv_index = (conv_y * input_width + conv_x) * input_depth + c;
              // The contribution is added to the output at the location being
              // updated. Since the filter is all ones, the contribution is
              // simply the input value at this location.
              output_data[(b * output_height + conv_y) * output_width + conv_x] +=
                  input_data[conv_index] * filter_data[filter_index];
            }
          }
        }
      }
    }
  }
}  // namespace tflite

