void operator()(OpKernelContet* ct, const CPUDevice& d, const T* inputs,
                   const int* input_lengths, const T* labels,
                   const int* label_lengths, T* costs, T* gradient) {
  // Clear costs.
  const int batch_size = input_lengths[0];
  const int max_time = input_lengths[1];
  if (costs != nullptr) {
    ct->eigen_device<Eigen::CPU>().setZero(costs, batch_size);
  }
  if (gradient != nullptr) {
    ct->eigen_device<Eigen::CPU>().setZero(gradient,
                                           batch_size * max_time);
  }
  // Check for empty batch.
  if (batch_size == 0) {
    return;
  }
  // Check that input_lengths is non-decreasing.
  for (int i = 1; i < batch_size; ++i) {
    OP_REQUIRES(ct, input_lengths[i - 1] <= input_lengths[i],
                errors::InvalidArgument("input_lengths is not "
                                        "non-decreasing."));
  }
  // Check that label_lengths is non-decreasing.
  for (int i = 1; i < batch_size; ++i) {
    OP_REQUIRES(ct, label_lengths[i - 1] <= label_lengths[i],
                errors::InvalidArgument("label_lengths is not "
                                        "non-decreasing."));
  }
  // Check that there is at least one valid input.
  OP_REQUIRES(ct, input_lengths[batch_size - 1] > 0,
              errors::InvalidArgument("input_lengths has no valid entry."));
  const int input_total = input_lengths[batch_size - 1];
  const int num_classes_raw = inputs[input_total - 1];
  // Check that there is at least one label.
  OP_REQUIRES(ct, num_classes_raw > 0,
              errors::InvalidArgument("num_classes <= 0"));
  const int num_classes = num_classes_raw + 1;  // For blank.
  // Check that label_lengths is non-decreasing.
  for (int i = 1; i < batch_size; ++i) {
    OP_REQUIRES(ct, label_lengths[i - 1] <= label_lengths[i],
                errors::InvalidArgument("label_lengths is not "
                                        "non-decreasing."));
  }
  const int output_total = label_lengths[batch_size - 1];
  // Compute total cost and gradient.
  CTCLossCalculator loss_calculator;
  loss_calculator.CalculateLoss(batch_size, max_time, num_classes,
                                input_lengths, inputs, label_lengths, labels,
                                costs, gradient);
}  // namespace tensorflow

