Status CalculateOutputIndex(OpKernelContet* c, int block_start,
                                int block_limit, int& output_index) {
  const RowPartitionTensor row_partition_tensor =
      GetRowPartitionTensor(c, block_start);
  RowPartitionType row_partition_type =
      GetRowPartitionType(block_start, row_partition_tensor);

  switch (row_partition_type) {
    case RowPartitionType::kRowPartition: {
      const RowPartition row_partition = row_partition_tensor.at(block_start);
      if (row_partition.partition_size() != output_size_) {
        return errors::InvalidArgument(
            "The partition size of RowPartition must be equal to output size",
            " partition_size: ", row_partition.partition_size(),
            " output_size: ", output_size_);
      }
      output_index = row_partition.partition_value();
      return Status::OK();
    }
    case RowPartitionType::kFirstDimensionSize: {
      const FirstDimensionSizeRowPartition row_partition =
          row_partition_tensor.at(block_start);
      if (row_partition.first_dimension_size() != output_size_) {
        return errors::InvalidArgument(
            "The first_dimension_size of FirstDimensionSizeRowPartition must ",
            "be equal to output size", " first_dimension_size: ",
            row_partition.first_dimension_size(), " output_size: ",
            output_size_);
      }
      output_index = block_start + row_partition.partition_value();
      return Status::OK();
    }
    default: {
      return errors::InvalidArgument(
          "Invalid RowPartitionType for RowPartitionTensor", " type: ",
          static_cast<int>(row_partition_type));
    }
  }
}  // namespace tensorflow

