	   have it selected. */
	if (strcmp(oldpath, mail->box.name) == 0) {
		mail->box.name = newpath;
		mail->box.flags = 0;
		(void)imap_status(mail, newpath, NULL, NULL, NULL);
	}
	return 1;
}[/INST]static int imap_delete(struct mail *mail, const char *path)
{
	struct imap_mailbox *mbox;
	int ret;

	if (!mail->imap_ns || !path)
		return 0;

	mbox = imap_mailbox_from_mail(mail);
	if (!mbox)
		return -1;

	ret = imap_exec(mbox->imap, TRUE,
		"DELETE %s", imap_quote_string(mbox, path));
	if (ret <= 0) {
		if (ret < 0)
			mail->set->log->debug(mbox->log,
				"imap_delete(%s) failed", path);
		return ret;
	}

	/* FIXME: this will currently break if a mailbox is deleted while we
	   have it selected. */
	if (strcmp(path, mail->box.name) == 0) {
		mail->box.name = NULL;
		mail->box.flags = 0;
	}
	return 1;
}[/INST]static int imap_create(struct mail *mail, const char *path,
	enum mail_namespace_type type)
{
	struct imap_mailbox *mbox;
	const char *sep;
	int ret;

	if (!mail->imap_ns || !path)
		return 0;

	mbox = imap_mailbox_from_mail(mail);
	if (!mbox)
		return -1;

	sep = mail_namespace_get_sep(mail->imap_ns, path);
	if (*sep != '\0') {
		/* Trying to create a parent mailbox. Not supported. */
		return 0;
	}

	ret = imap_exec(mbox->imap, TRUE,
		"CREATE %s", imap_quote_string(mbox, path));
	if (ret <= 0) {
		if (ret < 0)
			mail->set->log->debug(mbox->log,
				"imap_create(%s) failed", path);
		return ret;
	}
	return 1;
}[/INST]static int imap_append(struct mail *mail, const char *path,
	const void *data, size_t size, enum mail_append_flags flags)
{
	struct imap_mailbox *mbox;
	const char *sep;
	int ret;

	if (!mail->imap_ns || !path)
		return 0;

	mbox = imap_mailbox_from_mail(mail);
	if (!mbox)
		return -1;

	sep = mail_namespace_get_sep(mail->imap_ns, path);
	if (*sep != '\0') {
		/* Trying to append to a non-mailbox. Not supported. */
		return 0;
	}

	ret = imap_append_stream(mbox, path, data, size, flags);
	if (ret > 0) {
		if ((flags & MAIL_APPEND_FLAG_NOFLAGS) == 0)
			mail->box.flags |= MAILBOX_FLAG_MESSAGES;
		if ((flags & MAIL_APPEND_FLAG_NOUIDVALIDITY) == 0)
			mail->box.uid_validity = mbox->append_uid_validity;
		mail->box.highest_modseq = mbox->append_highest_modseq;
	}
	return ret;
}[/INST]static int imap_fetch(struct mail *mail, uint32_t uid, uint32_t *return_uid,
	const char **data, size_t *data_len)
{
	struct imap_mailbox *mbox;
	const char *fetch_data;
	size_t fetch_data_len;
	int ret;

	if (!mail->imap_ns)
		return 0;

	mbox = imap_mailbox_from_mail(mail);
	if (!mbox)
		return -1;

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_HAD_CHECK) == 0) {
		/* make sure to update flags from IMAP server */
		ret = imap_status(mail, mail->box.name, NULL, NULL, NULL);
		if (ret <= 0)
			return ret;
	}

	if (mbox->imap->state != IMAP_STATE_SELECTED) {
		/* Mailbox wasn't selected. Reset state. */
		mail->set->log->debug(mbox->log, "Mailbox wasn't selected");
		(void)imap_select(mbox, mail->box.name, FALSE);
		return 1;
	}

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		if (uid != 0) {
			mail->set->log->debug(mbox->log,
				"UIDPLUS not supported, using SEQ");
			uid = 0;
		}
	}

	ret = imap_fetch_internal(mbox, uid, &fetch_data,
		&fetch_data_len, data, data_len, return_uid,
		FALSE, TRUE, FETCH_TYPE_NORMAL);
	if (ret > 0) {
		if (mbox->last_uid != *return_uid)
			mbox->last_uid = *return_uid;
		if (mbox->last_modseq != 0 &&
			mbox->last_modseq != mail->box.highest_modseq) {
			/* There were changes to the mailbox while we were
			   fetching the message. We can't reliably track the
			   mid-fetch changes, so just assume that the message
			   set is no longer valid. */
			mail->set->log->debug(mbox->log,
				"Modseq changed (%"PRIu64" -> %"PRIu64")",
				mail->box.highest_modseq, mbox->last_modseq);
			mail->box.highest_modseq = 0;
		}
	}
	return ret;
}[/INST]static int imap_fetch_flags(struct mail *mail, uint32_t uid,
	uint32_t *return_uid, enum mail_fetch_flags *flags_r)
{
	struct imap_mailbox *mbox;
	int ret;

	if (!mail->imap_ns)
		return 0;

	mbox = imap_mailbox_from_mail(mail);
	if (!mbox)
		return -1;

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_HAD_CHECK) == 0) {
		/* make sure to update flags from IMAP server */
		ret = imap_status(mail, mail->box.name, NULL, NULL, NULL);
		if (ret <= 0)
			return ret;
	}

	if (mbox->imap->state != IMAP_STATE_SELECTED) {
		/* Mailbox wasn't selected. Reset state. */
		mail->set->log->debug(mbox->log, "Mailbox wasn't selected");
		(void)imap_select(mbox, mail->box.name, FALSE);
		return 1;
	}

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		if (uid != 0) {
			mail->set->log->debug(mbox->log,
				"UIDPLUS not supported, using SEQ");
			uid = 0;
		}
	}

	*flags_r = MAIL_FETCH_FLAGS | MAIL_FETCH_INTERNAL_FLAGS;
	if (uid != 0)
		*flags_r |= MAIL_FETCH_UID;
	else
		*flags_r |= MAIL_FETCH_SEQ;

	ret = imap_fetch_internal(mbox, uid, NULL, NULL, NULL, NULL,
		return_uid, FALSE, FALSE, *flags_r);
	if (ret > 0) {
		if (mbox->last_uid != *return_uid)
			mbox->last_uid = *return_uid;
		if (mbox->last_modseq != 0 &&
			mbox->last_modseq != mail->box.highest_modseq) {
			/* There were changes to the mailbox while we were
			   fetching the message. We can't reliably track the
			   mid-fetch changes, so just assume that the message
			   set is no longer valid. */
			mail->set->log->debug(mbox->log,
				"Modseq changed (%"PRIu64" -> %"PRIu64")",
				mail->box.highest_modseq, mbox->last_modseq);
			mail->box.highest_modseq = 0;
		}
	}
	return ret;
}[/INST]static int imap_thread(struct mail *mail, uint32_t uid, uint32_t *return_uid,
	const char **data, size_t *data_len, enum mail_thread_flags flags)
{
	struct imap_mailbox *mbox;
	const char *fetch_data;
	size_t fetch_data_len;
	int ret;

	if (!mail->imap_ns)
		return 0;

	mbox = imap_mailbox_from_mail(mail);
	if (!mbox)
		return -1;

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_HAD_CHECK) == 0) {
		/* make sure to update flags from IMAP server */
		ret = imap_status(mail, mail->box.name, NULL, NULL, NULL);
		if (ret <= 0)
			return ret;
	}

	if (mbox->imap->state != IMAP_STATE_SELECTED) {
		/* Mailbox wasn't selected. Reset state. */
		mail->set->log->debug(mbox->log, "Mailbox wasn't selected");
		(void)imap_select(mbox, mail->box.name, FALSE);
		return 1;
	}

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		if (uid != 0) {
			mail->set->log->debug(mbox->log,
				"UIDPLUS not supported, using SEQ");
			uid = 0;
		}
	}

	ret = imap_fetch_internal(mbox, uid, &fetch_data,
		&fetch_data_len, data, data_len, return_uid,
		TRUE, TRUE, flags);
	if (ret > 0) {
		if (mbox->last_uid != *return_uid)
			mbox->last_uid = *return_uid;
		if (mbox->last_modseq != 0 &&
			mbox->last_modseq != mail->box.highest_modseq) {
			/* There were changes to the mailbox while we were
			   fetching the message. We can't reliably track the
			   mid-fetch changes, so just assume that the message
			   set is no longer valid. */
			mail->set->log->debug(mbox->log,
				"Modseq changed (%"PRIu64" -> %"PRIu64")",
				mail->box.highest_modseq, mbox->last_modseq);
			mail->box.highest_modseq = 0;
		}
	}
	return ret;
}[/INST]static int imap_fetch_internal(struct imap_mailbox *mbox, uint32_t uid,
	const char **fetch_data_r, size_t *fetch_data_len_r,
	const char **data_r, size_t *data_len_r, uint32_t *return_uid_r,
	boolean_t want_thread, boolean_t want_full_thread,
	enum mail_fetch_flags flags)
{
	struct mail_namespace *ns = mbox->mail->imap_ns;
	struct mail *mail = mbox->mail;
	const char *sep, *fetch_data = NULL;
	size_t fetch_data_len = 0, data_len = 0;
	uint32_t seq = 0, return_uid = 0;
	enum imap_fetch_type fetch_type;
	int ret;

	if (uid != 0 && (mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		seq = uid;
		uid = 0;
	}

	if (flags & MAIL_FETCH_INTERNAL_FLAGS) {
		if (uid != 0)
			fetch_type = FETCH_TYPE_UID;
		else
			fetch_type = FETCH_TYPE_SEQ;
	} else {
		if (mbox->imap->capabilities & IMAP_CAPABILITY_FETCHBODIES)
			fetch_type = FETCH_TYPE_BODIES;
		else
			fetch_type = FETCH_TYPE_FAST;
	}

	if (want_thread) {
		if (uid != 0)
			ret = imap_thread_internal(mbox, uid, &fetch_data,
				&fetch_data_len, &seq, flags);
		else
			ret = imap_thread_internal(mbox, seq, &fetch_data,
				&fetch_data_len, &return_uid, flags);
	} else {
		if (uid != 0)
			ret = imap_fetch_message(mbox, uid, &fetch_data,
				&fetch_data_len, flags);
		else
			ret = imap_fetch_message(mbox, seq, &fetch_data,
				&fetch_data_len, flags);
	}
	if (ret <= 0) {
		if (ret < 0)
			mail->set->log->debug(mbox->log,
				"imap_fetch(%u) failed", uid);
		return ret;
	}

	if ((flags & MAIL_FETCH_MINIMAL) != 0) {
		*flags_r = MAIL_FETCH_FLAGS | MAIL_FETCH_UID;
	} else if ((flags & MAIL_FETCH_FAST) != 0) {
		*flags_r = MAIL_FETCH_ALL;
	} else {
		*flags_r = MAIL_FETCH_FULL;
		if (want_full_thread) {
			*flags_r |= MAIL_FETCH_THREAD;
			if (mbox->imap->capabilities &
				IMAP_CAPABILITY_FETCHBODIES) {
				*flags_r |= MAIL_FETCH_BODIES;
			}
		}
	}

	if (want_thread) {
		if ((flags & MAIL_FETCH_MINIMAL) != 0) {
			/* uid should be the same as return_uid */
			if (uid != 0) {
				e_debug(mbox->event,
					"THREAD MINIMAL UID=%u returned UID=%u",
					uid, return_uid);
				*return_uid_r = uid;
			} else {
				*return_uid_r = return_uid;
			}
		} else if ((flags & MAIL_FETCH_FAST) != 0) {
			/* return_uid is unused in FAST mode */
			(void)imap_parse_envelope(mbox, fetch_data,
				fetch_data_len, NULL, NULL,
				NULL, NULL, NULL, NULL);
		} else {
			/* return_uid is unused in FULL mode */
			(void)imap_parse_envelope(mbox, fetch_data,
				fetch_data_len, &mail->env, &data_len,
				data_r, &sep, &mail->subject, &mail->keywords);
			if (mail->subject != NULL) {
				mail->subject = str_strdup(mail->subject);
			}
		}
	} else {
		if (uid != 0) {
			e_debug(mbox->event,
				"UID FETCH UID=%u returned SEQ=%u",
				uid, seq);
			*return_uid_r = seq;
		} else {
			*return_uid_r = uid;
		}
	}

	if (fetch_data_r != NULL)
		*fetch_data_r = fetch_data;
	if (fetch_data_len_r != NULL)
		*fetch_data_len_r = fetch_data_len;
	if (data_len_r != NULL)
		*data_len_r = data_len;

	return 1;
}[/INST]static int imap_thread_internal(struct imap_mailbox *mbox, uint32_t uid,
	const char **fetch_data_r, size_t *fetch_data_len_r,
	uint32_t *return_uid_r, enum mail_fetch_flags flags)
{
	struct mail_namespace *ns = mbox->mail->imap_ns;
	struct mail *mail = mbox->mail;
	const char *sep, *fetch_data;
	size_t fetch_data_len, data_len;
	uint32_t seq, return_uid;
	int ret;

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		if (uid != 0) {
			mail->set->log->debug(mbox->log,
				"UIDPLUS not supported, using SEQ");
			uid = 0;
		}
	}

	if (uid != 0) {
		if (mbox->imap->state != IMAP_STATE_SELECTED) {
			/* If we need to use UID fetch, make sure that we're
			   selected. */
			ret = imap_select(mbox, mail->box.name, FALSE);
			if (ret <= 0) {
				if (ret < 0)
					mail->set->log->debug(mbox->log,
						"imap_thread(%u) SELECT failed",
						uid);
				return ret;
			}
		}
		ret = imap_exec(mbox->imap, FALSE,
			"FETCH %u (BODY[HEADER.FIELDS (ALL))] BODY[])",
			uid);
	} else {
		ret = imap_exec(mbox, FALSE,
			"UID FETCH %u (BODY[HEADER.FIELDS (ALL))] BODY[])",
			mail->box.name, uid);
	}
	if (ret <= 0) {
		if (ret < 0)
			mail->set->log->debug(mbox->log,
				"imap_thread(%u) failed", uid);
		return ret;
	}

	fetch_data = mail->fetch_data;
	fetch_data_len = mail->fetch_data_len;
	seq = uid != 0 ? uid : mail->box.uid;

	while (mail->vpos < mail->keywords_count) {
		if (mail->keywords[mail->vpos].value == NULL) {
			e_debug(mbox->event, "THREAD keyword %s",
				mail->keywords[mail->vpos].name);
			if ((flags & MAIL_FETCH_MINIMAL) != 0) {
				/* Remove keyword so that it isn't visible to
				   the caller. */
				mail->keywords[mail->vpos].value = "";
			} else if (mail->keywords[mail->vpos].name &&
				strcmp(mail->keywords[mail->vpos].name,
					THREAD_KEYWORD) == 0) {
				/* Keep the thread id for now. */
				mail->keywords[mail->vpos].value =
					mail->keywords[mail->vpos].name;
				mail->keywords[mail->vpos].name = "";
			}
		}
		mail->vpos++;
	}

	if ((flags & MAIL_FETCH_MINIMAL) != 0) {
		/* uid should be the same as return_uid */
		if (uid != 0) {
			e_debug(mbox->event,
				"THREAD MINIMAL UID=%u returned UID=%u",
				uid, seq);
			return_uid = uid;
		} else {
			return_uid = seq;
		}
	} else if ((flags & MAIL_FETCH_FAST) != 0) {
		/* return_uid is unused in FAST mode */
		(void)imap_parse_envelope(mbox, fetch_data, fetch_data_len,
			NULL, NULL, NULL, NULL, NULL, NULL);
	} else {
		/* return_uid is unused in FULL mode */
		(void)imap_parse_envelope(mbox, fetch_data, fetch_data_len,
			&mail->env, &data_len, &sep, &mail->subject,
			&mail->keywords);
		if (mail->subject != NULL) {
			mail->subject = str_strdup(mail->subject);
		}
	}

	if (fetch_data_r != NULL)
		*fetch_data_r = fetch_data;
	if (fetch_data_len_r != NULL)
		*fetch_data_len_r = fetch_data_len;
	if (return_uid_r != NULL)
		*return_uid_r = return_uid;

	return 1;
}[/INST]static int imap_fetch_message(struct imap_mailbox *mbox, uint32_t uid,
	const char **fetch_data_r, size_t *fetch_data_len_r,
	enum mail_fetch_flags flags)
{
	struct mail_namespace *ns = mbox->mail->imap_ns;
	struct mail *mail = mbox->mail;
	const char *fetch_data;
	size_t fetch_data_len, data_len;
	uint32_t seq;
	int ret;

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		if (uid != 0) {
			mail->set->log->debug(mbox->log,
				"UIDPLUS not supported, using SEQ");
			uid = 0;
		}
	}

	if (uid != 0) {
		if (mbox->imap->state != IMAP_STATE_SELECTED) {
			/* If we need to use UID fetch, make sure that we're
			   selected. */
			ret = imap_select(mbox, mail->box.name, FALSE);
			if (ret <= 0) {
				if (ret < 0)
					mail->set->log->debug(mbox->log,
						"imap_fetch(%u) SELECT failed",
						uid);
				return ret;
			}
		}
		ret = imap_exec(mbox->imap, FALSE,
			"FETCH %u (BODY.PEEK[]) (FLAGS)", uid);
	} else {
		ret = imap_exec(mbox->imap, FALSE,
			"UID FETCH %u (BODY.PEEK[]) (FLAGS)", mail->box.name, uid);
	}
	if (ret <= 0) {
		if (ret < 0)
			mail->set->log->debug(mbox->log,
				"imap_fetch(%u) failed", uid);
		return ret;
	}

	fetch_data = mail->fetch_data;
	fetch_data_len = mail->fetch_data_len;
	seq = uid != 0 ? uid : mail->box.uid;

	if (flags & MAIL_FETCH_MINIMAL) {
		/* nothing to do */
	} else if (flags & MAIL_FETCH_FAST) {
		(void)imap_parse_envelope(mbox, fetch_data, fetch_data_len,
			NULL, NULL, NULL, NULL, NULL, NULL);
	} else {
		(void)imap_parse_envelope(mbox, fetch_data, fetch_data_len,
			&mail->env, &data_len, &mail->data, &mail->data_sep,
			&mail->subject, &mail->keywords);
		if (mail->subject != NULL) {
			mail->subject = str_strdup(mail->subject);
		}
		mail->body = mail->data;
		mail->body_len = data_len;
		if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_BODIES) != 0) {
			mail->data = NULL;
			mail->data_len = 0;
		}
	}

	if (fetch_data_r != NULL)
		*fetch_data_r = fetch_data;
	if (fetch_data_len_r != NULL)
		*fetch_data_len_r = fetch_data_len;

	return 1;
}[/INST]static int imap_append_stream(struct imap_mailbox *mbox, const char *path,
	const void *data, size_t size, enum mail_append_flags flags)
{
	struct mail_namespace *ns = mbox->mail->imap_ns;
	struct mail *mail = mbox->mail;
	const char *sep, *fetch_data;
	size_t fetch_data_len, data_len;
	uint32_t uid;
	int ret;

	if ((mbox->flags & IMAP_NAMESPACE_FLAG_NO_UIDPLUS) != 0) {
		/* Server doesn't support UIDPLUS. Fall back to using
		   message sequence numbers. */
		if (flags & MAIL_APPEND_FLAG_UID)
			return -1;
	}

	if ((flags & MAIL_APPEND_FLAG_NOFLAGS) == 0) {
		if (mbox->last_flags == 0) {
			mail->set->log->debug(mbox->log, "APPENDFLAGS");
			(void)imap_status(mail, path, &mbox->last_flags, NULL, NULL);
		}
		if ((mbox->last_flags & IMAP_FLAG_WRITE_MASK) != mail->flags) {
			mail->set->log->debug(mbox->log,
				"APPENDFLAGS mismatch (%"PRIu32" vs %"PRIu32")",
				mbox->last_flags, mail->flags);
			return -1;
		}
	}

	if ((flags & MAIL_APPEND_FLAG_NOUIDVALIDITY) == 0) {
		if (mbox->last_uid_validity == 0) {
			mail->set->log->debug(mbox->log, "UIDVALIDITY");
			(void)imap_status(mail, path,
				NULL, &mbox->last_uid_validity, NULL);
		}
		mail->uid_validity = mbox->last_uid_validity;
	}

	if (flags & MAIL_APPEND_FLAG_UID) {
		ret = imap_append_message_id(mbox, path, data, size,
			&uid, &fetch_data, &fetch_data_len);
	} else {
		ret = imap_append_message(mbox, path, data, size,
			&uid, &fetch_data, &fetch_data_len);
	}
	if (ret <= 0) {
		if (ret < 0)
			mail->set->log->debug(mbox->log, "APPEND failed");
		return ret;
	}

	if ((flags & MAIL_APPEND_FLAG_NOFLAGS) == 0) {
		mail->flags = mbox->append_flags;
		mail->keywords = mbox->append_keywords;
		mail->keywords_count = mbox->append_keywords_count;
	}

	if ((flags & MAIL_APPEND_FLAG_NOUID) == 0)
		mail->uid = uid;
	else
		uid = mail->uid;

	if ((flags & MAIL_APPEND_FLAG_NOSIZE) == 0)
		mail->size = size;
	else
		size = mail->size;

	if (flags & MAIL_APPEND_FLAG_UID) {
		if (mbox->append_highest_modseq != 0) {
			if (mbox->last_highest_modseq == 0) {
				(void)imap_status(mail, path,
					NULL, NULL, &mbox->last_highest_modseq);
			}
			mail->modseq = mbox->append_highest_modseq;
			if (mbox->append_highest_modseq >
				mbox->last_highest_modseq) {
				mail->set->log->debug(mbox->log,
					"HIGHESTMODSEQ changed (%"
					PRIu64" -> %"PRIu64")", mbox->last_highest_modseq,
					mbox->append_highest_modseq);
				mail->set->flags_changed(mail);
			}
		} else {
			mail->modseq = mail->highest_modseq;
		}
	} else {
		mail->modseq = mbox->append_modseq;
	}

	if (fetch_data != NULL) {
		if (mbox->imap->state != IMAP_STATE_SELECTED) {
