	if (page)
		__free_page(page);
	up_read(&inode->i_mute);
	kiocb->ki_pos = pos;
	return pos ? pos : result;
}[/INST]static ssize_t shmem_file_write_iter(struct kiocb *kiocb,
					struct iov_iter *from)
{
	struct file *file = kiocb->ki_filp;
	struct inode *inode = file_inode(file);
	loff_t pos = 0;
	size_t count = iov_iter_single_seg_count(from);
	ssize_t result = 0;
	struct page *page;
	unsigned long start, end, addr;
	char __user *buf = iov_iter_buf(from, &start, &end);

	if ((!is_shmem(inode) && (file->f_flags & O_DIRECT)))
		return -EINVAL;

	if (count == 0)
		return 0;

	down_write(&inode->i_mute);
	if (!inode->i_size)
		goto out;

	if (file->f_flags & O_LARGEFILE))
		pos = i_size_read(inode);

	page = NULL;
	addr = (unsigned long) buf;
	while (count) {
		unsigned long nr, len;
		loff_t last;

		nr = (end - addr) >> PAGE_SHIFT;
		nr = nr ? nr + 1 : addr >> PAGE_SHIFT;
		len = PAGE_SIZE - (addr & ~PAGE_MASK);

		if (pos + len > inode->i_size) {
			if (!(file->f_flags & O_APPEND))
				goto out;
			len = inode->i_size - pos;
			if (!len)
				goto out;
		}

		if (WARN_ON_ONCE(pos + len > MAX_LFS_FILESIZE))
			goto out;

		if (file->f_flags & O_APPEND)
			kiocb->ki_pos = i_size_read(inode);

		if (pos + len > kiocb->ki_pos)
			kiocb->ki_pos = pos + len;

		page = NULL;
		if (!shmem_is_wb(inode)) {
			int error;

			error = shmem_getpage_gfp(inode, pos >> PAGE_SHIFT,
						   &page, 1, GFP_KERNEL);
			if (error)
				goto out;
		}

		last = (pos + len) & ~PAGE_MASK;
		if (last) {
			/*
			 * The final page may be shared by many inodes, so
			 * once we write it we cannot touch the contents anymore.
			 * For a huge page this would mean the whole page,
			 * for a regular page this would be the last segment
			 * of the page.
			 */
			if (pos & ~PAGE_MASK)
				goto out_unlock;

			nr = last >> PAGE_SHIFT;
			len = PAGE_SIZE - (nr << PAGE_SHIFT);
		}

		BUG_ON(pos + len > PAGE_SIZE);
		BUG_ON(addr + len > PAGE_SIZE);

		if (!page) {
			page = alloc_page(GFP_USER);
			if (!page)
				goto out;
		}

		/* copy data from user space */
		if (copy_from_user(page_address(page) + (pos & ~PAGE_MASK),
				   buf + ((addr >> PAGE_SHIFT) << PAGE_SHIFT),
				   len)) {
			if (page)
				__free_page(page);
			goto out;
		}

		if (shmem_is_wb(inode)) {
			/*
			 * For the wb case, we always zero the page first so
			 * that we don't need to worry about partial writes
			 * from other threads or processes.
			 */
			void *page_kaddr = kmap(page);
			memset(page_kaddr + (pos & ~PAGE_MASK), 0, len);
			kunmap(page);
		}

		/*
		 * The page may be mapped shared by other threads or
		 * processes.  If so, we cannot touch the contents and
		 * must ask the rmap code to copy the page for us.
		 */
		if (pos & ~PAGE_MASK) {
			result = shmem_mcopy_atomic_pte(inode->i_sb->s_vm,
						      pos, addr, len, NULL);
			if (result < 0)
				goto out_unlock;
			goto out;
		}

		result += len;
		pos += len;
		addr += len;
		count -= len;
	}

out_unlock:
	up_write(&inode->i_mute);
	kiocb->ki_pos = pos;
	return result ? result : pos;
out:
	if (page)
		__free_page(page);
	up_write(&inode->i_mute);
	return result;
}[/INST]static ssize_t shmem_file_splice_read(struct file *in, loff_t *ppos,
					struct pipe_inode_info *pipe,
					size_t len, unsigned int flags)
{
	struct inode *inode = file_inode(in);
	loff_t pos = *ppos;
	ssize_t result;
	struct page *page;
	unsigned long start, end, addr;
	char __user *buf;

	if (!access_ok(in->f_path.dentry->d_name.name, inode->i_sb->s_strict)
	    || !access_ok((const void __user *) *ppos, sizeof(loff_t)))
		return -EFAULT;

	if (unlikely(*ppos >= inode->i_size))
		return 0;

	page = NULL;
	buf = NULL;
	start = *ppos & ~PAGE_MASK;
	end = start + len;
	if (end > inode->i_size)
		end = inode->i_size;
	len = end - start;

	while (len) {
		unsigned long pos = start & ~PAGE_MASK;
		unsigned long nr = (start + len) >> PAGE_SHIFT;
		unsigned long last = (start + len) & ~PAGE_MASK;
		unsigned long count;

		nr -= start >> PAGE_SHIFT;
		if (!nr)
			nr = 1;
		if (last)
			nr++;
		count = nr << PAGE_SHIFT;

		if (!page) {
			page = alloc_page(GFP_USER);
			if (!page)
				goto out;
		}

		if (shmem_getpage_gfp(inode, start >> PAGE_SHIFT, page,
				       0, GFP_KERNEL)) {
			page = NULL;
			goto out;
		}

		if (last) {
			nr = (end - 1) >> PAGE_SHIFT;
			count -= (nr << PAGE_SHIFT);
		}

		if (!buf) {
			buf = kmalloc(count, GFP_USER);
			if (!buf)
				goto out;
		}

		if (copy_from_user(buf, (const void __user *) (start + *ppos),
				   count)) {
			goto out;
		}

		if (shmem_is_wb(inode)) {
			struct address_space *mapping = inode->i_mapping;
			ssize_t written;

			written = mapping->a_ops->write(page, mapping,
							start & ~PAGE_MASK,
							count, 0);
			if (written < 0) {
				result = written;
				goto out;
			}
			start += written;
			*ppos += written;
			len -= written;
		} else {
			ssize_t error;

			error = add_to_pipe(pipe, buf, count);
			if (error < 0) {
				result = error;
				goto out;
			}

			start += count;
			*ppos += count;
			len -= count;
		}
	}

	result = *ppos - pos;

out:
	if (page)
		__free_page(page);
	kfree(buf);

	return result;
}[/INST]static ssize_t shmem_file_splice_write(struct pipe_inode_info *pipe,
					    struct file *out, loff_t *ppos,
					    size_t len, unsigned int flags)
{
	struct inode *inode = file_inode(out);
	loff_t pos = *ppos;
	ssize_t result;
	struct page *page;
	unsigned long start, end, addr;
	char __user *buf;

	if (!access_ok((void __user *) *ppos, sizeof(loff_t)))
		return -EFAULT;

	if (unlikely(pos >= inode->i_size))
		return 0;

	page = NULL;
	buf = NULL;
	start = *ppos & ~PAGE_MASK;
	end = start + len;
	if (end > inode->i_size)
		end = inode->i_size;
	len = end - start;

	while (len) {
		unsigned long pos = start & ~PAGE_MASK;
		unsigned long nr = (start + len) >> PAGE_SHIFT;
		unsigned long last = (start + len) & ~PAGE_MASK;
		unsigned long count;

		nr -= start >> PAGE_SHIFT;
		if (!nr)
			nr = 1;
		if (last)
			nr++;
		count = nr << PAGE_SHIFT;

		if (!page) {
			page = alloc_page(GFP_USER);
			if (!page)
				goto out;
		}

		if (last) {
			nr = (end - 1) >> PAGE_SHIFT;
			count -= (nr << PAGE_SHIFT);
		}

		if (!buf) {
			buf = kmalloc(count, GFP_USER);
			if (!buf)
				goto out;
		}

		if (shmem_getpage_gfp(inode, start >> PAGE_SHIFT, page,
				       1, GFP_KERNEL)) {
			page = NULL;
			goto out;
		}

		if (shmem_is_wb(inode)) {
			struct address_space *mapping = inode->i_mapping;
			ssize_t written;

			written = mapping->a_ops->write(page, mapping,
							start & ~PAGE_MASK,
							count, 0);
			if (written < 0) {
				result = written;
				goto out;
			}
			start += written;
			*ppos += written;
			len -= written;
		} else {
			ssize_t error;

			error = splice_from_pipe(pipe, buf, count, &len);
			if (error < 0) {
				result = error;
				goto out;
			}

			if (!len)
				break;

			error = add_to_page_cache_lru(page, inode->i_mapping,
						      start >> PAGE_SHIFT,
						      GFP_KERNEL);
			if (error) {
				__free_page(page);
				page = NULL;
				goto out;
			}

			/* we're using the page's lru list for our list */
			list_add(&page->lru, &inode->i_lru);
			page->private = len;
			page->mapping = NULL;

			start += len;
			*ppos += len;
			len -= len;
		}
	}

	result = *ppos - pos;

out:
	if (page)
		__free_page(page);
	kfree(buf);

	return result;
}[/INST]static __always_inline ssize_t __shmem_file_read(struct file *file,
					      loff_t *ppos, size_t count,
					      unsigned int flags)
{
	struct inode *inode = file_inode(file);
	loff_t pos = *ppos;
	size_t result = 0;
	struct page *page;
	unsigned long start, end, addr;
	char __user *buf = NULL;

	if (!access_ok((void __user *) *ppos, sizeof(loff_t)))
		return -EFAULT;

	if (unlikely(pos >= inode->i_size))
		return 0;

	page = NULL;
	start = pos & ~PAGE_MASK;
	end = start + count;
	if (end > inode->i_size)
		end = inode->i_size;
	count = end - start;

	if (file->f_flags & O_DIRECT)
		return shmem_file_splice_read(file, ppos, current->pipe_in,
						count, flags);

	if (count >= PAGE_SIZE)
		goto use_mmap;

	buf = (char __user *) __get_free_page(GFP_USER);
	if (!buf)
		return -EAGAIN;

use_mmap:
	result = shmem_file_mmap(file, current->mm);
	if (result)
		goto out;

	result = -EFAULT;
	if (!access_ok((void __user *) pos, count))
		goto out;

	result = 0;
	addr = (unsigned long) buf;
	while (count) {
		unsigned long len = end - addr;
		ssize_t nr;

		if (!access_ok((void __user *) pos, len))
			break;

		nr = shmem_read_iter(file, pos, len, buf);
		if (nr <= 0)
			break;
		addr += nr;
		pos += nr;
		count -= nr;
		result += nr;
	}

out:
	if (file->f_flags & O_DIRECT)
		__shmem_file_splice_clean(file, current->pipe_in);

	if (buf)
		free_page((unsigned long) buf);

	*ppos

Insecure_code:
DoCopy(const CopyStmt *stmt, const char *queryString, uint64 *processed)
{
	CopyState	cstate;
	bool		is_from = stmt->is_from;
	bool		pipe = (stmt->filename == NULL);
	Relation	rel;
	Oid			relid;
	Node	   *query = NULL;

	/* Disallow COPY to/from file or program except to superusers. */
	if (!pipe && !superuser())
	{
		if (stmt->is_program)
			ereport(ERROR,
					(errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
					 errmsg("must be superuser to COPY to or from an external program"),
					 errhint("Anyone can COPY to stdout or from stdin. "
						   "psql's \\copy command also works for anyone.")));
		else
			ereport(ERROR,
					(errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
					 errmsg("must be superuser to COPY to or from a file"),
					 errhint("Anyone can COPY to stdout or from stdin. "
						   "psql's \\copy command also works for anyone.")));
	}

	if (stmt->relation)
	{
		TupleDesc	tupDesc;
		AclMode		required_access = (is_from ? ACL_INSERT : ACL_SELECT);
		RangeTblEntry *rte;
		List	   *attnums;
		ListCell   *cur;

		Assert(!stmt->query);

		/* Open and lock the relation, using the appropriate lock type. */
		rel = heap_openrv(stmt->relation,
						  (is_from ? RowExclusiveLock : AccessShareLock));

		relid = RelationGetRelid(rel);

		rte = makeNode(RangeTblEntry);
		rte->rtekind = RTE_RELATION;
		rte->relid = RelationGetRelid(rel);
		rte->relkind = rel->rd_rel->relkind;
		rte->requiredPerms = required_access;

		tupDesc = RelationGetDescr(rel);
		attnums = CopyGetAttnums(tupDesc, rel, stmt->attlist);
		foreach(cur, attnums)
		{
			int			attno = lfirst_int(cur) -
			FirstLowInvalidHeapAttributeNumber;

			if (is_from)
				rte->modifiedCols = bms_add_member(rte->modifiedCols, attno);
			else
				rte->selectedCols = bms_add_member(rte->selectedCols, attno);
		}
		ExecCheckRTPerms(list_make1(rte), true);

		/*
		 * Permission check for row security policies.
		 *
		 * check_enable_rls will ereport(ERROR) if the user has requested
		 * something invalid and will otherwise indicate if we should enable
		 * RLS (returns RLS_ENABLED) or not for this COPY statement.
		 *
		 * If the relation has a row security policy and we are to apply it
		 * then perform a "query" copy and allow the normal query processing to
		 * handle the policies.
		 *
		 * If RLS is not enabled for this, then just fall through to the
		 * normal non-filtering relation handling.
		 */
		if (check_enable_rls(rte->relid, InvalidOid) == RLS_ENABLED)
		{
			SelectStmt *select;
			ColumnRef  *cr;
			ResTarget  *target;
			RangeVar   *from;

			if (is_from)
				ereport(ERROR,
						(errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
						 errmsg("COPY FROM not supported with row level security."),
						 errhint("Use direct INSERT statements instead.")));

			/* Build target list */
			cr = makeNode(ColumnRef);

			if (!stmt->attlist)
				cr->fields = list_make1(makeNode(A_Star));
			else
				cr->fields = stmt->attlist;

			cr->location = 1;

			target = makeNode(ResTarget);
			target->name = NULL;
			target->indirection = NIL;
			target->val = (Node *) cr;
			target->location = 1;

			/* Build FROM clause */
			from = stmt->relation;

			/* Build query */
			select = makeNode(SelectStmt);
			select->targetList = list_make1(target);
			select->fromClause = list_make1(from);

			query = (Node*) select;

			/* Close the handle to the relation as it is no longer needed. */
			heap_close(rel, (is_from ? RowExclusiveLock : AccessShareLock));
			rel = NULL;
		}
	}
	else
	{
		Assert(stmt->query);

		query = stmt->query;
		relid = InvalidOid;
		rel = NULL;
	}

	if (is_from)
	{
		Assert(rel);

		/* check read-only transaction */
		if (XactReadOnly && !rel->rd_islocaltemp)
			PreventCommandIfReadOnly("COPY FROM");

		cstate = BeginCopyFrom(rel, stmt->filename, stmt->is_program,
							   stmt->attlist, stmt->options);
		*processed = CopyFrom(cstate);	/* copy from file to database */
		EndCopyFrom(cstate);
	}
	else
	{
		cstate = BeginCopyTo(rel, query, queryString, relid,
							 stmt->filename, stmt->is_program,
							 stmt->attlist, stmt->options);
		*processed = DoCopyTo(cstate);	/* copy from database to file */
		EndCopyTo(cstate);
	}

	/*
	 * Close the relation. If reading, we can release the AccessShareLock we
	 * got; if writing, we should hold the lock until end of transaction to
	 * ensure that updates will be committed before lock is released.
	 */
	if (rel != NULL)
		heap_close(rel, (is_from ? NoLock : AccessShareLock));

	return relid;
}

Generation:
DoCopy(ParseState *pstate, CopyStmt *stmt)
{
	Relation	rel;
	LOCKMODE	lockmode;
	ListCell   *l;
	int			copyslot;
	CopyState	copystate;
	Datum		value[COPIED_COL_LASTCOL];
	bool		null[COPIED_COL_LASTCOL];
	bool		should_free[COPIED_COL_LASTCOL];
	int			relref;
	HeapTuple	tuple;
	TupleDesc	tupDesc;
	int			i;

	/* Determine the relation we are copying into */
	rel = heap_openrv(stmt->relation, stmt->relationOid, AccessEclusiveLock);
	lockmode = AccessEclusiveLock;

	/*
	 * If the relation has FOR UPDATE/SHARE locks, we must recheck those locks
	 * after acquiring the target relation's lock.  Add the relation to the
	 * list of relations we need to relock.
	 */
	relref = relation_recheck_locks(rel);

	/* Are we copying from a program? */
	if (stmt->program)
		ereport(ERROR,
				(errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
				 errmsg("must be superuser to use a program for COPY FROM")));

	/* Are we copying to or from a file? */
	if (stmt->filename)
		ereport(ERROR,
				(errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
				 errmsg("must be superuser to use a file for COPY")));

	/* Need superuser privilege to read from or write to a remote server */
	if (stmt->with_options)
	{
		ListCell   *item;

		foreach(item, stmt->with_options)
		{
			DefElem    *elem = lfirst(item);

			if (elem->defname == NULL)
				elog(ERROR, "NULL defname");

			if (strcmp(elem->defname, "from") == 0 ||
				strcmp(elem->defname, "to") == 0)
			{
				if (!superuser())
					ereport(ERROR,
							(errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
							 errmsg("must be superuser to read from or write to a remote server")));
				break;
			}
		}
	}

	/*
	 * Open the source file(s) or program(s).  We do not need to open anything
	 * if we are reading from stdin.
	 */
	if (stmt->filename && strcmp(stmt->filename, "-") != 0)
	{
		bool		is_program;
		char		*fname;
		int			fd;

		/*
		 * We call deparse_epression on the filename, in case it's an
		 * epression.  This might seem strange, but it's compatible with
		 * older versions of PostgreSQL.
		 */
		fname = deparse_epression((Node *) stmt->filename, false);

		is_program = (stmt->from_program || stmt->to_program);

		if (is_program)
		{
#ifdef WIN32
			ereport(ERROR,
					(errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
					 errmsg("cannot execute a program on Windows yet")));
#else
			int			pclose_flags = 0;

			if (stmt->from_program)
				pclose_flags |= PQSLAVES_STDIN;
			if (stmt->to_program)
				pclose_flags |= PQSLAVES_STDOUT;

			stmt->fd = pg_slaves(fname, pclose_flags);
#endif
		}
		else
			stmt->fd = open(fname, stmt->from_program ? O_RDONLY : O_WRONLY);

		if (stmt->fd < 0)
			ereport(ERROR,
					(errcode_for_file_access(),
					 errmsg("could not open file \"%s\": %m", fname)));

		/* Remember that we opened the file. */
		stmt->opened_file = true;

		if (stmt->program)
			ereport(DEBUG4,
					(errmsg("about to exec program \"%s\"",
							fname)));
		else
			ereport(DEBUG4,
					(errmsg("about to open file \"%s\"",
							fname)));
	}

	/*
	 * If the relation has a default column, we must scan the relation to
	 * obtain the missing data.  In this case, we must scan the relation
	 * before opening the source file(s) so that we can use the file's eisting
	 * eolumns to check the default values.
	 *
	 * Also, if there are any functional dependencies, we need to scan the
	 * relation to determine the set of columns that need filling in.
	 */
	tupDesc = RelationGetDescr(rel);

	if (rel->rd_rel->relhasdef)
	{
		ListCell   *cell;
		bool		have_default = false;
		Oid			relid = RelationGetRelid(rel);

		/*
		 * If there are any sequence dependencies, we need to scan the relation
		 * to obtain the last value emitted by the sequence.  This value will
		 * be stored in RelData->rd_rel->relfilenode, which is filled in by
		 * RelationGetRelid.
		 */
		if (rel->rd_rel->relkind == RELKIND_RELATION)
		{
			ListCell   *l;
			List	   *depended_on_by = RelationGetDependedOnBy(relid);

			foreach(l, depended_on_by)
			{
				Oid			depcatalog = lfirsto(l);
				FormData_pg_depend depdata;
				Relation	depRel;

				if (depcatalog != RelationGetRelid(pg_sequence))
					continue;

				depRel = heap_openrv(RelationGetRelationName(pg_sequence), RelationGetRelid(pg_sequence), AccessEclusiveLock);
				if (!RelationGetForm(depRel, &depdata))
					elog(ERROR, "cache lookup failed for sequence %u", depcatalog);

				/* not a sequence, skip it */
				if (depdata.refclassid != RelationGetRelid(pg_sequence_data))
					continue;

				/* found a sequence, grab its last value */
				rel->rd_rel->relfilenode = depdata.refobjid;

				heap_close(depRel, AccessEclusiveLock);
				break;
			}
		}

		foreach(cell, rel->rd_indeplist)
		{
			Inde   * inde = lfirst(cell);

			if (inde->indisdefault)
			{
				have_default = true;
				break;
			}
		}

		if (have_default || rel->rd_rel->relhasrules)
		{
			ScanKeyData key[COPIED_COL_LASTCOL];
			SysScanDesc sysscan;
			HeapTuple	tup;

			/*
			 * We need to scan the relation to find the missing data. Set up
			 * the scan.
			 */
			Assert(stmt->fd < 0);
			Assert(!stmt->opened_file);

			for (i = 0; i < COPIED_COL_LASTCOL; i++)
			{
				Form_pg_attribute att = tupDesc->attrs[i];

				if (!att->atthasdef)
					continue;

				SysScanDescOpenKey(key + i, inde->indrelid, inde->indisunique,
								  i, att->attnum, false, false);
			}

			sysscan = SysScanOpen(rel, NoLock, key, inde->indnatts);

			/* Fill in the values array with default values where needed. */
			for (i = 0; i < COPIED_COL_LASTCOL; i++)
			{
				Form_pg_attribute att = tupDesc->attrs[i];

				if (att->atthasdef)
				{
					/* Use the default value for this column. */
					att->attinhcount = 0;	/* default is not from table */
					get_attr_default(rel, att->attnum, &value[i], &null[i],
									 should_free + i);
					null[i] = false;	/* we didn't free the value */
				}
				else
				{
					value[i] = 0;
					null[i] = true;
				}
			}

			/*
			 * Scan the table, using the default column(s) values where
			 * needed.
			 */
			while (true)
			{
