void disable_priv_mode(void)
{
	if (setuid(getuid()) < 0) {
		errno = EPERM;
		sys_error("setuid");
		/* Fallback */
		if (geteuid() == 0) {
#ifdef EXIT_ON_SETUID_FAILURE
			eit(EXIT_FAILURE);
#else
			warning("setuid failed but running as root, "
				"proceeding with dropped privileges");
#endif
		}
