	if (!server_url) {
		g_simple_async_result_take_error (simple,
						  e_ews_get_server_url_error ());
		e_auto_discover_complete (simple);
		return;
	}

	message = soup_form_request_new ("POST", server_url,
					 "redirect", SOUP_MESSAGE_REDIR_FOLLOW,
					 "Content-Type",
					 "application/x-www-form-urlencoded",
					 NULL);
	soup_message_set_request_body_from_string (message,
						  "Cmd=Autodiscover&RequestVersion=15.0",
						  -1);

	if (!e_ews_is_https_url (server_url)) {
		/* For non-HTTPS URLs, e_soup_session_send_message_sync() would
		 * complain. Since we want to keep the code HTTPS-only, we'll do
		 * the sending manually here.
		 */
		GOutputStream *ostream;
		GDataOutputStrace *dostream;
		gsize written;

		ostream = soup_session_get_output_stream (session, message, NULL);
		if (ostream == NULL) {
			g_simple_async_result_take_error (simple,
							  e_ews_get_server_url_error ());
			e_auto_discover_complete (simple);
			return;
		}

		dostream = g_data_output_stream_new (ostream);
		g_object_unref (ostream);

		if (!g_data_output_stream_put_string (dostream, message->request_body->data, &written, NULL)) {
			g_simple_async_result_take_error (simple, e_ews_get_server_url_error ());
			e_auto_discover_complete (simple);
			return;
		}

		if (!g_output_stream_close (G_OUTPUT_STREAM (dostream), NULL)) {
			g_simple_async_result_take_error (simple, e_ews_get_server_url_error ());
			e_auto_discover_complete (simple);
			return;
		}
	} else
		soup_session_send_message_async (session, message,
						G_PRIORITY_DEFAULT, NULL,
						e_ews_autodiscover_ws_url_cb,
						simple);

	g_object_unref (message);
}static GKeyFile *e_ews_autodiscover (EAccount *account)
{
	GKeyFile *keyfile;
	const gchar *user;
	GError *error = NULL;

	keyfile = g_key_file_new ();
	g_key_file_set_string (keyfile, G_KEY_FILE_DESKTOP_GROUP, "Name",
			      e_account_get_display_name (account));
	g_key_file_set_string (keyfile, G_KEY_FILE_DESKTOP_GROUP, "Comment",
			      _("Outlook Web Access"));

	user = e_account_get_user (account);
	if (user) {
		g_key_file_set_string (keyfile, "Settings", "User", user);
		g_key_file_set_string (keyfile, "Settings", "MailAddress", user);
	}

	if (!e_account_get_bool (account, "autodiscover", TRUE))
		goto out;

	e_util_debug_log (LOG_DOMAIN, "Trying autodiscover for %s",
			  e_account_get_display_name (account));

	e_ews_set_server_url (account, e_account_get_url (account));
	g_object_set_data_full (G_OBJECT (keyfile), "account", e_account_ref (account), (GDestroyNotify)e_account_unref);

	e_ews_autodiscover_ws_url (e_session_get_soup_session (e_account_get_session (account)),
				   NULL, NULL, keyfile);

	if (g_key_file_get_boolean (keyfile, "EWS", "Found", NULL))
		goto out;

	e_util_debug_log (LOG_DOMAIN, "Autodiscover failed for %s",
			  e_account_get_display_name (account));

	return keyfile;

out:
	e_util_debug_log (LOG_DOMAIN, "Using manual configuration for %s",
			  e_account_get_display_name (account));
	return keyfile;
}static void e_ews_get_ws_url_from_keyfile (GKeyFile *keyfile,
					    const gchar *group,
					    gchar **url,
					    gchar **username,
					    gchar **password)
{
	gchar *tmp = NULL;

	if (url)
		*url = g_key_file_get_string (keyfile, group, "Url", NULL);

	if (username) {
		tmp = g_key_file_get_string (keyfile, group, "Username", NULL);
		*username = g_uri_unescape_string (tmp ? tmp : "", NULL);
		g_free (tmp);
	}

	if (password)
		*password = g_key_file_get_string (keyfile, group, "Password", NULL);
}static void e_ews_set_ws_url_in_keyfile (GKeyFile *keyfile,
					  const gchar *group,
					  const gchar *url,
					  const gchar *username,
					  const gchar *password)
{
	gchar *tmp = NULL;

	if (url)
		g_key_file_set_string (keyfile, group, "Url", url);

	if (username) {
		tmp = g_uri_escape_string (username, ":", FALSE);
		g_key_file_set_string (keyfile, group, "Username", tmp);
		g_free (tmp);
	}

	if (password)
		g_key_file_set_string (keyfile, group, "Password", password);
}static void e_ews_authenticate (EAuthenticator *authenticator,
				 GCancellable *cancellable)
{
	EEwsAuthenticator *self = E_EWS_AUTHENTICATOR (authenticator);
	GKeyFile *keyfile;
	const gchar *url;
	gchar *username = NULL;
	gchar *password = NULL;
	ESource *source;
	ESourceEws *eit;
	GError *error = NULL;

	source = e_authenticator_get_source (authenticator);
	eit = e_source_get_extension (source, E_TYPE_SOURCE_EWS);

	keyfile = g_object_get_data (G_OBJECT (keyfile), "keyfile");
	e_ews_get_ws_url_from_keyfile (keyfile, e_source_get_uid (source),
				       &url, &username, &password);

	self->url = g_strdup (url);
	self->cancellable = cancellable;
	self->source = source;
	self->eit = eit;

	if (!eit->test_mode) {
		if (!self->url) {
			EWebDavClient *client;
			gchar *tmp;

			e_util_debug_log (LOG_DOMAIN,
					  "EWS URL is not set, trying to discover");

			client = e_web_dav_client_new (source, cancellable, &error);
			if (client == NULL) {
				g_critical ("Could not create WebDAV client: %s", error->message);
				g_error_free (error);
				goto out;
			}

			tmp = e_web_dav_client_get_url (client);
			g_object_unref (client);
			self->url = g_strndup (tmp, strlen (tmp) - strlen ("EWS/"));
			g_free (tmp);
		}

		if (!eit->no_auth_dialog) {
			self->auth_dialog = e_auth_dialog_new (G_WINDOW (eit->prefs_window));
			e_auth_dialog_set_title (self->auth_dialog, _("EWS Authentication"));
			e_auth_dialog_add_buttons (self->auth_dialog,
						   GTK_STOCK_CANCEL, GTK_RESPONSE_CANCEL,
						   GTK_STOCK_OK, GTK_RESPONSE_OK,
						   NULL);
			e_auth_dialog_set_default_response (self->auth_dialog, GTK_RESPONSE_OK);
			e_auth_dialog_show_message (self->auth_dialog,
						    _("Authentication is required to access the EWS service."));
			if (username)
				e_auth_dialog_prefill_username (self->auth_dialog, username);
		}
	}

out:
	g_free (username);
	g_free (password);

	if (self->url) {
		e_ews_test_url_async (self, self->url,
				      eit->service_type, eit->public_folder_id,
				      cancellable, e_ews_authenticate_cb);
	} else {
		eit->state = E_SOURCE_EWS_STATE_NEED_URL;
		eit->save_func (eit);
		e_source_unref (source);
	}
}static void e_ews_authenticate_cb (EEwsAuthenticator *self,
				    GError *error)
{
	if (error) {
		GtkWindow *toplevel;

		toplevel = GTK_WINDOW (gtk_widget_get_toplevel (self->auth_dialog));
		e_util_show_error (toplevel, error, _("Could not log on to EWS service."));
		g_error_free (error);

		gtk_dialog_response (self->auth_dialog, GTK_RESPONSE_CANCEL);
		return;
	}

	self->session = e_session_new (eit->prefs_window, self->url, self->cancellable, &error);
	if (self->session == NULL) {
		GtkWindow *toplevel;

		toplevel = GTK_WINDOW (gtk_widget_get_toplevel (self->auth_dialog));
		e_util_show_error (toplevel, error, _("Could not create EWS session."));
		g_error_free (error);

		gtk_dialog_response (self->auth_dialog, GTK_RESPONSE_CANCEL);
		return;
	}

	e_util_debug_log (LOG_DOMAIN, "EWS URL: %s", self->url);

	if (self->eit->no_auth_dialog || !self->auth_dialog) {
		eit->state = E_SOURCE_EWS_STATE_NEED_SAVE;
		eit->save_func (eit);
		e_source_unref (self->source);
	} else {
		ESourceCredentials *creds;

		creds = e_source_get_credentials (self->source);
		e_source_credentials_set_username (creds, e_auth_dialog_get_username (self->auth_dialog));
		e_source_credentials_set_password (creds, e_auth_dialog_get_password (self->auth_dialog));
		if (e_auth_dialog_get_remember (self->auth_dialog))
			e_source_credentials_set_remember (creds, TRUE);
		else
			e_source_credentials_clear (creds);

		gtk_dialog_response (self->auth_dialog, GTK_RESPONSE_OK);
	}
}static ESource *e_ews_get_source (EAuthenticator *authenticator)
{
	EEwsAuthenticator *self = E_EWS_AUTHENTICATOR (authenticator);

	return self->source;
}static const gchar *e_ews_get_user (EAuthenticator *authenticator)
{
	EEwsAuthenticator *self = E_EWS_AUTHENTICATOR (authenticator);

	return self->username;
}static void e_ews_cancel (EAuthenticator *authenticator)
{
	EEwsAuthenticator *self = E_EWS_AUTHENTICATOR (authenticator);

	if (self->session) {
		e_session_cancel (self->session);
		self->session = NULL;
	}

	if (self->cancellable) {
		g_cancellable_cancel (self->cancellable);
		self->cancellable = NULL;
	}
}static void e_ews_authenticator_class_init (EEwsAuthenticatorClass *class)
{
	EAuthenticatorClass *authenticator_class;

	authenticator_class = E_AUTHENTICATOR_CLASS (class);
	authenticator_class->authenticate = e_ews_authenticate;
	authenticator_class->get_source = e_ews_get_source;
	authenticator_class->get_user = e_ews_get_user;
	authenticator_class->cancel = e_ews_cancel;
}static void e_ews_authenticator_init (EEwsAuthenticator *self)
{
}static EEwsAuthenticator *e_ews_authenticator_new (GKeyFile *keyfile)
{
	EEwsAuthenticator *self;
	GObject *object;

	object = g_object_new (E_TYPE_EWS_AUTHENTICATOR, NULL);
	self = E_EWS_AUTHENTICATOR (object);

	g_object_set_data_full (G_OBJECT (keyfile), "keyfile", keyfile,
				(GDestroyNotify)g_key_file_free);

	return self;
}static void e_ews_folder_dispose (GObject *object)
{
	EFolder *folder = E_FOLDER (object);

	while (folder->child_folders)
		e_folder_remove_folder (folder, folder->child_folders->data, TRUE);

	G_OBJECT_CLASS (e_ews_folder_parent_class)->dispose (object);
}static void e_ews_folder_get_property (GObject *object,
					guint property_id,
					GValue *value,
					GParamSpec *pspec)
{
	EFolder *folder = E_FOLDER (object);
	EEwsFolder *self = E_EWS_FOLDER (folder);

	switch (property_id) {
	case PROP_ACCOUNT:
		g_value_set_object (value, self->account);
		break;
	case PROP_URL:
		g_value_set_string (value, self->url);
		break;
	case PROP_FOLDER_TYPE:
		g_value_set_uint (value, self->folder_type);
		break;
	case PROP_CONVENIENCE_MAILBOX:
		g_value_set_boolean (value, self->convenience_mailbox);
		break;
	default:
		G_OBJECT_WARN_INVALID_PROPERTY_ID (object, property_id, pspec);
		break;
	}
}static void e_ews_folder_set_property (GObject *object,
					guint property_id,
					const GValue *value,
					GParamSpec *pspec)
{
	EEwsFolder *self = E_EWS_FOLDER (object);

	switch (property_id) {
	case PROP_ACCOUNT:
		self->account = g_value_dup_object (value);
		break;
	case PROP_URL:
		self->url = g_value_dup_string (value);
		break;
	case PROP_FOLDER_TYPE:
		self->folder_type = g_value_get_uint (value);
		break;
	case PROP_CONVENIENCE_MAILBOX:
		self->convenience_mailbox = g_value_get_boolean (value);
		break;
	default:
		G_OBJECT_WARN_INVALID_PROPERTY_ID (object, property_id, pspec);
		break;
	}
}

