static void e_ews_folder_init (EEwsFolder *self)
{
	self->folder_type = E_FOLDER_TYPE_OTHER;
}/**
 * e_ews_folder_new:
 * @account: an #EAccount
 * @url: a WebDAV URL
 * @folder_type: a folder type constant
 * @convenience_mailbox: if the folder is a convenience mailbox
 *
 * Creates a new instance of an #EEwsFolder.
 *
 * Return value: a new #EEwsFolder
 **/
EEwsFolder *e_ews_folder_new (EAccount *account,
			      const gchar *url,
			      EFolderType folder_type,
			      gboolean convenience_mailbox)
{
	g_return_val_if_fail (E_IS_ACCOUNT (account), NULL);

	return E_EWS_FOLDER (g_object_new (E_TYPE_EWS_FOLDER,
					    "account", account,
					    "url", url,
					    "folder-type", folder_type,
					    "convenience-mailbox",
					    convenience_mailbox, NULL));
}static void e_ews_folder_bound (EEwsFolder *self,
				 const gchar *property,
				 const GValue *value,
				 gpointer user_data)
{
	if (g_str_equal (property, "store")) {
		EStore *store;

		store = E_STORE (g_value_get_object (value));
		self->eternity_folder =
			e_store_get_eternity_folder (store);
		self->drafts_folder =
			e_store_get_drafts_folder (store);
		self->templates_folder =
			e_store_get_templates_folder (store);
		self->stationery_folder =
			e_store_get_stationery_folder (store);
	}
}static void e_ews_folder_create_folder (EFolder *folder,
					EFolder *child_folder,
					GCancellable *cancellable,
					GAsyncReadyCallback callback,
					gpointer user_data)
{
	EEwsFolder *self = E_EWS_FOLDER (folder);

	if (self->account->offline || !self->session) {
		GError *error = NULL;

		e_folder_child_not_supported (folder, child_folder);
		g_simple_async_result_new_error (G_OBJECT (self),
						  callback, user_data,
						  G_IO_ERROR,
						  G_IO_ERROR_NOT_SUPPORTED,
						  _("EWS account is offline "
						    "or server is not reachable"));
		return;
	}

	e_ews_create_folder (self->session, self->url,
			     e_folder_get_display_name (child_folder),
			     e_folder_get_uid (child_folder),
			     cancellable, callback, user_data);
}static void e_ews_folder_delete_folder (EFolder *folder,
					EFolder *child_folder,
					GCancellable *cancellable,
					GAsyncReadyCallback callback,
					gpointer user_data)
{
	EEwsFolder *self = E_EWS_FOLDER (folder);

	if (self->account->offline || !self->session) {
		GError *error = NULL;

		e_folder_child_not_supported (folder, child_folder);
		g_simple_async_result_new_error (G_OBJECT (self),
						  callback, user_data,
						  G_IO_ERROR,
						  G_IO_ERROR_NOT_SUPPORTED,
						  _("EWS account is offline "
						    "or server is not reachable"));
		return;
	}

	e_ews_delete_folder (self->session, self->url,
			     e_folder_get_uid (child_folder),
			     cancellable, callback, user_data);
}static void e_ews_folder_rename_folder (EFolder *folder,
					EFolder *child_folder,
					const gchar *new_name,
					GCancellable *cancellable,
					GAsyncReadyCallback callback,
					gpointer user_data)
{
	EEwsFolder *self = E_EWS_FOLDER (folder);

	if (self->account->offline || !self->session) {
		GError *error = NULL;

		e_folder_child_not_supported (folder, child_folder);
		g_simple_async_result_new_error (G_OBJECT (self),
						  callback, user_data,
						  G_IO_ERROR,
						  G_IO_ERROR_NOT_SUPPORTED,
						  _("EWS account is offline "
						    "or server is not reachable"));
