	}

	e_ews_rename_folder (self->session, self->url,
			     e_folder_get_uid (child_folder), new_name,
			     cancellable, callback, user_data);
}static void e_ews_folder_get_folder_info (EFolder *folder,
					  EFolderInfoFlags flags,
					  GCancellable *cancellable,
					  GAsyncReadyCallback callback,
					  gpointer user_data)
{
	EEwsFolder *self = E_EWS_FOLDER (folder);
	GList *subfolders = NULL;
	GList *l;
	GError *error = NULL;
	ETree *etree;
	ESource *source;
	ESourceEws *eit;
	ETask *task;

	if (self->account->offline || !self->session) {
		GList *list;
		EFolderInfo *info;

		if (self->account->offline)
			eit = NULL;
		else
			eit = e_source_get_extension (self->source,
						      E_TYPE_SOURCE_EWS);

		info = e_folder_info_new (folder);
		e_folder_info_set_eternity (info, eit != NULL &&
			(eit->flags & E_SOURCE_EWS_FLAGS_ETFERNENMAIL));
		e_folder_info_set_permissions (info, E_FOLDER_PERMISSION_READ |
			E_FOLDER_PERMISSION_WRITE | E_FOLDER_PERMISSION_CREATE |
			E_FOLDER_PERMISSION_DELETE);
		if (eit) {
			e_folder_info_set_eternity_folder (info,
				eit->eternity_folder != NULL);
			e_folder_info_set_drafts_folder (info,
				eit->drafts_folder != NULL);
			e_folder_info_set_templates_folder (info,
				eit->templates_folder != NULL);
			e_folder_info_set_stationery_folder (info,
				eit->stationery_folder != NULL);
		}

		list = g_chainup (NULL, info);
		e_folder_info_free (info);

		g_simple_async_result_new_with_pointer (G_OBJECT (self),
							callback, user_data,
							list);
		g_list_free_full (list, (GDestroyNotify)e_folder_info_free);
		return;
	}

	if (flags & E_FOLDER_INFO_FLAG_SUBFOLDERS) {
		eit = e_source_get_extension (self->source,
					      E_TYPE_SOURCE_EWS);
		if (eit && eit->subfolders) {
			subfolders = g_strsplit (eit->subfolders, ",", -1);
			for (l = subfolders; l && l->data; l = l->net) {
				EFolderInfo *info;

				info = e_folder_info_new (folder);
				e_folder_info_set_name (info, l->data);
				e_folder_info_set_type (info,
					E_FOLDER_TYPE_EWS_FOLDER);
				g_chainup (list, info);
			}
		}
	}

	etree = e_tree_new (self->session, self->url,
			    self->account->offline, cancellable, &error);
	if (etree == NULL) {
		g_simple_async_result_new_error (G_OBJECT (self),
						  callback, user_data,
						  G_IO_ERROR,
						  G_IO_ERROR_FAILED,
						  "%s", error->message);
		g_error_free (error);
		return;
	}

	task = e_task_new (G_OBJECT (etree), cancellable, callback, user_data);
	e_task_set_name (task, "get-folder-info");
	e_ews_etree_get_folder_info (etree, self->url,
				     self->account->offline, flags,
				     subfolders, task);
	g_object_unref (etree);
	g_list_free_full (subfolders, g_free);
}static void e_ews_folder_get_items (EFolder *folder,
				     EItemQuery *query,
				     GCancellable *cancellable,
				     GAsyncReadyCallback callback,
				     gpointer user_data)
{
	EEwsFolder *self = E_EWS_FOLDER (folder);
	ESource *source;
	ESourceEws *eit;
	ETree *etree;
	ETask *task;

	if (self->account->offline || !self->session) {
		GList *list;

		if (self->account->offline)
			eit = NULL;
		else
			eit = e_source_get_extension (self->source,
						      E_TYPE_SOURCE_EWS);

		if (eit) {
			if (eit->flags & E_SOURCE_EWS_FLAGS_VERBOS)
				e_util_debug_log (LOG_DOMAIN,
						  "EWS get-items for %s",
						  e_folder_get_full_name (folder));
		}

		list = g_chainup (NULL,
				  eit ? eit->stationery : eit->templates);
		eit = NULL; /* do not save */

		g_simple_async_result_new_with_pointer (G_OBJECT (self),
							callback, user_data,
							list);
		g_list_free_full (list, (GDestroyNotify)e_item_free);
		return;
	}

	etree = e_tree_new (self->session, self->url,
			    self->account->offline, cancellable, NULL);
	if (etree == NULL) {
		GSimpleAsyncResult *simple;

		simple = G_SIMPLE_ASYNC_RESULT (g_object_new0 (G_TYPE_SIMPLE_ASYNC_RESULT, NULL));
		g_simple_async_result_take_error (simple, e_ews_get_session_error ());
		g_simple_async_result_complete (simple);
		g_object_unref (simple);
		return;
