static int oidc_handle_logout(request_rec *r, oidc_cfg *c,
		oidc_session_t *session) {

	const char *logout_url = oidc_session_get_logout_url(r, session);
	if (logout_url == NULL || strlen(logout_url) == 0) {
		return oidc_util_html_send_error(r, c->error_template,
				"Logout Error",
				"The logout URL is not configured. "
						"You must set the <code>OIDCLogoutURL</code> directive to a valid URL.",
				HTTP_INTERNAL_SERVER_ERROR);
	}

	apr_uri_t uri;
	if (apr_uri_parse(r->pool, logout_url, &uri) != APR_SUCCESS) {
		return oidc_util_html_send_error(r, c->error_template,
				"Logout Error",
				apr_psprintf(r->pool,
						"The logout URL '%s' is not valid.",
						logout_url),
				HTTP_INTERNAL_SERVER_ERROR);
	}

	const char *hostname = oidc_session_get_hostname(r, session);
	if (hostname == NULL || strlen(hostname) == 0) {
		return oidc_util_html_send_error(r, c->error_template,
				"Logout Error",
				"The hostname of the IdP is not known. "
						"You must set the <code>OIDCRemoteHost</code> directive.",
				HTTP_INTERNAL_SERVER_ERROR);
	}

	if (uri.hostname != NULL && strlen(uri.hostname) != 0
			&& strcmp(hostname, uri.hostname) != 0) {
		return oidc_util_html_send_error(r, c->error_template,
				"Logout Error",
				apr_psprintf(r->pool,
						"The logout URL '%s' does not match the hostname '%s' of the IdP. "
								"You must set the <code>OIDCRemoteHost</code> directive correctly.",
						logout_url, hostname),
				HTTP_INTERNAL_SERVER_ERROR);
	}

	char *logout_request_url = apr_pstrdup(r->pool, logout_url);
	const char *redir = oidc_session_get_authorization_redirect(r, session);
	if (redir != NULL && strlen(redir) != 0) {
		logout_request_url = apr_psprintf(r->pool, "%s?%s",
				logout_request_url, redir);
	}

	const char *id_token_hint = oidc_session_get_idtoken(r, session);
	if (id_token_hint != NULL && strlen(id_token_hint) != 0) {
		if (strchr(logout_request_url, '?') == NULL)
			logout_request_url = apr_psprintf(r->pool, "%s?id_token_hint=%s",
					logout_request_url,
					oidc_util_escape_string(r, id_token_hint));
		else
			logout_request_url = apr_psprintf(r->pool, "%s&id_token_hint=%s",
					logout_request_url,
					oidc_util_escape_string(r, id_token_hint));
	}

	oidc_debug(r, "logout request URL: %s", logout_request_url);

	return oidc_util_html_send_redirect(r, logout_request_url);
}

