static CamelCipher *
empe_app_smime_get_cipher (EMailPart *part, const gchar *ct)
{
	EMail *mail;
	EMailAccount *account;
	CamelSession *session;
	const gchar *keyword, *s;
	CamelCipher *cipher = NULL;
	CamelCipherInfo *info;
	GError *err = NULL;

	mail = e_mail_part_get_mail (part);
	account = e_mail_get_account (mail);
	session = e_mail_account_get_session (account);

	info = camel_cipher_info_get ();
	for (keyword = ct; keyword; keyword = s) {
		s = camel_cipher_info_get_next_keyword (info, keyword);
		if (!s)
			break;
		if (strncmp (s, "smime-", 6))
			continue;
		cipher = camel_cipher_new (session, s + 6, &err);
		if (err) {
			g_critical ("Couldn't create cipher: %s", err->message);
			g_error_free (err);
			break;
		}
		if (!camel_cipher_is_usable (cipher)) {
			g_object_unref (cipher);
			cipher = NULL;
			continue;
		}
		break;
	}
	camel_cipher_info_free (info);

	return cipher;
}static void empe_app_smime_part_decrypt (EMailPart *part)
{
	EMailPart *parent;
	EMail *mail;
	EMailAccount *account;
	CamelSession *session;
	CamelFolder *folder;
	CamelStore *store;
	const gchar *ct;
	CamelCipher *cipher;
	GOutputStream *outstream;
	GError *err = NULL;
	gint id;

	parent = e_mail_part_get_parent (part);
	if (!parent)
		return;

	mail = e_mail_part_get_mail (part);
	account = e_mail_get_account (mail);
	session = e_mail_account_get_session (account);

	folder = e_mail_get_folder (mail);
	store = camel_folder_get_store (folder);

	if (!E_IS_MESSAGE_RECEIVE_FOLDER (E_FOLDER (folder)))
		return;

	id = e_mail_part_get_part_id (parent);
	if (id < 0)
		return;

	ct = e_mail_part_get_content_type (part);
	if (!ct || strstr (ct, "multipart/signed") || strstr (ct, "multipart/encrypted"))
		return;

	cipher = empe_app_smime_get_cipher (part, ct);
	if (!cipher)
		return;

	outstream = e_mail_part_get_decompress_stream (parent);
	if (outstream) {
		GInputStream *instream;

		instream = e_mail_part_get_decrypt_stream (part, cipher, &err);
		if (err) {
			g_critical ("Couldn't create decrypt stream: %s", err->message);
			g_error_free (err);
			g_object_unref (cipher);
			return;
		}

		g_output_stream_splice (outstream, instream,
			G_OUTPUT_STREAM_SPLICE_CLOSE_SOURCE |
			G_OUTPUT_STREAM_SPLICE_CLOSE_TARGET, NULL);
		g_object_unref (instream);
	}

	e_mail_part_update_validity (part, FALSE);
	e_mail_part_set_decrypted (part, TRUE);

	g_object_unref (cipher);
