	folderinfo = e_mail_folder_get_server_folder (E_MAIL_FOLDER (folder));

	mail = e_mail_new ();
	e_mail_set_account (mail, account);
	e_mail_set_folder (mail, folder);
	e_mail_set_message (mail, message);

	part = e_mail_get_message_part (mail);
	e_mail_part_set_content_type (part, ct);
	e_mail_part_set_stream (part, in, -1, TRUE);

	if (source)
		g_object_unref (source);

	if (folderinfo) {
		ETree *et;
		gchar *subject = NULL;
		const gchar *tmp;

		if (message->subject)
			subject = g_strstrip (g_strdup (message->subject));
		tmp = e_mail_folder_info_get_et (folderinfo);
		if (tmp && subject) {
			et = e_tree_new (tmp);
			e_tree_set_variable (et, "subject", subject);
			g_free (subject);
			e_mail_part_set_et (part, et);
			e_tree_free (et);
		}
	}

	epe_app_smime_message_parse (mail);

	if (message->flags & E_MAIL_FLAGS_RECEIVED) {
		GDate *date;

		date = camel_mime_message_get_date (mm);
		if (date) {
			GDateTime *gdate;

			gdate = g_date_time_new_from_timeval_local (g_date_get_time_t (date));
			e_mail_message_set_date (message, gdate);
			g_date_time_unref (gdate);
			g_date_free (date);
		}
	}

	e_mail_message_set_size (message, message->total_size);

	if (message->flags & E_MAIL_FLAGS_NEW)
		e_mail_folder_add_message (mailfolder, message);

	e_mail_free (mail);

	g_free (ct);
}static void empe_app_smime_folder_get_message (CamelFolder *folder,
