	gchar *ct = NULL;

	if (message->content_type)
		ct = g_strdup (message->content_type);
	else
		ct = g_strdup ("application/octet-stream");

	account = e_mail_folder_get_account (E_MAIL_FOLDER (folder));
	mailsession = e_mail_account_get_session (account);
	mailfolder = e_mail_session_get_mail_folder (mailsession);

	mail = e_mail_new ();
	e_mail_set_account (mail, account);
	e_mail_set_folder (mail, folder);
	e_mail_set_message (mail, message);

	part = e_mail_get_message_part (mail);
	e_mail_part_set_content_type (part, ct);

	if (message->flags & E_MAIL_FLAGS_RECEIVED) {
		GDate *date;

