		CAMEL_FOLDER_SUMMARY_ANNOTATIONS;
}static void empe_app_smime_folder_search (CamelFolder *folder,
                                          const gchar *search,
                                          CamelFolderSearchFlags flags,
                                          GCancellable *cancellable,
                                          GAsyncReadyCallback callback,
                                          gpointer user_data)
{
	EMailAccount *account;
	EMailSession *mailsession;
	EMailFolder *mailfolder;
	GList *list, *l;
	GError *err = NULL;
	ETree *et;
	const gchar *tmp;

	account = e_mail_folder_get_account (E_MAIL_FOLDER (folder));
	mailsession = e_mail_account_get_session (account);
	mailfolder = e_mail_session_get_mail_folder (mailsession);

	if (flags & CAMEL_FOLDER_SEARCH_GLOBBING)
		search = e_util_glob_to_regex (search);
	if (flags & CAMEL_FOLDER_SEARCH_REGEX) {
		tmp = e_util_make_search_et (search);
		et = e_tree_new (tmp);
		g_free (tmp);
	} else {
		et = e_tree_new_word_list (search);
	}
	list = e_mail_folder_search (mailfolder, et, flags, cancellable);
	e_tree_free (et);

	if (list) {
		GList *results = NULL;
		for (l = list; l; l = g_list_net (l)) {
			CamelMessageInfo *message = l->data;
			EMailPart *part;
			ETree *et;
			gchar *subject = NULL;
			const gchar *tmp2;

			if (!(message->flags & E_MAIL_FLAGS_RECEIVED))
				continue;

			if (flags & CAMEL_FOLDER_SEARCH_FULL_TEXT) {
				et = e_mail_folder_get_full_text_et (mailfolder, message);
				if (et) {
					tmp2 = e_mail_part_get_et (part);
					if (tmp2)
						et = e_tree_parse (et, tmp2);
				}
			}

			tmp2 = e_mail_folder_get_summary_et (mailfolder, message);
			if (tmp2) {
				et = e_tree_new (tmp2);
				if (et) {
					if (flags & CAMEL_FOLDER_SEARCH_FULL_TEXT) {
						et = e_tree_parse (et, et);
					}
					results = g_list_prepend (results, et);
				}
			}
		}
		if (results) {
			GObject *source;

			source = g_object_ref (folder);
			g_object_set_data_full (G_OBJECT (source), "search-results", results, (GDestroyNotify) e_tree_list_free);
			g_object_set_data (G_OBJECT (source), "search-error", NULL);
			e_util_dispatch (callback, G_OBJECT (source), user_data, error);
		}
		g_object_unref (source);
	} else {
		GObject *source;

		source = g_object_ref (folder);
		g_object_set_data (G_OBJECT (source), "search-error", g_error_copy (err));
		e_util_dispatch (callback, G_OBJECT (source), user_data, error);
		g_object_unref (source);
		g_error_free (err);
	}
}static GObject *empe_app_smime_folder_search_finish (CamelFolder *folder,
                                                     GAsyncResult *result,
                                                     GError **error)
{
	GObject *source;
	GList *list;

	source = g_async_result_get_source_object (result);
	if (g_async_result_legacy_propagate_error (result, error))
		return NULL;

	list = g_object_get_data (source, "search-results");
	if (list) {
		ETree *et;
		GList *l;

		et = g_object_get_data (source, "search-et");
		if (!et)
			et = e_tree_new ("true");

		for (l = list; l; l = g_list_net (l)) {
			ETree *et2 = l->data;
			et2 = e_tree_parse (et2, et);
			if (et2 && et2->type == E_TREE_AND)
				et = et2;
			else
				g_object_unref (et2);
		}

		return G_OBJECT (et);
	}

	if (error)
		g_propagate_error (error, g_object_get_data (source, "search-error"));

	return NULL;
