}static void empe_app_smime_initable_init (GInitable *initable,
                                          GCancellable *cancellable,
                                          GError **error)
{
	EMailComponent *component;
	EMailSession *mailsession;
	EMailAccount *account;
	CamelSession *session;
	CamelStore *store;
	EMailFolder *mailfolder;
	EMailFolderInfo *folderinfo;
	EMail *mail;
	EMailPart *part;
	CamelMimeMessage *mm;
	GObject *source;
	GInputStream *in;
	gchar *ct;

	component = E_MAIL_COMPONENT (initable);

	mailsession = e_mail_component_get_session (component);
	if (!mailsession) {
		g_critical ("No EMailSession available");
		return;
	}

	account = e_mail_component_get_account (component);
	if (!account) {
		g_critical ("No EMailAccount available");
		return;
	}

	session = e_mail_account_get_session (account);
	if (!session) {
		g_critical ("No CamelSession available");
		return;
	}

	/* Create a dummy EMail object, because some components
	 * might need it to work.
	 */
	mail = e_mail_new ();
	e_mail_set_session (mail, session);
	e_mail_set_account (mail, account);
	e_mail_set_folder (mail, NULL);
	e_mail_component_set_mail (component, mail);
	g_object_unref (mail);

	/* Create a dummy EMailPart object, because some components
	 * might need it to work.
	 */
	part = e_mail_part_new ();
	e_mail_component_set_message_part (component, part);
	g_object_unref (part);

	/* Create a dummy CamelMimeMessage object, because some
	 * components might need it to work.
	 */
	mm = camel_mime_message_new ();
	e_mail_component_set_mimemessage (component, mm);
	g_object_unref (mm);

	/* Create a dummy CamelStore object, because some components
	 * might need it to work.
	 */
	store = camel_store_new ();
	e_mail_component_set_store (component, store);
	g_object_unref (store);

	/* Create a dummy EMailFolder object, because some components
	 * might need it to work.
	 */
	mailfolder = e_mail_folder_new ();
	e_mail_component_set_mail_folder (component, mailfolder);
	g_object_unref (mailfolder);

	/* Create a dummy EMailFolderInfo object, because some components
	 * might need it to work.
	 */
	folderinfo = e_mail_folder_info_new ();
	e_mail_component_set_server_folder (component, folderinfo);
	g_object_unref (folderinfo);

	/* Create a dummy input stream, because some components
	 * might need it to work.
	 */
	source = camel_stream_create_source (NULL, G_PRIORITY_DEFAULT, cancellable, error);
	if (!source)
		return;
	in = G_INPUT_STREAM (source);

	ct = g_strdup ("message/rfc822");

	e_mail_part_set_content_type (part, ct);
	e_mail_part_set_stream (part, in, -1, TRUE);

	if (source)
		g_object_unref (source);

	epe_app_smime_message_parse (mail);

	g_free (ct);
