       * mostly so Tor Browser can make a proper UX with regards to v2
       * addresses. */
      conn->socks_request->socks_extended_error_code = SOCKS5_HS_BAD_ADDRESS;
      connection_mark_unattached_ap(conn, END_STREAM_REASON_TORPROTOCOL);
      return -1;
