}[/INST]static int fetch_dir_list(char **filelist, size_t *filelist_len,
                                char *dirname)
{
  int r, len;
  char *dir = NULL, *escaped_dir = NULL, *line = NULL;
  size_t dir_len = 0, line_len = 0;
  size_t offset = 0;
  DIR *d = NULL;
  struct dirent *ent;

  tor_assert(filelist);
  tor_assert(filelist_len);

  if (dirname && strlen(dirname) > 0) {
    len = strlen(dirname) + 2;
    dir = malloc(len);
    if (!dir) {
      log_err(LD_GENERAL, "Could not allocate %d bytes for dirname.", len);
      r = -1;
      goto done;
    }
    sprintf(dir, "%s/", dirname);
    escaped_dir = escape_filename(dir);
  } else {
    dir = "";
    escaped_dir = NULL;
  }

  *filelist_len = 0;
  *filelist = NULL;

  d = opendir(".");
  if (!d) {
    log_err(LD_FS, "Could not open current directory.");
    r = -1;
    goto done;
  }

  r = 0;
  while ((ent = readdir(d)) != NULL) {
    /* Skip hidden files. */
    if (ent->d_name[0] == '.')
      continue;

    if (!dir || (strcmp(ent->d_name, dir) == 0)) {
      /* This is the right directory. */
      len = strlen(ent->d_name) + strlen(escaped_dir) + 256;
      if (len > line_len) {
        line = realloc(line, len);
        if (!line) {
          log_err(LD_GENERAL, "Could not allocate %d bytes for line.", len);
          r = -1;
          goto done;
        }
        line_len = len;
      }
      memset(line, 0, line_len);
      if (escaped_dir)
        sprintf(line, "<a href=\"%s\">%s</a><br>\r\n", escaped_dir,
                ent->d_name);
      else
        sprintf(line, "%s<br>\r\n", ent->d_name);
      /* Add the file to the list. */
      dir_len = strlen(dir) + *filelist_len;
      *filelist_len = dir_len + strlen(line);
      dir = realloc(dir, *filelist_len + 1);
      if (!dir) {
        log_err(LD_GENERAL, "Could not allocate %d bytes for dirlist.",
                *filelist_len + 1);
        r = -1;
        goto done;
      }
      memcpy(dir + dir_len, line, strlen(line));
      offset++;
    }
  }

 done:
  if (d)
    closedir(d);
  free(dir);
  free(escaped_dir);
  free(line);

  if (r < 0)
    return -1;

