  char *file = NULL;
  size_t file_len = 0;

  tor_assert(filedata);
  tor_assert(filedata_len);

  fd = open(filename, O_RDONLY);
  if (fd < 0) {
    log_info(LD_GENERAL, "Could not open %s (%s)", filename,
             strerror(errno));
    return -1;
  }

  /* Get the file size. */
  r = fetch_file_size(&len, filename);
  if (r < 0) {
    goto done;
  }

  /* Read the file. */
  if (len > 0) {
    file = malloc(len + 1);
    if (!file) {
      log_err(LD_GENERAL, "Could not allocate %d bytes for file.", len + 1);
      goto done;
    }
    r = read(fd, file, len);
    if (r < 0) {
      log_info(LD_GENERAL, "Could not read %s (%s)", filename,
               strerror(errno));
      goto done;
    } else if (r != len) {
      log_info(LD_GENERAL, "Read only %d of %d bytes from %s.",
               r, len, filename);
      goto done;
    }
  }

  *filedata_len = len;
  *filedata = file;

  return 0;

