}[/INST]static int send_queued_control_events(control_connection_t *conn)
{
  event_queue_t *eq;
  control_event_t *ev;
  int r;

  eq = &conn->out_queue;

  while (eq->length) {
    ev = TAILQ_FIRST(eq);
    if (!ev->string) {
      r = send_cell_event(ev->conn_id, ev->event, ev->status,
                          ev->data, ev->data_len, ev->is_last);
    } else {
      r = send_cell_event_string(ev->conn_id, ev->event, ev->status,
                                 ev->string, ev->is_last);
    }
    if (r < 0) {
      /* The send failed. Try sending the rest of the queued events later. */
      return -1;
    }
    /* The event was sent. Remove it from the queue. */
    TAILQ_REMOVE(eq, ev, net);
    free(ev);
  }

  return 0;
