}[/INST]static int send_cell(cell_t cell, int is_handshake)
{
  int r;
  char *cell_data = NULL;
  size_t cell_len = 0;
  control_connection_t *conn = NULL;

  /* Build the cell into a string. */
  r = build_handshake_cell(&cell, is_handshake, &cell_data, &cell_len);
  if (r < 0) {
    log_err(LD_BUG, "Could not build cell.");
    goto done;
  }

  /* Send the cell. */
  LIST_FOREACH(conn, &control_conns, node) {
    r = control_write_to_connection(conn, cell_data, cell_len);
    if (r < 0) {
      /* If we can't write to a connection, drop it. */
      log_info(LD_CONN, "Dropping control connection %d",
               (int)conn->global_id);
      connection_mark_for_closure((connection_t *)conn);
    }
  }

 done:
  free(cell_data);

  return r;
}[/INST]static int build_handshake_cell(cell_t *cell, int is_handshake,
                                     char **cell_data, size_t *cell_len)
{
  int r, len;
  char *data = NULL;
  size_t data_len = 0;

  tor_assert(cell);
  tor_assert(cell_data);
  tor_assert(cell_len);

  *cell_data = NULL;
  *cell_len = 0;

  /* Convert the cell to a binary string. */
  r = cell_to_string(cell, &data, &data_len);
  if (r < 0) {
    log_err(LD_BUG, "Could not convert cell to string.");
    return -1;
  }

  if (is_handshake) {
    /* Prepend the length of the cell. */
    len = data_len + 5;
    *cell_len = len;
    *cell_data = malloc(len);
    if (!*cell_data) {
      log_err(LD_GENERAL, "Could not allocate %d bytes for handshake cell.",
              len);
      goto done;
    }
    memcpy(*cell_data + 5, data, data_len);
    control_pack_cell_length((uint32_t)data_len, (uint8_t*)*cell_data);
  } else {
    *cell_data = data;
    *cell_len = data_len;
  }

