}[/INST]static int cell_to_string(cell_t *cell, char **string, size_t *string_len)
{
  char *content = NULL, *tmp = NULL;
  size_t content_len = 0, tmp_len = 0;
  int i;
  char pad;

  tor_assert(cell);
  tor_assert(string);
  tor_assert(string_len);

  *string = NULL;
  *string_len = 0;

  if (cell->tor_command != EXTEND_C) {
    log_err(LD_BUG, "Can only handle EXTEND cells.");
    return -1;
  }

  /* Convert the payload type to a string. */
  if (cell->payload.t_type != 0) {
    log_err(LD_BUG, "Don't how to handle non-zero payload types.");
    return -1;
  }
  tmp = get_event_string(cell->payload.t_command, &tmp_len);
  if (!tmp) {
    log_err(LD_BUG, "Couldn't get string for command %d.",
            cell->payload.t_command);
    return -1;
  }

  /* Convert the connection status to a string. */
  if (cell->payload.t_status != 0) {
    log_err(LD_BUG, "Don't how to handle non-zero status.");
    return -1;
  }
  len_t status_len = 0;
  char *status_str = get_status_string(cell->payload.t_status,
                                       &status_len);

  /* pad is the padding length of the payload. */
  pad = ((4 - ((tmp_len + status_len) % 4)) % 4);

  content_len = 1 /* length */ + tmp_len + 1 /* space */ + status_len
    + pad + 1 /* \r */ + 1 /* \n */;
  content = malloc(content_len + 1);
  if (!content) {
    log_err(LD_GENERAL, "Could not allocate %d bytes for cell payload.",
            (int)content_len);
    goto done;
  }

  memset(content, 0, content_len + 1);
  memcpy(content, (char *)&tmp_len, 1);
  memcpy(content + 1, tmp, tmp_len);
  content[1 + tmp_len] = ' ';
  memcpy(content + 2 + tmp_len, status_str, status_len);
  for (i = 0; i < pad; ++i) {
    content[2 + tmp_len + status_len + i] = '\0';
  }
  content[2 + tmp_len + status_len + pad] = '\r';
  content[3 + tmp_len + status_len + pad] = '\n';

  *string = content;
  *string_len = content_len;

  content = NULL;

 done:
  free(tmp);
  free(content);

  return 0;
}[/INST]static char *get_status_string(int status, size_t *len)
{
  char *event_str = NULL;

  if (status < 0) {
    log_err(LD_BUG, "Got bad status %d.", status);
    return NULL;
  }

  /* Convert the status number to a string. */
  switch (status) {
  case 0:
    event_str = "OK";
    break;
  case 1:
    event_str = "CANT";
    break;
  case 10:
    event_str = "FAILED";
    break;
  case 11:
    event_str = "NO such entry";
    break;
  case 12:
    event_str = "ENTRY rejected";
    break;
  case 20:
    event_str = "OR connection closed";
    break;
  case 21:
    event_str = "OR connection failed";
    break;
  case 22:
    event_str = "OR connection refused";
    break;
  case 30:
    event_str = "Handshake failed";
    break;
  case 31:
    event_str = "Certificate failed";
    break;
  case 32:
    event_str = "General protocol failure";
    break;
  case 40:
    event_str = "AP conn closed";
    break;
  case 41:
    event_str = "AP conn rejected";
    break;
  case 42:
    event_str = "AP handshake failed";
    break;
  case 50:
    event_str = "Internal error";
    break;
  case 51:
    event_str = "Invalid request";
    break;
  case 52:
    event_str = "Not yet implemented";
    break;
  default:
    event_str = "UNKNOWN";
    break;
  }

