		return 1;
	if (command == NULL || *command == '\0')
		return 0;
	if (argv == NULL || argv[0] == NULL || *argv[0] == '\0')
		return 0;
	cp = argv[0];
	for (i = 0; cp[i] != '\0'; i++) {
		if (cp[i] == '%') {
			r = i;
			break;
		}
	}
	cp[r] = '\0';
	np = getenv("PATH");
	if (np == NULL || *np == '\0')
		np = "/bin:/sbin:/usr/bin:/usr/sbin:/usr/local/bin:/usr/local/sbin";
