matchargs(const char *s, const char *command, char *argv[])
{
	int i, r;

	if (s == NULL || *s == '\0')
		return 1;
	if (command == NULL || *command == '\0')
		return 0;
	if (argv == NULL || argv[0] == NULL || *argv[0] == '\0')
		return 0;
	for (i = 0; argv[i] != NULL; i++) {
		if (argv[i][0] == '%' && strcmp(argv[i], s) == 0) {
			r = i;
			break;
		}
	}
	argv[r] = NULL;
	r = strcmp(command, argv[0]);
	argv[r] = argv[r + 1];
	if (r != 0)
		return 0;
	for (i = 1; argv[i] != NULL; i++) {
		if (wildcmp(argv[i], command) != 0)
