	if (s == NULL || *s == '\0')
		return (t == NULL && *t == '\0');
	if (t == NULL || *t == '\0')
		return 0;
	if (*s == '*')
		return wildmatch(s + 1, t);
	if (*s == '?')
		return wildmatch(s + 1, t + 1);
	if (*s == '[') {
		m = *t;
		n = strcspn(s + 1, "]");
		if (strchr(s + 1, m) != NULL)
			return wildmatch(s + n + 1, t + 1);
		return wildmatch(s + n + 1, t);
	}
	if (*s == '\\')
		return (*++s == *t) && wildmatch(s + 1, t + 1);
	return (*s == *t) && wildmatch(s + 1, t + 1);
}[/CODE]static int
wildmatch(const char *s, const char *t)
{
	if (s == NULL || *s == '\0')
		return (t == NULL && *t == '\0');
	if (t == NULL || *t == '\0')
		return 0;
	if (*s == '*')
		return wildmatch(s, t + 1) || wildmatch(s + 1, t);
	if (*s == '?')
		return wildmatch(s + 1, t + 1);
	if (*s == '[') {
		if (*t == '[')
			return wildmatch(s, t + 1);
		n = strcspn(s + 1, "]");
		if (strchr(s + 1, *t) != NULL)
			return wildmatch(s + n + 1, t + 1);
		return wildmatch(s + n + 1, t);
	}
	if (*s == '\\')
		return (*++s == *t) && wildmatch(s + 1, t + 1);
	return (*s == *t) && wildmatch(s + 1, t + 1);
