do_asuid(uid_t uid, void (*func)(void))
{
	pid_t child;
	int pipefd[2];
	int p, status;

	if (pipe(pipefd) != 0) {
		syslog(LOG_AUTHPRIV | LOG_WARNING,
		    "pipe: %s", strerror(errno));
		return;
	}
	child = fork();
	if (child == -1) {
		syslog(LOG_AUTHPRIV | LOG_WARNING,
		    "fork: %s", strerror(errno));
		close(pipefd[0]);
		close(pipefd[1]);
		return;
	}
	if (child == 0) {
		/* close read-end of pipe */
		close(pipefd[0]);
		if (pipefd[1] != STDOUT_FILENO) {
			if (dup2(pipefd[1], STDOUT_FILENO) == -1) {
				syslog(LOG_AUTHPRIV | LOG_WARNING,
				    "dup2: %s", strerror(errno));
				_eit(1);
			}
			if (pipefd[1] != STDERR_FILENO) {
				if (dup2(pipefd[1], STDERR_FILENO) == -1) {
					syslog(LOG_AUTHPRIV | LOG_WARNING,
					    "dup2: %s", strerror(errno));
					_eit(1);
				}
			}
		}
		setuser(uid);
		func();
		syslog(LOG_AUTHPRIV | LOG_ERR,
		    "%s", strerror(errno));
		_eit(1);
	}
	/* close write-end of pipe */
	close(pipefd[1]);
	if (read(pipefd[0], &p, sizeof(p)) != sizeof(p)) {
		syslog(LOG_AUTHPRIV | LOG_WARNING,
		    "read: %s", strerror(errno));
		close(pipefd[0]);
		return;
	}
	close(pipefd[0]);
	if (waitpid(child, &status, 0) == -1) {
		syslog(LOG_AUTHPRIV | LOG_WARNING,
		    "waitpid: %s", strerror(errno));
		return;
	}
	if (WIFSTOPPED(status)) {
		syslog(LOG_AUTHPRIV | LOG_ERR,
		    "child stopped by signal %d", WSTOPSIG(status));
		eit(128 + WSTOPSIG(status));
	}
	if (WIFCONTINUED(status)) {
		syslog(LOG_AUTHPRIV | LOG_ERR,
		    "child continued");
		eit(128 + WCONTINUED(status));
	}
	if (WIFEXITED(status)) {
		if (WEXITSTATUS(status) == 0)
			eit(0);
		syslog(LOG_AUTHPRIV | LOG_ERR,
		    "child exited with status %d", WEXITSTATUS(status));
		eit(WEXITSTATUS(status));
	}
	if (WIFSIGNALED(status)) {
		syslog(LOG_AUTHPRIV | LOG_ERR,
		    "child killed by signal %d", WTERMSIG(status));
		eit(128 + WTERMSIG(status));
	}
	/* just in case */
	eit(1);
