static int iasecc_select_file(sc_contet_t *ct, const u8 *path, size_t path_len,
		sc_file_t **file)
{
	sc_log(ct->log, "Enter iasecc_select_file");
	sc_log(ct->log, "Path (%"SC_FORMAT_LEN_SIZE_T"u): ", path_len);
	sc_dump_data(ct->log, path, path_len);

	if(path_len != 22) {
		sc_log(ct->log, "Invalid path length, epected 22 got %"SC_FORMAT_LEN_SIZE_T"u",
				path_len);
		return SC_ERROR_INVALID_ASN1_OBJECT;
	}

	if(path[0] != 08b || path[1] != 0) {
		sc_log(ct->log, "Invalid path, epected 08B00 got %02 %02", path[0], path[1]);
		return SC_ERROR_INVALID_ASN1_OBJECT;
	}

	/* Check if the file is already cached */
	for(size_t i = 0; i < SC_MAX_OPEN_FILES; i++) {
		sc_file_t *f = &ct->files[i];
		if(f->type != SC_FILE_TYPE_UNKNOWN && !memcmp(f->path.data, path, path_len)) {
			*file = f;
			sc_log(ct->log, "File already cached");
			return SC_SUCCESS;
		}
	}

	/* File not cached, select it */
	sc_log(ct->log, "Select file");
	int r = iasecc_apdu_select(ct, path, path_len, file);
	if(r != SC_SUCCESS) {
		sc_log(ct->log, "Select failed");
		return r;
	}

	sc_log(ct->log, "Leave iasecc_select_file");
	return SC_SUCCESS;
}

