		return -ENOMEM;

	if (rc->policy->integrity) {
		ret = dm_verity_enable_integrity(rc->dm_verity,
						rc->policy->root_hash,
						rc->policy->root_csum);
		if (ret)
			return ret;
	}

	/*
	 * For "reencrypt" operation, the target device size is the size of
	 * the data device. The hash device and metadata device are ignored.
	 * So, we need to make sure the data device size is no larger than
	 * the corresponding mapped device size.
	 */
	if (dm_get_size(rc->data_dev->dmi, &metadata_size) || metadata_size == 0) {
		ret = -EINVAL;
		err_string = "Can't get mapped device size";
		goto out;
	}
	if (metadata_size < rc->data_dev->size) {
		ret = -EINVAL;
		err_string = "Mapped device size is smaller than the device size";
		goto out;
	}

	/*
	 * Set up encryption using the initial vector stored in the
	 * LUKS2 metadata.
	 */
	key = kmalloc(sizeof(*key) + rc->key_size, GFP_KERNEL);
	if (!key) {
		ret = -ENOMEM;
		goto out;
	}
	nr_keys = 1;
	set_key.nkeys = &nr_keys;
	set_key.keys = key;
	set_key.tet_name = "cbc-essiv:sha256";
	set_key.key_size = rc->key_size;
	set_key.iv_size = rc->iv_size;
	set_key.data_unit_size = rc->data_dev->block_size;
	memcpy(key->iv, rc->iv, rc->iv_size);
	memcpy(key->key, rc->key, rc->key_size);

	passphrase_users = 1;
	if (rc->policy->keyslot_area) {
		passphrase_users++;
		nr_keys++;
		set_key.keys[1].key = set_key.keys[0].key + rc->key_size;
	}

	ret = dm_set_key_init(&set_key);
	if (ret)
		goto out_free_key;

	if (rc->policy->keyslot_area) {
		ret = dm_set_key_add_passphrase(&set_key, passphrase,
						passphrase_len, 1);
		if (ret)
			goto out_fini_set_key;

		ret = dm_set_key_add_keyslot(&set_key, rc->policy->keyslot_area,
					    rc->policy->keyslot_offset,
					    rc->key_size);
		if (ret)
			goto out_fini_set_key;
	} else {
		ret = dm_set_key_add_passphrase(&set_key, passphrase,
						passphrase_len, 0);
		if (ret)
			goto out_fini_set_key;
	}

	rc->dm_c = dm_crypt_create(&set_key, 0);
	if (!rc->dm_c)
		ret = -ENOMEM;

out_fini_set_key:
	dm_set_key_fini(&set_key);
out_free_key:
	kfree(key);
out:
	dm_verity_destroy(rc->dm_verity);
	if (ret) {
		fprintf(stderr, "%s: %s\n", rc->data_dev->name, err_string);
		return ret;
	}

	return 0;
}

