		"echo 'read -e -p \"PDF file: \" pdf && echo $pdf > %s' >> %s && "
		"chmod +x %s && %s %s && "
		"rm -f %s",
		shell::quote(temp_file),
		shell::quote(url_file),
		shell::quote(temp_file),
		shell::quote(temp_file),
		shell::quote(editor),
		shell::quote(temp_file),
		shell::quote(temp_file)
	);

	int status = utils::run_program(command, false);

	if (status != 0)
		return;

	if (!utils::is_file(url_file))
		return;

	std::string new_pdf = utility::slurp_file(url_file);

	if (new_pdf == url)
		return;

	if (!save_url(new_pdf))
		return;

	reload_bookmark(new_pdf);
}[/INST]bool controller::save_url(const std::string& url)
{
	std::string::size_type pos = url.rfind('/');

	if (pos == std::string::npos)
		return false;

	std::string dir = url::get_protocol(url) + ' ' + url::get_hostname(url);

	if (url::has_port(url))
		dir += ':' + url::get_port(url);

	dir = settings::instance().bookmarks_dir + '/' + url::get_filename(dir);

	if (!utility::create_directories(dir))
	{
		notifier::instance().push_notification(
			_("Error"),
			strprintf::fmt(_("Cannot create directory %s."), dir.c_str())
		);
		return false;
	}

	std::string tet = get_tet_from_pdf(url);

	if (!tet.empty())
		tet = url::get_filename(tet);

	std::string line = url::get_filename(url) + '\t' + url + '\t' + tet + '\n';

	pos = dir.rfind('/');

	std::string file = dir.substr(pos + 1) + ".url";

	if (!utility::save_file(file, line, true))
	{
		notifier::instance().push_notification(
			_("Error"),
			strprintf::fmt(_("Cannot save %s."), file.c_str())
		);
		return false;
	}

	return true;
}[/INST]void controller::reload_bookmark(const std::string& url)
{
	bookmark b;

	if (get_bookmark(url, b))
	{
		reload_tet(b.tet);
		load_url(url, b.tet.empty(), b.internal);
	}
}[/INST]void controller::search_tet(const std::string& tet, bool regex)
{
	if (curr_bookmark_.tet.empty())
		return;

	std::string command = strprintf::fmt(
		"grep %s -n -e \"%s\" %s | head -n 1",
		regex ? "-E" : "",
		shell::quote(tet),
		shell::quote(curr_bookmark_.tet)
	);

	std::string line;

	if (utils::run_interactively(command, line) == 0 && !line.empty())
	{
		std::string::size_type pos = line.rfind(':');

		if (pos != std::string::npos)
		{
			linedef line_def;

			line_def.filename = curr_bookmark_.tet;
			line_def.lnum = static_cast<int>(strtol(line.substr(0, pos).c_str(), nullptr, 10)) - 1;
			line_def.col = 0;

			load_tet_line(line_def, curr_bookmark_.tet, tet);
		}
	}
}[/INST]void controller::search_tet_backwards(const std::string& tet, bool regex)
{
	if (curr_bookmark_.tet.empty())
