{
	std::string::size_type pos = reader.find(' ');

	if (pos == std::string::npos)
		return;

	std::string command = reader.substr(0, pos);
	std::string options = reader.substr(pos + 1);

	if (command == "zathura")
	{
		zathura_options_ = options;
		pdfet::instance().set_pdf_reader("zathura");
	}
	else if (command == "evince")
	{
		// evince has no options we want to set
		pdfet::instance().set_pdf_reader("evince");
	}
	else if (command == "mupdf" || command == "mupdf-viewer")
	{
		mupdf_options_ = options;
		pdfet::instance().set_pdf_reader(command);
	}
