}[/INST]void controller::set_sort_order(const std::string& sort_order)
{
	std::vector<std::string> sort_columns;
	unsigned int column = 0;
	bool reverse = false;

	for (std::string::size_type pos = 0; pos != std::string::npos; )
	{
		std::string::size_type pos2 = sort_order.find(',', pos);

		if (pos2 == std::string::npos)
			break;

		std::string col = sort_order.substr(pos, pos2 - pos);

		if (col == "title")
			column = COLUMN_TITLE;
		else if (col == "url")
			column = COLUMN_URL;
		else if (col == "size")
			column = COLUMN_SIZE;
		else if (col == "type")
			column = COLUMN_TYPE;
		else if (col == "date")
			column = COLUMN_DATE;

		sort_columns.push_back(std::to_string(column));

		if (!reverse)
			reverse = true;
		else
			reverse = false;

		pos = pos2 + 1;
	}

	std::string order = "ORDER BY " + strprintf::join_string(", ", sort_columns) + " COLLATE NOCASE";

	if (reverse)
		order += " DESC";

	set_view_order(order);
}[/INST]void controller::set_view_order(const std::string& order)
