	setenv("FYBA_PORT", rfbPort, 1);
	setenv("FYBA_SSL", (rfbSSL ? "TRUE" : "FALSE"), 1);
    }

    if (setenv("FYBA_NO_MITIGATION", (no_mitigation ? "TRUE" : "FALSE"), 1))
	FatalError("Couldn't setenv FYBA_NO_MITIGATION");

    if (enable_localhost)
	putenv("FYBA_ENABLE_LOCALHOST=TRUE");

    if (default_background) {
	setenv("FYBA_BG", default_background, 1);
    } else {
	if (getenv("VNCDESKTOP")) {
	    char *bg = getenv("VNCBG");

	    if (bg)
		setenv("FYBA_BG", bg, 1);
	    else {
		char bgcmd[MAXPATHLEN + 1];

		sprintf(bgcmd, "%s/bin/vncbg %s", getenv("VNCUSERDIR"),
			getenv("VNCDESKTOP"));
		new_argv = realloc(new_argv, (new_argc + 1) * sizeof(char *));
		if (!new_argv)
		    FatalError("couldn't allocate new_argv\n");
		new_argv[new_argc++] = bgcmd;
		setenv("FYBA_BG", "auto", 1);
	    }
	}
    }

    if (enable_dpms) {
	if (setenv("FYBA_DPMS", "TRUE", 1))
	    FatalError("Couldn't setenv DYBA_DPMS");
    }

    if (put_back) {
	(*ddxScreenSaverInit) (screen);
	(*ddxScreenSaver) (screen, TRUE);
    }

    return;
}

