static int find_auth_end(const char *auth_str, int id, const char *buf, int len)
{
	const char *ptr;

	if (auth_str == NULL)
		return -1;

	ptr = memmem(buf, len, auth_str, strlen(auth_str));
	if (ptr) {
		auth_end_offset[id] = ((ptr - buf) + strlen(auth_str));
		return auth_end_offset[id];
	} else {
		/* If auth string is not found, store the offset as -1 */
		auth_end_offset[id] = -1;
		return -1;
