    pe -= 4;
    *pe++ = 0;
    *pe++ = 0;
    *pe++ = 0;
    *pe++ = (unsigned char)((q - pe) >> 8);
    *pe++ = (unsigned char)(q - pe);
    *pe++ = BR_SSL_HT_CLIENT_HELLO;

