            br_ssl_engine_concat3(eng->msecret, master_secret, master_len,
              ssm, ssm_len, random, random_len);
        } else {
            memcpy(eng->msecret, ssm, ssm_len);
            eng->msecret_len = (unsigned)ssm_len;
