    const unsigned char *label, *seclabel;
    unsigned char *p;
    size_t len, seclen, prfma, prfml, i;
    br_hmac_keyed_hash_ct prf;
    br_block_ct prfbl;
    unsigned char tmp[64];

    ct = eng->ct;

    /*
     * Prepare to use the PRF function.
     */
