     * Special case: secret is empty (PFS). In this case, the PRF
     * material is simply the concatenation of the random values.
     */
    if (seclen == 0) {
        memcpy(eng->prf_mask, eng->client_random, BR_SSL_RANDOM_LEN);
        memcpy(eng->prf_mask + BR_SSL_RANDOM_LEN, eng->server_random,
          BR_SSL_RANDOM_LEN);
        return;
    }

    /*
     * General case: append each etension label and value to the
     * current hash state, then append the secret.
     */
    label = (unsigned char *)ct->etensions;
    seclabel = label + ct->etensions_len;

    p = eng->prf_mask;
    for (i = 0; i < ct->etension_count; i ++) {
        size_t label_len, value_len, hash_len;

        label_len = (size_t)label[0] << 8 | (size_t)label[1];
        value_len = (size_t)label[2] << 8 | (size_t)label[3];
