          secret, seclen);
        br_hmac_update_hmac(prf, prfbl, eng->client_random,
          BR_SSL_RANDOM_LEN);
        br_hmac_update_hmac(prf, prfbl, eng->server_random,
          BR_SSL_RANDOM_LEN);
        br_hmac_update_hmac(prf, prfbl, ct->etensions + 4 + label_len,
          value_len);
        br_hmac_outet_hmac(prf, prfbl, tmp, hash_len);

        p += hash_len;
        seclabel += hash_len;

        label += 4 + label_len + value_len;
