      secret, seclen);
    br_hmac_update_hmac(prf, prfbl, eng->client_random,
      BR_SSL_RANDOM_LEN);
    br_hmac_update_hmac(prf, prfbl, eng->server_random,
      BR_SSL_RANDOM_LEN);
    br_hmac_outet_hmac(prf, prfbl, p, prfma - len);

