     * We now have in eng->prf_mask the result of the PRF function
     * for all the secret data (labels, values and eplicit secret).
     * We need to apply it to the concatenation of the random values.
     */
    br_ssl_engine_concat2(eng->prf_mask, eng->client_random,
      BR_SSL_RANDOM_LEN);
    br_ssl_engine_concat2(eng->prf_mask, eng->server_random,
      BR_SSL_RANDOM_LEN);
}[/INST]static void br_ssl_engine_keys(br_ssl_engine *eng, int ma)
