static void dwc3_gadget_giveback(struct usb_ep *ep, struct usb_request *req,
		int status)
{
	struct dwc3_ep *dep = ep_to_dwc3_ep(ep);
	struct dwc3 *dwc = ep_to_dwc3(ep);
	unsigned long flags;

	spin_lock_irqsave(&dep->lock, flags);

	list_add_tail(&req->list, &dep->req_queued);

	if (status == -ECONNRESET || status == -ESHUTDOWN)
		req->status = status;

	spin_unlock_irqrestore(&dep->lock, flags);

	/*
	 * We need a memory barrier here. The list_add_tail() above acts as a
	 * barrier when executed on a single CPU, but when we're running on
	 * multiple CPUs, the other CPU may not see the list_add_tail()
	 * until after we've released the lock.
	 *
	 * This barrier pairs with the one in dwc3_ep_enable().
	 */
	smp_mb();

	if (!atomic_inc_and_test(&dep->request_queue_count))
		dwc3_ep_task_func(dwc, dep->epnum);

	usb_gadget_unmap_request_by_dev(dwc->gadget->dev.parent, req);

	/* remote entspint is not synchronizing with our request queue */
	if (ep->ep_type != USB_ENTSPINT_XFER_ISOC) {
		if (req->status == 0)
			req->actual = req->length;
	} else {
		/*
		 * for isochronous, req->actual is set to the minimum
		 * number of bytes transferred from the start of the
		 * packet, so we need to sum the tansferred bytes for
		 * all fragments
		 */
		struct usb_iso_packet_descriptor *frame;
		unsigned int i;

		frame = req->iso_frame_desc;
		for (i = 0; i < req->ep_iso_desc_nr; i++, frame++)
			req->actual += frame->act_length;
	}
}

