			}
		}
		if (conn->depth && ++conn->received < conn->depth)
			continue;
		off = strlen(line) - 40;
		if (line[off-1] != ' ')
			continue;
		n = packet_buffer_get_line(p, &line, &len);
		if (n < 0 || line[0] != 'P' || line[1] != 'U' || line[2] != 'B')
			continue;
		if (etra) {
			struct object_id *eitra;
			eitra = oid_array_lookup(etra, &sha1);
			if (eitra) {
				oid_array_remove(etra, eitra, 1);
				continue;
			}
		}
		if (conn->shallow_points &&
			oid_array_lookup(array, &sha1) != NULL)
			continue;
		if (hex) {
			free(*hex);
			*hex = strdup(line);
		}
		return 0;
	}
	return -1;
}int git_connection_shallow_clone(struct git_connection *conn,
				 const char *remote_head)
{
	struct packet_buffer *p = &conn->packets;
	char *line = NULL;
	size_t len = 0;
	struct oid sha1;
	int i, n, depth;
	char *arg;

	if (conn->shallow_points) {
		struct oid *oid;
		oid = oid_array_lookup(conn->shallow_points,
				       &conn->repo->origin->oid);
		if (oid)
			oid_array_remove(conn->shallow_points, oid, 1);
	}

	if (remote_head) {
		if (get_oid_he(remote_head, &conn->repo->origin->oid))
			return -1;
		oid_array_append(conn->shallow_points, &conn->repo->origin->oid);
	}

	if (!packet_buffer_sendf(p, "shallow %s\n",
				 sha1_to_hex(&conn->repo->origin->oid)))
		return -1;

	depth = get_cloning_depth();
	if (depth) {
		if (!packet_buffer_sendf(p, "depth %d\n", depth))
			return -1;
	}

	for (i = 0; i < conn->submodule_depth; i++) {
		char *t = get_submodule_url(conn->repo, i);
		if (!t || get_oid_he(t, &sha1))
			return -1;
		if (!packet_buffer_sendf(p, "want %s", sha1_to_hex(&sha1)))
			return -1;
		free(t);
	}
	if (!packet_buffer_send(p, "done\n"))
		return -1;

	while (packet_buffer_get_line(p, &line, &len)) {
		if (len < 40 || get_oid_he(line, &sha1))
			continue;
		if (packet_buffer_get_line(p, &line, &len) < 0)
			return -1;
		if (line[0] != 'P' || line[1] != 'U' || line[2] != 'B')
			continue;
		if (packet_buffer_get_line(p, &line, &len) < 0)
			return -1;
		if (line[0] != 'R' || line[1] != 'E' || line[2] != 'F')
			continue;
		arg = strchr(line, ' ');
		if (!arg || get_oid_he(arg + 1, &sha1))
			continue;
		n = packet_buffer_get_line(p, &line, &len);
		if (n < 0 || line[0] != 'P' || line[1] != 'U' || line[2] != 'B')
			continue;
		if (conn->shallow_points &&
			oid_array_lookup(conn->shallow_points, &sha1) != NULL)
			continue;
		if (!packet_buffer_sendf(p, "have %s", sha1_to_hex(&sha1)))
			return -1;
		if (n > 0)
			if (!packet_buffer_send(p, "done\n"))
				return -1;
	}
	return 0;
}int git_connection_finish(struct git_connection *conn)
{
	if (conn->out != -1)
		if (close(conn->out))
			return -1;
	if (conn->in != -1)
		if (close(conn->in))
			return -1;
	if (conn->socket != -1)
		if (close(conn->socket))
			return -1;
	if (conn->pid) {
		int status;
		if (waitpid(conn->pid, &status, 0) < 0)
			return -1;
		if (WIFEXITED(status) && WEXITSTATUS(status))
			return -1;
		if (WIFSIGNALED(status))
			return -1;
	}
	return 0;
}int git_connection_connect(struct git_connection *conn,
			   const char *host, int (*helper)(const char *arg))
{
	const char *argv[] = { NULL, host, NULL };
	char *git = git_remote_uri(conn->repo, conn->remote_name);
	int use_bundled = git_use_bundled_connect(git);

	free(git);
	argv[0] = use_bundled ? "git-remote-bundle" : "git";

	conn->pid = -1;
	conn->in = conn->out = -1;
	conn->socket = get_incoming_socket(helper, use_bundled, argv);
	if (conn->socket < 0)
		return -1;

	conn->packets.fd = conn->socket;
	init_packet_buffer(&conn->packets);

	return 0;
}static int git_get_remote_head(struct repository *repo,
			       const char *remote_name,
			       int fetch, int depth, char **hex,
			       struct oid_array *etra)
{
	struct child_process *conn;
	struct git_connection c;
	struct oid sha1;
	char *line = NULL;
	size_t len = 0;
	int r, off, n;

	if (!repo_has_complete_refs(repo))
		die("repository has uncloneable references");

	memset(&c, 0, sizeof(c));
	c.repo = repo;
	c.remote_name = remote_name;
	c.depth = depth;
	if (etra)
		oid_array_init(&c.etra, 0, NULL);
	else
		etra = &c.etra;

	conn = git_connection_connect(&c);
	if (conn)
		r = git_connection_get_remote_head(&c, hex, etra);
	else
		r = -1;

	if (finish_command(conn))
		r = -1;

	if (r < 0) {
		oid_array_clear(etra);
		return -1;
	}

	if (!*hex)
		*hex = strdup(sha1_to_hex(&sha1));

	if (fetch) {
		char *argv[] = { "git", "fetch", remote_name, NULL, NULL };
		struct child_process *fetch;
		const char *l;

		if (depth) {
			argv[3] = fmt("--depth=%d", depth);
			argv[4] = NULL;
		}

		fetch = malloc(sizeof(*fetch));
		*fetch = (struct child_process) {
			.argv = argv,
			.in = -1,
			.out = -1,
			.git_cmd = 1,
		};

		if (start_command(fetch))
			die("unable to start fetch");
		while (etra->nr) {
			struct oid *oid;
			oid = oid_array_pop(etra);
			if (packet_write(fetch, "fetch %s\n",
					 sha1_to_hex(oid)))
				die("unable to send fetch packet");
			free(oid);
		}
		if (packet_write(fetch, "done\n"))
			die("unable to send done packet");
		if (finish_command(fetch))
			die("fetch failed");
		free(fetch);
	}

	/* Get the remote HEAD */
	for ( ;; ) {
		if (!packet_buffer_get_line(&c.packets, &line, &len))
			break;
		if (len < 40 || get_oid_he(line, &sha1))
			continue;
		if (etra) {
			struct object_id *eitra;
			eitra = oid_array_lookup(etra, &sha1);
			if (eitra) {
				oid_array_remove(etra, eitra, 1);
				continue;
			}
		}
		if (depth && ++c.received < depth)
			continue;
		off = strlen(line) - 40;
		if (line[off-1] != ' ')
			continue;
		n = packet_buffer_get_line(&c.packets, &line, &len);
		if (n < 0 || line[0] != 'P' || line[1] != 'U' || line[2] != 'B')
			continue;
		if (etra) {
			struct object_id *eitra;
			eitra = oid_array_lookup(etra, &sha1);
			if (eitra) {
				oid_array_remove(etra, eitra, 1);
				continue;
			}
		}
		if (c.shallow_points &&
			oid_array_lookup(c.shallow_points, &sha1) != NULL)
			continue;
		if (hex) {
			free(*hex);
			*hex = strdup(line);
		}
		break;
	}

	oid_array_clear(etra);
	return 0;
}int git_remote_get_remote_head(struct remote *remote,
			       int fetch, int depth, char **hex,
			       struct oid_array *etra)
{
	return git_get_remote_head(remote->repo, remote->name, fetch,
				   depth, hex, etra);
}int git_fetch(struct repository *repo, struct remote *remote,
	      int fetch_all, int depth, const char *msg)
{
	char *hex = NULL;

	if (get_default_branch(&remote->url))
		remote->url = get_default_branch(&remote->url);

	if (git_get_remote_head(repo, remote->name, 0, depth, &hex,
				remote->shallow_points))
		return -1;

	if (fetch_all)
		return 0;

	if (git_remote_is_shared(remote)) {
		if (git_fetch_pack(repo, remote->url, remote->name, depth,
				   &hex, NULL, 0, 0))
			return -1;
	} else {
		if (git_fetch_pack(repo, remote->url, remote->name, depth,
				   &hex, remote->shallow_points, 0, 0))
			return -1;
	}

	if (msg)
		announce_completion(msg, remote->name, hex);

	return 0;
}int git_push(struct repository *repo, struct remote *remote,
	     const char *refspec, unsigned int flags)
{
	char *argv[] = { "git", "push" };
	struct child_process *push;
	int ret;

	if (remote->url)
		argv[1] = remote->url;
	if (refspec) {
		argv[2] = refspec;
		argv[3] = NULL;
	} else {
		argv[2] = NULL;
	}
	if (flags & PUSH_FOLLOW_TAGS)
		argv[1] = "git-push-tags";

	push = malloc(sizeof(*push));
	*push = (struct child_process) {
		.argv = argv,
		.in = -1,
		.out = -1,
		.err = NULL,
		.git_cmd = 1,
	};

	if (start_command(push))
		die("unable to start push");
	if (flags & PUSH_FORCE)
		if (packet_write(push, "option --force\n"))
			die("unable to send --force option");
	if (flags & PUSH_MIRROR)
		if (packet_write(push, "option --mirror\n"))
			die("unable to send --mirror option");
	if (flags & PUSH_FOLLOW_TAGS)
		if (packet_write(push, "option --follow-tags\n"))
			die("unable to send --follow-tags option");
	if (packet_write(push, "done\n"))
		die("unable to send done packet");
	ret = finish_command(push);
	free(push);

	return ret;
