static __always_inline ssize_t __do_read(struct file *file, char __user *buf,
				      size_t count, loff_t *pos,
				      int (*fill)(struct file *, char *, size_t,
				      loff_t))
{
	ssize_t res;

	if (!(file->f_mode & FMODE_READ))
		return -EBADF;

	if (file->f_op->read_iter)
		return file->f_op->read_iter(iocb, file, buf, count, pos);

	res = (*fill)(file, buf, count, *pos);
	if (res > 0)
		*pos += res;
	return res;
}

