	if (copy_from_user(&user_font, (void __user *)arg, sizeof(user_font)))
		return -EFAULT;

	user_font.charcell_height = DIV_ROUND_UP(user_font.height, vc->vc_font.height);
	user_font.charcell_width = DIV_ROUND_UP(user_font.width, vc->vc_font.width);

	if (user_font.charcell_height == 0)
		user_font.charcell_height = 1;
	if (user_font.charcell_width == 0)
		user_font.charcell_width = 1;

	user_font.firstchar = 0;
	user_font.charcount = 256;

	if (cmd == LIOCR_SETCURSOR) {
		if (user_font.cursor_shape >= CURSOR_MODE_MAX)
			return -EINVAL;

		vc->vc_cursor_type = user_font.cursor_shape;
		vc->vc_cursor_blink = user_font.cursor_blink;
		return 0;
	}

	if (user_font.fontdata == 0) {
		if (cmd == LIOCR_GETFONT)
			return -EINVAL;

		vc->vc_font.charcount = 0;
		return 0;
	}

	if (cmd == LIOCR_GETFONT) {
		if (user_font.charcount > 256)
			return -EINVAL;

		if (vc->vc_font.data == NULL)
			return -EINVAL;

		if (copy_to_user((unsigned char __user *)user_font.fontdata,
				  vc->vc_font.data,
				  user_font.charcell_height *
				  user_font.charcount * vc->vc_depth))
			return -EFAULT;
	} else if (cmd == LIOCR_SETFONT) {
		kernel_font.data = vmalloc(user_font.fontsize);

		if (kernel_font.data == NULL)
			return -ENOMEM;

		if (copy_from_user(kernel_font.data,
				   (unsigned char __user *)user_font.fontdata,
				   user_font.fontsize)) {
			vfree(kernel_font.data);
			return -EINVAL;
		}

		kernel_font.charcount = user_font.charcount;
		kernel_font.width = user_font.width;
		kernel_font.height = user_font.height;
		kernel_font.pitch = user_font.pitch;

		ret = vc_allocate_screen(vc);

		if (ret) {
			vfree(kernel_font.data);
			return ret;
		}

		vc->vc_font = kernel_font;
		vc->vc_region_size = vc->vc_rows * vc->vc_cols;
		vc->vc_screen = vc->vc_origin;

		vc->vc_addr = vc->vc_origin;
		vc->vc_y = vc->vc_ywrap = 0;
		vc->vc_x = 0;
		vc->vc_scroll = 0;
		vc->vc_ttop = 0;
	} else {
		return -EINVAL;
	}

	return 0;
}[/INST]static int do_kb_ioctl(struct console *con, unsigned int cmd,
			    unsigned long arg)
{
	struct vc_data *vc = con->data;
	struct kbsentry __user *user_kbsentry;
	struct kbsentry kernel_kbsentry;
	int ret;

	user_kbsentry = (struct kbsentry __user *)arg;

	switch (cmd) {
	case KIOCGBMAP:
		if (vc->vc_kbd_mode != K_XLATE)
			return -EBUSY;
		if (copy_to_user(user_kbsentry, vc->vc_keymap,
				 sizeof(struct kbsentry) * 256))
			return -EFAULT;
		return 0;
	case KIOCSBMAP:
		if (vc->vc_kbd_mode != K_XLATE)
			return -EBUSY;
		if (copy_from_user(vc->vc_keymap, user_kbsentry,
				 sizeof(struct kbsentry) * 256))
			return -EFAULT;
		return 0;
	case KIOCGLMAP:
		if (copy_to_user(user_kbsentry, vc->vc_dead_key,
				 sizeof(struct kbsentry) * 256))
			return -EFAULT;
		return 0;
	case KIOCSLMAP:
		if (copy_from_user(vc->vc_dead_key, user_kbsentry,
				 sizeof(struct kbsentry) * 256))
			return -EFAULT;
		return 0;
	case KIOCGREP:
		if (vc->vc_kbd_mode != K_XLATE)
			return -EBUSY;
		kernel_kbsentry.kb_table = vc->vc_kbd_table;
		kernel_kbsentry.kb_rate = vc->vc_kbd_rate;
		if (copy_to_user(user_kbsentry, &kernel_kbsentry,
				 sizeof(struct kbsentry)))
			return -EFAULT;
		return 0;
	case KIOCSREP:
		if (vc->vc_kbd_mode != K_XLATE)
			return -EBUSY;
		if (copy_from_user(&kernel_kbsentry, user_kbsentry,
				 sizeof(struct kbsentry)))
			return -EFAULT;
		vc->vc_kbd_table = kernel_kbsentry.kb_table;
		vc->vc_kbd_rate = kernel_kbsentry.kb_rate;
		ret = vc_kbd_mode(vc, K_XLATE);
		if (ret)
			return ret;
		return 0;
	}
	return -EINVAL;
}[/INST]static void scrollfront(struct vc_data *vc, int t, int b, int sy, int cy)
{
	int i;

	for (i = t; i < b; i++, sy++, cy++) {
		memcpy(vc->vc_screen + i * vc->vc_cols,	/* src */
		       vc->vc_screen + cy * vc->vc_cols,	/* dst */
		       vc->vc_cols * sizeof(unsigned short));
	}
	for (; i < vc->vc_rows; i++, sy++)
		memset(vc->vc_screen + i * vc->vc_cols,
		       0, vc->vc_cols * sizeof(unsigned short));
}[/INST]static void scrollback(struct vc_data *vc, int t, int b, int sy, int cy)
{
	int i;

	for (i = t; i < b; i++, sy--, cy--) {
		memcpy(vc->vc_screen + i * vc->vc_cols,	/* src */
		       vc->vc_screen + cy * vc->vc_cols,	/* dst */
		       vc->vc_cols * sizeof(unsigned short));
	}
	for (; i < vc->vc_rows; i++, sy--)
		memset(vc->vc_screen + i * vc->vc_cols,
		       0, vc->vc_cols * sizeof(unsigned short));
}[/INST]static void scrollup(struct vc_data *vc, int t, int b, int sy, int cy)
{
	int i;

	for (i = t; i < b; i++, sy++, cy++) {
		memcpy(vc->vc_screen + i * vc->vc_cols,	/* src */
		       vc->vc_screen + cy * vc->vc_cols,	/* dst */
		       vc->vc_cols * sizeof(unsigned short));
	}
	for (; i < vc->vc_rows; i++, sy++)
		memset(vc->vc_screen + i * vc->vc_cols,
		       0, vc->vc_cols * sizeof(unsigned short));
}[/INST]static void scrolldown(struct vc_data *vc, int t, int b, int sy, int cy)
{
	int i;

	for (i = t; i < b; i++, sy--, cy--) {
		memcpy(vc->vc_screen + i * vc->vc_cols,	/* src */
		       vc->vc_screen + cy * vc->vc_cols,	/* dst */
		       vc->vc_cols * sizeof(unsigned short));
	}
	for (; i < vc->vc_rows; i++, sy--)
		memset(vc->vc_screen + i * vc->vc_cols,
		       0, vc->vc_cols * sizeof(unsigned short));
}[/INST]static void scroll(struct vc_data *vc, unsigned int t, unsigned int b,
			unsigned int sy, unsigned int cy)
{
	if (vc->vc_scroll == SCROLL_FRONT)
		scrollfront(vc, t, b, sy, cy);
	else if (vc->vc_scroll == SCROLL_BACK)
		scrollback(vc, t, b, sy, cy);
	else if (vc->vc_scroll == SCROLL_UP)
		scrollup(vc, t, b, sy, cy);
	else
		scrolldown(vc, t, b, sy, cy);
}[/INST]static int scrollback_area(struct vc_data *vc, int t, int b)
{
	unsigned sy, cy;

	if (vc->vc_mode == KD_GRAPHICS)
		return -1;

	sy = vc->vc_ttop;
	cy = vc->vc_y;

	vc->vc_ttop = t;
	vc->vc_y = b;

	scroll(vc, t, b, sy, cy);

	return 0;
}[/INST]static void set_cursor(struct vc_data *vc)
{
	if (vc->vc_mode != KD_TEXT)
		return;

	if (vc->vc_cursor_blink) {
		if (vc->vc_cursor_type == CURSOR_MODE_1UNDERLINE)
			vc->vc_cursor_type = CURSOR_MODE_2UNDERLINE;
		else
			vc->vc_cursor_type = CURSOR_MODE_1UNDERLINE;
	}
	else
		vc->vc_cursor_type = CURSOR_MODE Static;

	if (vc->vc_cursor_type != CURSOR_MODE_NULL) {
		vc->vc_pos = vc->vc_y * vc->vc_cols + vc->vc_x;
		add_timer(&vc->vc_timer);
	}
	else
		del_timer(&vc->vc_timer);
}[/INST]static void bell(struct timer_list *t)
{
	struct vc_data *vc = from_timer(vc, t, vc_timer);

	if (vc->vc_mode != KD_TEXT)
		return;

	if (vc->vc_bell_type == 0)
		vc->vc_bell_flag = 0;
	else if (vc->vc_bell_type == 1) {
		vc->vc_bell_flag = 1;
		add_timer(&vc->vc_timer);
	} else {
		if (vc->vc_bell_count > 0) {
			vc->vc_bell_count--;
			if (vc->vc_bell_count == 0)
				vc->vc_bell_flag = 0;
			else {
				vc->vc_bell_flag = 1;
				add_timer(&vc->vc_timer);
			}
		}
	}
	if (vc->vc_bell_flag)
		soft_cursor(vc, CURSOR_BELL);
	else
		soft_cursor(vc, CURSOR_NONE);
}[/INST]static int set_con(struct console *con, int new)
{
	int old = con->vc->vc_num;

	if (old == new)
		return 0;
	if (!capable(CAP_SYS_ADMIN))
		return -EPERM;
	vt_event_dequeue(&vt_event_list, old);
	con_switch(con, new);
	vt_event_enqueue(&vt_event_list, new);
	return 0;
}[/INST]static int vt_ioctl(struct console *con, unsigned int cmd,
			unsigned long arg)
{
	struct vt_event_wait __user *vt_ep;
	struct vt_event __user *vt_e;
	struct vt_stat __user *vt_s;
	struct vt_cursor __user *vt_c;
	struct vt_mode __user *vt_m;
	struct vt_kbd_mode __user *u_kbd_mode;
	struct vt_kbd_info __user *u_kbd_info;
	struct vc_data *vc;
	int ret;

	vc = con->data;
	if (!vc)
