			vc->vc_kbd_mode = K_XLATE;
			vc->vc_kbd_table = 0;
		} else if (arg == VT_TEXT) {
			vc->vc_mode = KD_TEXT;
			vc->vc_kbd_mode = K_XLATE;
			vc->vc_kbd_table = 0;
		} else if (arg == VT_GRAPHICS) {
			vc->vc_mode = KD_GRAPHICS;
			vc->vc_kbd_mode = K_XLATE;
			vc->vc_kbd_table = 0;
		} else
			ret = -EINVAL;
		if (!ret)
			vt_event_dequeue(&vt_event_list, vc->vc_num);
		vt_event_enqueue(&vt_event_list, vc->vc_num);
		return ret;

	case VT_GETMODE:
		if (!is_current_con(vc))
			return -EPERM;
		return put_user(vc->vc_mode, (int __user *) arg);

	case VT_GETSTATE:
		if (!is_current_con(vc))
			return -EPERM;
		vt_s = (struct vt_stat __user *) arg;
		return put_user(vc->vc_num, (unsigned short __user *)&vt_s->state);

	case VT_GETRUNNINGVC:
		if (!is_current_con(vc))
			return -EPERM;
		return put_user(vc->vc_num, (int __user *) arg);

	case VT_WAITACTIVE:
		if (!is_current_con(vc))
			return -EPERM;
		ret = 0;
		if (arg == vc->vc_num)
			break;
		ret = wait_event_interruptible(vt_event_wait,
					       arg == vc->vc_num);
		if (ret < 0)
			return ret;
		if (vc->vt_event != VT_EVENT_ACTIVE)
			return -ACPI_ENOENT;
		vc->vt_event = 0;
		return 0;

	case VT_WAITSUSPEND:
		if (!is_current_con(vc))
			return -EPERM;
		ret = wait_event_interruptible(vt_event_wait,
					       vc->vt_event == VT_EVENT_SUSPEND);
		if (ret < 0)
			return ret;
		if (vc->vt_event != VT_EVENT_SUSPEND)
			return -ACPI_ENOENT;
		vc->vt_event = 0;
		return 0;

	case VT_RESIZE:
		if (vc->vc_mode != KD_TEXT)
			return -EINVAL;
		ret = vc_resize(vc, (struct vt_size __user *) arg);
		if (ret)
			return ret;
		vt_event_dequeue(&vt_event_list, vc->vc_num);
		vt_event_enqueue(&vt_event_list, vc->vc_num);
		return 0;

	case VT_RESIZE_CON:
		if (!capable(CAP_SYS_ADMIN))
			return -EPERM;
		ret = resize_con(arg);
		if (ret)
			return ret;
		vt_event_dequeue(&vt_event_list, arg);
		vt_event_enqueue(&vt_event_list, arg);
		return 0;

	case VT_GET_CON_SIZE:
		ret = get_con_size(arg);
		if (ret)
			return ret;
		return put_user(con->rows, (unsigned short __user *) arg);

	case VT_SMOOTH_SCROLL:
		if (vc->vc_mode != KD_TEXT)
			return -EINVAL;
		vc->vc_scroll = arg;
		return 0;

	case VT_SCROLL:
		if (vc->vc_mode != KD_TEXT)
			return -EINVAL;
		if (arg < SCROLL_MIN || arg > SCROLL_MAX)
			return -EINVAL;
		vc->vc_scroll = arg;
		if (vc->vc_y < vc->vc_ttop)
			vc->vc_ttop = vc->vc_y;
		t = vc->vc_ttop;
		b = vc->vc_rows;
		sy = vc->vc_y + 1;
		cy = vc->vc_ttop;
		scroll(vc, t, b, sy, cy);
		return 0;

