		c = 0177;
		return put_user(c, (unsigned short __user *) arg);

	case VT_TAB:
		if (vc->vc_mode != KD_TEXT)
			return -EINVAL;
		vc->vc_pos += 8 - (vc->vc_pos % 8);
		if (vc->vc_pos >= vc->vc_cols) {
			vc->vc_pos = vc->vc_cols - 1;
			return 0;
		}
		c = 0;
		return put_user(c, (unsigned short __user *) arg);

	case VT_NEWLINE:
		if (vc->vc_mode != KD_TEXT)
			return -EINVAL;
		vc->vc_pos += vc->vc_cols;
		if (vc->vc_pos >= vc->vc_rows * vc->vc_cols) {
			vc->vc_pos = vc->vc_rows * vc->vc_cols - 1;
			return 0;
		}
		c = 0;
		return put_user(c, (unsigned short __user *) arg);

	case VT_GET_KBD_MODE:
		u_kbd_mode = (struct vt_kbd_mode __user *) arg;
		ret = 0;
		if (vc->vc_kbd_mode == K_XLATE) {
			if (vc->vc_kbd_table == 0)
				ret = VT_KBD_MODE_RAW;
			else
				ret = VT_KBD_MODE_MAPPED;
		}
		return put_user(ret, (int __user *)&u_kbd_mode->mode);

	case VT_SET_KBD_MODE:
		u_kbd_mode = (struct vt_kbd_mode __user *) arg;
		ret = 0;
		if (vc->vc_mode != KD_TEXT)
			ret = -EBUSY;
		else if (u_kbd_mode->mode == VT_KBD_MODE_RAW)
			vc->vc_kbd_mode = K_RAW;
		else if (u_kbd_mode->mode == VT_KBD_MODE_MAPPED) {
			vc->vc_kbd_mode = K_XLATE;
			vc->vc_kbd_table = 0;
		} else
			ret = -EINVAL;
		if (!ret)
			vt_event_dequeue(&vt_event_list, vc->vc_num);
		vt_event_enqueue(&vt_event_list, vc->vc_num);
		return ret;

	case VT_GET_KBD_TABLE:
		u_kbd_info = (struct vt_kbd_info __user *) arg;
		if (vc->vc_kbd_mode != K_XLATE)
			return -EBUSY;
		return put_user(vc->vc_kbd_table,
				(unsigned short __user *)&u_kbd_info->table);

	case VT_SET_KBD_TABLE:
		u_kbd_info = (struct vt_kbd_info __user *) arg;
		if (vc->vc_mode != KD_TEXT)
			return -EBUSY;
		if ((unsigned)u_kbd_info->table >= KEYMAP_COUNT)
			return -EINVAL;
		vc->vc_kbd_table = u_kbd_info->table;
		vc->vc_kbd_mode = K_XLATE;
		return 0;

