	case VT_WAIT_CON:
		ret = wait_event_interruptible(vt_event_wait,
					       arg == vc->vc_num);
		if (ret < 0)
			return ret;
		if (vc->vt_event != VT_EVENT_ACTIVE)
			return -ACPI_ENOENT;
		vc->vt_event = 0;
		return 0;

	case VT_GET_CON:
		return get_con(arg);

	case VT_EVENT_WAIT:
		vt_ep = (struct vt_event_wait __user *)arg;
		ret = get_user(vt_ep->vte_event, &vt_ep->vte_event);
		if (ret)
			return ret;
		if (vt_ep->vte_event != VT_EVENT_SUSPEND &&
		    vt_ep->vte_event != VT_EVENT_ACTIVE)
			return -EINVAL;
		ret = wait_event_interruptible(vt_event_wait,
			       (vc->vt_event == vt_ep->vte_event ||
				vc->vt_event == VT_EVENT_SUSPEND));
		if (ret < 0)
			return ret;
		if (vc->vt_event != vt_ep->vte_event)
			return -ACPI_ENOENT;
		vc->vt_event = 0;
		return 0;

	case VT_GET_SIZE:
		vt_e = (struct vt_event __user *) arg;
		ret = get_user(vt_e->vt_event, &vt_e->vt_event);
		if (ret)
			return ret;
		if (vt_e->vt_event != VT_EVENT_RESIZE)
			return -EINVAL;
		ret = get_user(vt_e->vt_pid, &vt_e->vt_pid);
		if (ret)
			return ret;
		vt_e->vt_rows = vc->vc_rows;
		vt_e->vt_cols = vc->vc_cols;
		vt_e->vt_bwidth = vc->vc_bwidth;
		return 0;

	case VT_SET_CURSOR:
		vt_c = (struct vt_cursor __user *)arg;
		ret = copy_from_user(&vc->vc_new_c, vt_c, sizeof(struct vt_cursor));
		if (ret)
			return -EFAULT;
		if (vc->vc_new_c.state == CURSOR_HIDE)
			vc->vc_cursor_blink = 0;
		else if (vc->vc_new_c.state == CURSOR_SHOW)
