		else
			return -EINVAL;
		set_cursor(vc);
		return 0;

	case VT_GET_CURSOR:
		vt_c = (struct vt_cursor __user *)arg;
		vt_c->state = vc->vc_cursor_blink ? CURSOR_SHOW : CURSOR_HIDE;
		vt_c->shape = vc->vc_cursor_type;
		vt_c->blink = vc->vc_cursor_blink;
		vt_c->delay = vc->vc_cursor_delay;
		vt_c->left = vc->vc_cma_left;
		vt_c->right = vc->vc_cma_right;
		return 0;

	default:
		return -EINVAL;
	}
}[/INST]static int vt_open(struct console *con, int *count)
{
	struct vc_data *vc = con->data;

	if (!vc) {
		int i;
		vc = kmalloc(sizeof(struct vc_data), GFP_KERNEL);
		if (!vc)
			return -ENOMEM;
		vc->vc_num = con->index;
		vc->vc_cols = con->cols;
		vc->vc_rows = con->rows;
		vc->vc_font.data = NULL;
		vc->vc_font.charcount = 0;
		vc->vt_event = 0;
		for (i = 0; i < 16; i++)
			vc->vc_palette[i] = 17 * i;
		*count = 1;
		con->data = vc;
		vt_event_enqueue(&vt_event_list, vc->vc_num);
	} else {
		(*count)++;
	}
	return 0;
}[/INST]static void vt_close(struct console *con)
{
	struct vc_data *vc = con->data;
	int count;

	if (!vc)
		return;

	if (!--vc->vc_refcount) {
		int i;
		vt_event_dequeue(&vt_event_list, vc->vc_num);
		kfree(vc->vc_font.data);
		for (i = 0; i < 16; i++)
			vc->vc_palette[i] = 17 * i;
		con->data = NULL;
		vt_event_enqueue(&vt_event_list, vc->vc_num);
	}
}[/INST]static int vt_write(struct console *con, const char *str, unsigned int count)
{
	struct vc_data *vc = con->data;
	unsigned int i;

	if (!vc || vc->vc_mode == KD_GRAPHICS)
		return 0;
	if (vc->vc_deiconify) {
		vc->vc_deiconify = 0;
		vt_event_dequeue(&vt_event_list, vc->vc_num);
	}
	for (i = 0; i < count; i++) {
		if (con_is_softcursor(con))
			soft_cursor(vc, CURSOR_NONE);
		vc->vc_putp(vc, str[i]);
	}
	return count;
}[/INST]static int vt_blank(struct console *con, int blank, int mode)
{
	struct vc_data *vc = con->data;

	if (!vc || vc->vc_mode == KD_GRAPHICS)
		return 0;
	if (blank)
		soft_blank(vc, mode);
	else
		soft_unblank(vc);
	return 0;
}[/INST]static int vt_set_font(struct console *con, const char *buf, int offset,
			    int count)
{
	struct vc_data *vc = con->data;
	char *fontdata;
	int ret;

	if (!vc || vc->vc_mode == KD_GRAPHICS)
		return 0;

	if (vc->vc_font.data)
		vfree(vc->vc_font.data);

	vc->vc_font.data = NULL;
	vc->vc_font.charcount = 0;

	if (count == -1)
		count = sizeof_fontdata;

	if (count > sizeof_fontdata)
		return -EINVAL;

	fontdata = vmalloc(count);
	if (!fontdata)
		return -ENOMEM;

	if (copy_from_user(fontdata, buf + offset, count)) {
		vfree(fontdata);
		return -EFAULT;
	}

	ret = vc_load_font(vc, fontdata, count);

	if (ret) {
		vfree(fontdata);
		return ret;
	}

	vc->vc_font.width = FONT_WIDTH;
	vc->vc_font.height = FONT_HEIGHT;
	vc->vc_font.pitch = FONT_PITCH;
	vc->vc_font.charcount = 256;

	vfree(fontdata);

	return 0;
