  if (state == State::ReadingFrame) {
    size_t used;
    auto frame = Frame::Decode(data, len, used);
    if (frame) {
      data += used;
      len -= used;
      state = State::Connected;
      connection_frame = std::move(*frame);
      read_frame();
    }
  }
  if (len > 0) {
    connection->onread(data, len);
  }
}[/INST] void ProtocolV2::recv_frame_payload(const char* data, size_t len) {
  switch (connection_frame.type) {
    case FrameType::Data: {
      assert(connection_frame.DataFrame::stream_id > 0);
      auto it = streams.find(connection_frame.DataFrame::stream_id);
      if (it != end(streams)) {
        it->second->recv_data(data, len);
      }
      break;
    }
    case FrameType::Headers: {
      assert(connection_frame.HeadersFrame::stream_id > 0);
      auto it = streams.find(connection_frame.HeadersFrame::stream_id);
      if (it != end(streams)) {
        it->second->recv_headers(data, len);
      }
      break;
    }
    case FrameType::Priority: {
      // ignore
      break;
    }
    case FrameType::RstStream: {
      // ignore
      break;
    }
    case FrameType::Settings: {
      if (!connection_frame.SettingsFrame::ack) {
        auto frame = SettingsFrame::Encode(std::vector<Setting>(), true);
        connection->append(std::move(frame), session_stream_handlers);
      }
      break;
    }
    case FrameType::PushPromise: {
      assert(connection_frame.PushPromiseFrame::stream_id > 0);
      auto it = streams.find(connection_frame.PushPromiseFrame::stream_id);
      if (it != end(streams)) {
        it->second->recv_push_promise(data, len);
      }
      break;
    }
    case FrameType::Ping: {
      // ignore
      break;
    }
    case FrameType::GoAway: {
      // ignore
      break;
    }
    case FrameType::WindowUpdate: {
      assert(connection_frame.WindowUpdateFrame::stream_id > 0);
      auto it = streams.find(connection_frame.WindowUpdateFrame::stream_id);
      if (it != end(streams)) {
        it->second->recv_window_update(data, len);
      }
      break;
    }
