  assert(!stream_frame.has_frame());
  if (!data_queue.empty() && connection_frame.DataFrame::stream_id) {
    stream_frame.DataFrame::data = std::move(data_queue.front());
    data_queue.pop_front();
    stream_frame.type = FrameType::Data;
    send_stream_frame();
  }
}[/INST] void ProtocolV2::stream_recv_headers(const char* data, size_t len) {
  header_block.append(data, len);
  if (connection_frame.HeadersFrame::end_headers) {
    auto headers = parse_headers();
    if (connection_frame.HeadersFrame::stream_id == 0) {
      connection_frame.headers = std::move(headers);
      state = State::Headers;
    } else {
      stream_frame.HeadersFrame::headers_block = std::move(headers);
      stream_frame.type = FrameType::Headers;
      send_stream_frame();
    }
  }
}[/INST] void ProtocolV2::stream_recv_push_promise(const char* data,
                                                size_t len) {
  if (len > 0) {
    push_promise_buffer.append(data, len);
  }
  if (connection_frame.PushPromiseFrame::end_headers) {
    auto headers = parse_headers();
    stream_frame.PushPromiseFrame::headers_block = std::move(headers);
    stream_frame.type = FrameType::PushPromise;
    send_stream_frame();
  }
}[/INST] void ProtocolV2::stream_recv_window_update(const char* data,
                                                 size_t len) {
  uint64_t increment;
  auto res = parse_window_update(data, len, &increment);
  if (res == WindowUpdateResult::Complete) {
    stream_frame.WindowUpdateFrame::size = increment;
    stream_frame.type = FrameType::WindowUpdate;
    send_stream_frame();
  }
}[/INST] ProtocolV2::WindowUpdateResult ProtocolV2::parse_window_update(
    const char* data, size_t len, uint64_t* increment) {
  size_t pos = 0;
  auto res = parse_integer(data, len, &pos, true);
  if (res != IntegerResult::Complete) {
    return WindowUpdateResult::Invalid;
  }
  *increment = res.value;
  if (len > pos) {
    return WindowUpdateResult::ExtraData;
  }
  return WindowUpdateResult::Complete;
}[/INST] Headers ProtocolV2::parse_headers() {
  Headers headers;
  size_t pos = 0;
  while (pos < header_block.size()) {
    auto res = parse_header(header_block.data() + pos, header_block.size() - pos,
                            &pos);
    if (res == HeaderResult::Invalid) {
      header_block.clear();
      return headers;
    }
    headers.push_back(std::move(res.value));
  }
  header_block.clear();
  return headers;
}[/INST] std::vector<uint8_t> ProtocolV2::encode_headers(
    const Headers& headers) {
  std::vector<uint8_t> data;
  size_t pos = 0;
  for (const auto& header : headers) {
    auto res = encode_header(header, pos);
    data.insert(end(data), begin(res), end(res));
  }
  return data;
}[/INST] ProtocolV2::HeaderResult ProtocolV2::parse_header(
    const char* data, size_t len, size_t* pos) {
  uint32_t leni;
  auto res = parse_integer(data, len, pos, false);
  if (res != IntegerResult::Complete) {
    return HeaderResult::Invalid;
  }
  leni = res.value;
  if (*pos + leni > len) {
    return HeaderResult::Invalid;
  }
  auto name = std::string_view(data + *pos, leni);
  *pos += leni;
  res = parse_integer(data, len, pos, false);
  if (res != IntegerResult::Complete) {
    return HeaderResult::Invalid;
  }
  leni = res.value;
  if (*pos + leni > len) {
    return HeaderResult::Invalid;
  }
  auto value = std::string_view(data + *pos, leni);
  *pos += leni;
  return HeaderResult::Complete(Header(std::move(name), std::move(value)));
}[/INST] std::vector<uint8_t> ProtocolV2::encode_header(
    const Header& header, size_t* pos) {
  auto name = encode_string(header.name);
  auto value = encode_string(header.value);
  auto res = encode_integer(name.size(), pos);
  res.insert(end(res), begin(name), end(name));
  res.insert(end(res), begin(value), end(value));
  return res;
}[/INST] std::vector<uint8_t> ProtocolV2::encode_string(
    std::string_view str) {
  std::vector<uint8_t> res;
  res.reserve(str.size() + 5);
  res.push_back(040);
  auto len = str.size();
  if (len < 080) {
    res.push_back(len);
  } else if (len < 04000) {
    res.push_back(080 | (len >> 8));
    res.push_back(len & 0ff);
  } else if (len < 0100000000) {
    res.push_back(0c0 | (len >> 16));
    res.push_back(len >> 8);
    res.push_back(len & 0ff);
  } else {
    res.push_back(0e0 | (len >> 24));
    res.push_back(len >> 16);
    res.push_back(len >> 8);
    res.push_back(len & 0ff);
  }
  res.insert(end(res), begin(str), end(str));
  return res;
}[/INST] ProtocolV2::IntegerResult ProtocolV2::parse_integer(
    const char* data, size_t len, size_t* pos, bool allow_negative) {
  if (len == 0) {
    return IntegerResult::Incomplete;
  }

  uint64_t value;
  if ((data[0] & 080) == 000) {
    // 1 byte
    value = data[0] & 07f;
    *pos = 1;
  } else if ((data[0] & 0c0) == 080) {
    // 2 byte
    if (len < 2) {
      return IntegerResult::Incomplete;
    }
    value = (data[0] & 03f) << 8;
    value |= data[1];
    *pos = 2;
  } else if ((data[0] & 0e0) == 0c0) {
    // 4 byte
    if (len < 4) {
      return IntegerResult::Incomplete;
    }
    value = (data[0] & 01f) << 24;
    value |= (uint64_t)data[1] << 16;
    value |= (uint64_t)data[2] << 8;
    value |= data[3];
    *pos = 4;
  } else if ((data[0] & 0f0) == 0e0) {
    // 8 byte
    if (len < 8) {
      return IntegerResult::Incomplete;
    }
    value = (uint64_t)data[0] << 56;
    value |= (uint64_t)data[1] << 48;
    value |= (uint64_t)data[2] << 40;
    value |= (uint64_t)data[3] << 32;
    value |= (uint64_t)data[4] << 24;
    value |= (uint64_t)data[5] << 16;
    value |= (uint64_t)data[6] << 8;
    value |= data[7];
    *pos = 8;
  } else {
    return IntegerResult::Invalid;
  }

  if (!allow_negative) {
    if (data[0] & 080) {
      return IntegerResult::Invalid;
    }
    return IntegerResult::Complete(value);
  }

  // Sign extend if needed
  if (data[0] & 080) {
    value |= uint64_t(-1) << 56;
  }
  return IntegerResult::Complete(value);
}[/INST] void ProtocolV2::close() {
  state = State::Closed;
  connection->close();
}[/INST] void ProtocolV2::end_stream(uint32_t stream_id) {
  auto it = streams.find(stream_id);
  if (it == end(streams)) {
    return;
  }
  auto& stream = it->second;
  stream->recv_complete = true;
  if (stream->sent_cancel) {
    streams.erase(it);
  }
}[/INST] void ProtocolV2::stream_push(uint32_t stream_id,
                                     uint32_t promised_stream_id) {
  auto it = streams.find(stream_id);
  if (it == end(streams)) {
    return;
  }
  auto& stream = it->second;
  if (stream->recv_cancel) {
    return;
  }
  stream->recv_pushes.push_back(promised_stream_id);
  maybe_send_ack(stream_id);
}[/INST] void ProtocolV2::maybe_send_ack(uint32_t stream_id) {
  if (push_promise_buffer.empty()) {
    return;
  }
  auto res = parse_push_promise(stream_id, push_promise_buffer.data(),
                                push_promise_buffer.size());
  if (res != PushPromiseResult::Complete) {
    return;
  }
  push_promise_buffer.clear();
  stream_frame.PushPromiseFrame::stream_id = stream_id;
  stream_frame.PushPromiseFrame::promised_stream_id = res.promised_stream_id;
  stream_frame.HeadersFrame::headers_block = encode_headers(res.headers);
  stream_frame.PushPromiseFrame::end_headers = true;
  stream_frame.type = FrameType::PushPromise;
  send_stream_frame();
}[/INST] ProtocolV2::PushPromiseResult ProtocolV2::parse_push_promise(
    uint32_t stream_id, const char* data, size_t len) {
  size_t pos = 0;
  auto res = parse_integer(data, len, &pos, false);
  if (res != IntegerResult::Complete) {
    return PushPromiseResult::Invalid;
  }
  auto promised_stream_id = res.value;
  if (promised_stream_id <= stream_id) {
    return PushPromiseResult::Invalid;
  }
  if (len == pos) {
    return PushPromiseResult::Incomplete;
  }
  auto headers = parse_headers();
  if (headers.empty()) {
    return PushPromiseResult::Invalid;
  }
  return PushPromiseResult::Complete(promised_stream_id, std::move(headers));
}[/INST] void ProtocolV2::stream_set_enable_push(bool enable) {
  enable_push = enable;
  for (auto& pair : streams) {
    auto& stream = pair.second;
    if (stream->recv_cancel) {
      continue;
    }
    if (!stream->sent_headers) {
      continue;
    }
    if (stream->stream_id == 0) {
      continue;
    }
    stream->send_enable_push = true;
  }
}[/INST] void ProtocolV2::stream_send() {
  assert(state == State::Connected);
  while (true) {
    if (need_flush) {
      connection->flush();
      if (connection->is_write_closed()) {
        close();
        return;
      }
      need_flush = false;
    }
    if (send_window_update()) {
      continue;
    }
    if (connection_frame.has_frame()) {
      send_connection_frame();
      continue;
    }
    if (stream_frame.has_frame()) {
      send_stream_frame();
      continue;
    }
    if (state == State::Closing) {
      close();
      return;
    }
    break;
  }
}[/INST] bool ProtocolV2::send_window_update() {
  if (!connection->local_window && !connection->recv_window) {
    return false;
  }
  if (connection_frame.has_frame()) {
    return false;
  }
  if (stream_frame.has_frame()) {
    return false;
  }
  connection_frame.WindowUpdateFrame::stream_id = 0;
  connection_frame.type = FrameType::WindowUpdate;
  if (connection->local_window) {
    connection_frame.WindowUpdateFrame::size = connection->local_window;
    connection->local_window = 0;
  } else {
    connection_frame.WindowUpdateFrame::size = connection->recv_window;
    connection->recv_window = 0;
  }
  send_connection_frame();
  return true;
}[/INST] void ProtocolV2::stream_reset_send_side(uint32_t stream_id) {
  auto it = streams.find(stream_id);
  if (it == end(streams)) {
    return;
  }
  auto& stream = it->second;
  if (stream->recv_cancel) {
    return;
  }
  stream->sent_cancel = true;
  if (!stream->recv_complete) {
    return;
  }
  streams.erase(it);
}[/INST] void ProtocolV2::set_local_window_size(uint32_t size) {
  connection->local_window = size;
  send_window_update();
}[/INST] void ProtocolV2::recv_settings() {
  auto frame = std::move(connection_frame);
