		DEBUG(0, ("talloc failed\n"));
		goto fail;
	}
	fsp->fh->fd = -1;
	fsp->lock_ct = lock;
	fsp->private_data = fsp;

	share_mode_init(fsp);

	if (create_new) {
		if (!smb2req->cancel_is_close) {
			int flags = smb2req->cancel;
			files_struct_init(fsp, smb2req, parent, lock);
			if (!open_file(fsp, h, flags)) {
				goto fail;
			}
			return fsp;
		}
		/* Cancel is close, fall through and close an
		 * existing file handle. */
	}

	if (parent != NULL) {
		/* Child always inherit read access to the share. */
		parent->share_access |= ACCESS_READ;
	}

	if (smb2req != NULL) {
		struct files_struct *sfsp;
		uint32_t root_flags = 0;

		TALLOC_FREE(smb2req->fsp);
		smb2req->fsp = fsp;
		files_struct_register(fsp);

		if (parent == NULL) {
			/* This is a root fsp. */
			root_flags = smb2req->root_flags;
			fsp->root_flags = root_flags;
		}

		if (smb2req->oplock_type) {
			fsp->oplock_type = smb2req->oplock_type;
		}

		if (smb2req->is_smb1) {
			fsp->smb1.is_smb1 = true;
			fsp->smb1.ejected = false;
			fsp->smb1.smb1req = smb2req->smb1req;
			smb2req->smb1req->fsp = fsp;

			if (!smb1_is_valid_pid(smb2req->smb1req->pid)) {
				goto fail;
			}
		} else {
			fsp->smb1.is_smb1 = false;
			fsp->smb2.smb2req = smb2req;
			smb2req->fsp = fsp;

			if (!smb2_is_valid_pid(smb2req->smb2.pid)) {
				goto fail;
			}
		}

		sfsp = smb2_get_smb1_fsp(sconn, smb2req, parent);
		if (sfsp != NULL) {
			if (sfsp->oplock_type) {
				fsp->oplock_type = sfsp->oplock_type;
			}
			if (sfsp->lock_count) {
				fsp->lock_count = sfsp->lock_count;
			}
			if (sfsp->close_count) {
				fsp->close_count = sfsp->close_count;
			}
			if (sfsp->can_write) {
				fsp->can_write = true;
			}
		}

		if (parent == NULL) {
			/* No parent, so this is a root fsp. */
			if (root_flags & SMB2_ROOT_ASYNC) {
				fsp->aio_fildes = talloc(fsp, int);
				if (fsp->aio_fildes == NULL) {
					DEBUG(0, ("talloc failed\n"));
					goto fail;
				}
				*fsp->aio_fildes = -1;
			}

			if ((root_flags & SMB2_ROOT_RETURN_BACKUP_INVALID) &&
			    IS_BACKUP_INTENT(smb2req)) {
				fsp->backup_invalid = true;
			}
		}

		if (!smb2req->no_oplock) {
			/*
			 * Ask the oplock manager code to check for oplocks.
			 * This is a no-op if oplocks are not supported for
			 * this share.
			 */
			share_mode_oplock_request(fsp->lock_ct, fsp);
		}

		/*
		 * If we get a reparse point from the wire, and the
		 * underlying file isn't a reparse point, then the
		 * default handler will return an error.  A reparse
		 * handler can overwrite this with a talloc'd string
		 * if appropriate.
		 */
		fsp->reparse_tag = talloc_strdup(fsp,
						smb2req->reparse_tag);

		fsp->sfh = smb2req->sfh;
	} else {
		fsp->smb1.is_smb1 = true;
	}

	files_struct_init(fsp, NULL, parent, lock);

	return fsp;
fail:
	talloc_free(fsp);
	return NULL;
