			if (bpf_pseudo_call(insn)) {
				/* point imm points to the start of the callee */
				imm = env->subprog_info[insn->off].start;
				callee = insn->off;
			} else {
				/* for eplicit call, imm points to the callee
				 * insn, for implicit call, imm points to
				 * insn after the callee
				 */
				imm = env->insn_au_data[i].call_imm;
				callee = insn->imm + imm - 1;
			}

			if (insn->code == (BPF_JMP | BPF_CALL) &&
			    callee != i + 1) {
				WARN_ONCE(1, "verifier bug. Expected jump-to-end insn at %d\n",
					  i);
				err = -EFAULT;
				goto out_unlock_maps;
			}

			if (insn->code != (BPF_JMP | BPF_CALL) &&
			    callee != i) {
				WARN_ONCE(1, "verifier bug. Expected eplicit fall-through insn at %d\n",
					  i);
				err = -EFAULT;
				goto out_unlock_maps;
			}

			if (map && insn->code == (BPF_MAP_LOOKUP_ELEM | BPF_PSEUDO_MAP) &&
			    env->insn_au_data[i].subprog != subprog) {
				WARN_ONCE(1, "verifier bug. Expected map %p to be used by subprog %d\n",
					  map, env->insn_au_data[i].subprog);
				err = -EFAULT;
				goto out_unlock_maps;
			}
		}
	}

	err = bpf_prog_alloc_jited_linfo(env);
	if (err)
		goto out_unlock_maps;

	for (i = 0; i < env->insn_cnt; i++) {
		insn = &env->insn[i];
		if (!bpf_pseudo_call(insn))
			continue;
		subprog = insn->off;
		insn->imm = env->subprog_info[subprog].start_func;
	}

	old_bpf_func = env->bpf_func;
	env->bpf_func = bpf_jit_compile(env->prog);
	if (!env->bpf_func) {
		err = -ENOMEM;
		goto out_unlock_maps;
	}

	if (old_bpf_func != env->bpf_func)
		bpf_prog_free(old_bpf_func);

	for (subprog = 0; subprog < env->subprog_cnt; subprog++) {
		insn = &env->insn[env->subprog_info[subprog].start_insn];
		for (i = 0; i < env->subprog_info[subprog].end_insn; i++, insn++)
			insn->imm = env->subprog_info[subprog].start + insn->imm;
	}

	/* finally lock all maps that are used by this program, since we
	 * need to keep them pinned so that the JITed image can use them.
	 * We also pass a flag to the map indicating whether the map is
	 * used as a function return site.
	 */
	for (i = 0; i < MAX_NR_MAPS; i++) {
		map_ptr = env->used_map[i];
		if (!map_ptr)
			continue;
		bpf_map_get(map_ptr);
		if (env->subprog_info[0].map == map_ptr)
			map_ptr->ops->map_release_uref(map_ptr);
	}

	return 0;
out_unlock_maps:
	for (i = 0; i < MAX_NR_MAPS; i++) {
		map_ptr = env->used_map[i];
		if (!map_ptr)
			continue;
		bpf_map_put(map_ptr);
	}
	return err;

