      }
      nbdkit_debug (": ma piecelen %" PRIu32, conn->ma_piecelen);
    }
    else if (new_option.option == NBD_OPT_TIMEOUT) {
      if (new_option.optlen != sizeof (uint32_t)) {
        nbdkit_error ("NBD_OPT_TIMEOUT sent with wrong length %zd",
                      new_option.optlen);
        return -1;
      }
      r = read_uint32 (&new_option, &conn->timeout);
      if (r == -1)
