            assert(3 == children[i]->len);
            assert(0 == memcmp("foo", children[i]->str, 3));
            i++;
            assert(REDIS_REPLY_BULK == children[i]->type);
            assert(3 == children[i]->len);
            assert(0 == memcmp("bar", children[i]->str, 3));
            i++;
            assert(REDIS_REPLY_BULK == children[i]->type);
            assert(3 == children[i]->len);
            assert(0 == memcmp("qux", children[i]->str, 3));
            i++;
        }
        assert(NULL == children[3]);
        for (i = 4; i < 5; i++) {
            assert(REDIS_REPLY_BULK == children[i]->type);
            assert(3 == children[i]->len);
            assert(0 == memcmp("corge", children[i]->str, 3));
        }
        freeReplyObject(redisReaderGetReply(reader, &error));
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with allocation error for len buffer. */
        reader = createReader(">1000\r\n");
        redisReaderSetMemoryError(reader, 2);
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(1000 == reader->elements);
        for (i = 0; i < 1000; i++) {
            assert(NULL == reader->element[i]);
        }
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with allocation error for bulk reader. */
        reader = createReader(">2\r\n$5\r\nhello\r\n$5\r\n");
        redisReaderSetMemoryError(reader, 3);
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(2 == reader->elements);
        assert(NULL == reader->element[0]);
        assert(REDIS_REPLY_BULK == reader->element[1]->type);
        assert(5 == reader->element[1]->len);
        assert(0 == memcmp("hello", reader->element[1]->str, reader->element[1]->len));
        freeReplyObject(redisReaderGetReply(reader, &error));
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with invalid bulk length */
        reader = createReader(">2\r\n$-1\r\n$5\r\nhello\r\n");
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(2 == reader->elements);
        assert(REDIS_REPLY_NIL == reader->element[0]->type);
        assert(REDIS_REPLY_BULK == reader->element[1]->type);
        assert(5 == reader->element[1]->len);
        assert(0 == memcmp("hello", reader->element[1]->str, reader->element[1]->len));
        freeReplyObject(redisReaderGetReply(reader, &error));
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with valid and then invalid bulk length */
        reader = createReader(">2\r\n$5\r\nhello\r\n$-1\r\n");
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(2 == reader->elements);
        assert(REDIS_REPLY_BULK == reader->element[0]->type);
        assert(5 == reader->element[0]->len);
        assert(0 == memcmp("hello", reader->element[0]->str, reader->element[0]->len));
        assert(REDIS_REPLY_NIL == reader->element[1]->type);
        freeReplyObject(redisReaderGetReply(reader, &error));
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with too long push length */
        reader = createReader(">4294967296\r\n");
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(4294967296 == reader->elements);
        for (i = 0; i < 3; i++) {
            assert(NULL == reader->element[i]);
        }
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with invalid push length */
        reader = createReader(">-1\r\n");
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(-1 == reader->elements);
        assert(REDIS_ERR == redisReaderGetReply(NULL, NULL));
        free_reader(reader);
        assert(NULL == reader);

        /* Check with -1 length bulk replies in push replies */
        reader = createReader(">3\r\n$5\r\nhello\r\n$-1\r\n$5\r\nhello\r\n");
        assert(REDIS_REPLY_PUSH == redisReaderGetReply(reader, NULL));
        assert(3 == reader->elements);
        assert(REDIS_REPLY_BULK == reader->element[0]->type);
        assert(5 == reader->element[0]->len);
        assert(0 == memcmp("hello", reader->element[0]->str, reader->element[0]->len));
        assert(REDIS_REPLY_NIL == reader->element[1]->type);
        assert(REDIS_REPLY_BULK == reader->element[2]->type);
        assert(5 == reader->element[2]->len);
        assert(0 == memcmp("hello", reader->element[2]->str, reader->element[2]->len));
        len = redisReaderGetReply(reader, &error);
        assert(REDIS_ERR == len);
        assert(reader->err == REDIS_ERR_EOF);
        free_reader(reader);
        assert(NULL == reader);
    }

