    char_u	*sub_char = NULL;
    int		sub_len = 0;
    int		lock = FALSE;

    try = &su->su_try;
    chars = try->try_cstack;

    if (depth >= try->try_top)
    {
	// At the bottom of the trie, score the word.
	scorep = add_to_suglist(su, score, TRUE, what, flags);
	if (scorep == NULL)
	    return;
	scorep->tsc_flags = try->try_flags;
	// Include the compounding flag in the flags for sorting.
	if (try->try_flags & TSF_COMPOUND)
	    scorep->tsc_flags |= SFF_COMP;
	scorep->tsc_score = score;
