	scorep->tsc_word = vim_strsave_undup(try->try_word);
	if (scorep->tsc_word == NULL)
	    return;
	// Add the last (partial) character.
	n = ucs_to_buf(ucs, buf);
	cp = buf;
	while (n-- > 0)
	    *scorep->tsc_word = *cp++;
	*scorep->tsc_word = 0;
	slen = (int)STRLEN(scorep->tsc_word);

	// Apply soundfold, if any.
	if (try->try_sflist != NULL)
	{
	    apply_soundfold(su, scorep->tsc_word, try->try_sflist,
					scorep->tsc_word, MAXWLEN, &slen);
	    // If the word becomes empty after soundfolding remove it.
	    if (slen == 0)
		scorep->tsc_word[0] = 0;
	}

	// If a prefix was handled separately, add it now.
	if (try->try_prefix != NULL)
	{
	    scorep->tsc_word = concat_strs(scorep->tsc_word, try->try_prefix);
	}

	// Use the score for the (complete) word as the key for sorting.
	scorep->tsc_score = score_word(su, lp, scorep->tsc_word,
							   what, flags, score);

