	scorep = get_sugscore(su, score, what, flags);
	if (scorep == NULL)
	    return;

	// Get the list of characters to try.
	n = get_contet_chars(su, lp, plane, ucs, depth,
							  &chars, &utf_len);

	// If the character was substituted, use the "normal" one here.
	// (The one that doesn't produce a soundfold change.)
	if (try->try_subchar != NULL)
	{
	    sub_char = try->try_subchar;
	    sub_len = try->try_sublen;
	    lock = TRUE;
	}
	else if (try->try_flags & TSF_SUBCHAR)
	{
	    for (i = 0; i < sub_len; ++i)
		if (sub_char[i] == ucs)
		{
		    was_subbed = TRUE;
		    break;
		}
	}
	else if (n == 1)
	{
	    // Only one char to try, use it.
	    sub_char = (char_u *)chars;
	    sub_len = ucs_to_buf(*chars, buf);
	    lock = TRUE;
	}

	if (!lock)
	{
	    // Remember the character(s) to try.
	    try->try_subchar = (char_u *)chars;
	    try->try_sublen = utf_len;
	}

	for (i = 0; i < n; ++i)
	{
	    c = chars[i];

	    // Skip characters that would not change the soundfold
	    // result when substituting.  Also skip characters that
	    // would produce the same soundfold result when swapped
	    // with the current character.
	    if ((lock && !should_keep(c, ucs))
		    || (!lock && !should_swap(c, ucs, scorep->tsc_score)))
		continue;

	    suggest_trie_walk(su, lp, plane, c, scorep->tsc_score, depth + 1,
					what, flags);

	    // If the substitution list is exhausted and we got a new
	    // character that scores higher than the previous ones,
	    // keep it and the ones that follow for a while.  This
	    // helps with words that have a rare first letter, e.g.
	    // "i", "e", "o" in Dutch.
	    if (try->try_flags & TSF_SUBCHAR)
	    {
		int	new_score = soundfold_score(lp, c, ucs);

		if (new_score > scorep->tsc_score)
		{
		    do_combine = TRUE;
		    if (slen + 1 >= MAXWLEN)
			break;
		    buf[slen] = nfc_to_compose(c, ucs);
		    scorep->tsc_score = new_score;
		}
	    }
	}

