	{
	    // Combine the kept characters with the previous ones.
	    // This calls the recursive suggest_trie_walk() for each
	    // kept character.
	    for (i = 0; i < sub_len; ++i)
	    {
		c = sub_char[i];
		if (c == ucs && was_subbed)
		    continue; // skip, already tried this one
		suggest_trie_walk(su, lp, plane, c, scorep->tsc_score,
					depth + 1, what, flags);
	    }
