	// Clear the list of characters to try.
	if (!lock)
	    try->try_subchar = NULL;
    }

    // Handle the "ban this character" flags set by other words.
    if (flags & SFF_BAN)
	scorep->tsc_flags |= flags & SFF_BAN;

    // Handle a prefix that was handled separately.
    if (try->try_prefix != NULL)
    {
	vim_free(try->try_prefix);
	try->try_prefix = NULL;
    }

    if (sub_char != NULL && !lock)
    {
	vim_free(sub_char);
	try->try_subchar = NULL;
    }
}

