static oe_result_t _hostfs_write(
    int desc, const void* buf, size_t count, size_t* bytes_written)
{
    oe_result_t result;
    if (desc < 0)
        return OE_FAILURE;
    if (!buf || !count || !bytes_written)
        return OE_INVALID_PARAMETER;

    *bytes_written = 0;
    size_t bytes_left = count;
    while (bytes_left > 0)
    {
        size_t bytes_to_write = (bytes_left > OE_HOSTFS_WRITE_MAX_SIZE)
                                    ? OE_HOSTFS_WRITE_MAX_SIZE
                                    : bytes_left;
        result = oe_syscall_write_ocall(
            desc, (const uint8_t*)buf + count - bytes_left, bytes_to_write,
            bytes_written);
        if (result != OE_OK)
            return result;

        bytes_left -= *bytes_written;
    }

    return OE_OK;
}

