static int bpf_map_mmap_open(struct vm_area_struct *vma)
{
	struct bpf_map *map = vma->vm_private_data;
	int ret = 0;

	if (!(vma->vm_flags & VM_MAYWRITE))
		return 0;

	/* can't handle the case when the epected write count overflow */
	if (map->writecnt >= INT_MAX)
		return -EBUSY;

	/*
	 * Use a mutex to protect the map->writecnt increment because
	 * a) writecnt is of type u32 and may overflow if a CPU does
	 *    a wraparound while another CPU is in the middle of incrementing
	 *    it and has done the increment but not yet written it back
	 *    to memory.
	 * b) even though in most cases the map->writecnt operation is
	 *    protected by the map->freeze_refcnt, it can be seen as
	 *    a strong barrier (see bpf_map_freeze) and it is safer
	 *    to use a mutex in addition to the freeze_refcnt.
	 */
	if (mutex_lock_interruptible(&map->freeze_mute))
		return -EINTR;

	map->writecnt++;
	mutex_unlock(&map->freeze_mute);

	return ret;
}

