Device* GetDeviceForInput(EagerContet* ct, TensorHandle* handle,
                            bool* is_tpu) {
  Device* ret = nullptr;
  *is_tpu = false;
  if (handle->Type() == TensorHandle::LOCAL) {
    // EagerTensor
    ret = handle->device();
  } else if (handle->Type() == TensorHandle::REMOTE) {
    // RemoteTensor
    const Device* source_device = handle->SourceDevice();
    if (source_device != nullptr) {
      // If the remote tensor has a source device, we try to place the
      // op on that device as well.
      ret = ct->SelectDevice(*source_device, /* try_to_place_on_tpu= */ false);
      // If that fails, we return the source device.
      if (ret == nullptr) {
        ret = const_cast<Device*>(source_device);
      }
    } else {
      // If the remote tensor has no source device, we place the op on the
      // device where the remote tensor is.
      ret = ct->SelectDevice(*handle->device(),
                             /* try_to_place_on_tpu= */ false);
    }
    if (ret == nullptr) {
      ret = handle->device();
    }
  } else if (handle->Type() == TensorHandle::COMPOSITE) {
    // CompositeTensor
    const Device* resource_device = handle->ResourceDevice();
    if (resource_device != nullptr) {
      // If the resource tensor has a resource device, we try to place the
      // op on that device as well. We pass in 'true' for try_to_place_on_tpu
      // since a resource op placed on the CPU might still end up running on
      // the TPU (e.g. if the resource itself is a TPU resource).
      ret = ct->SelectDevice(*resource_device, /* try_to_place_on_tpu= */ true);
      if (ret == nullptr) {
        ret = const_cast<Device*>(resource_device);
      }
    } else {
      // If the resource tensor has no resource device, we place the op on the
      // device where the resource tensor is.
      ret = ct->SelectDevice(*handle->device(),
                             /* try_to_place_on_tpu= */ true);
    }
    if (ret == nullptr) {
      ret = handle->device();
    }
  }
  TF_CHECK_OK(ct->DeviceIsLocal(ret));
