static void destroy_session(struct _sasl_session *session)
{
	s_log(SSL, "Destroying session %s", session->uniqueid);

	if (session->client)
		mowgli_node_delete(session->client, &session->server->clients);

	if (session->server)
		mowgli_node_delete(session->server, &session->client->servers);

	if (session->outq)
		free(session->outq);

	if (session->mech)
		session->mech->free_fn(session->mech, session);

	if (session->parent)
		session->parent->child = NULL;

	free(session);
