	target_p->localClient->sasl_id = my_strdup(parv[1]);
	target_p->localClient->sasl_target = my_strdup(parv[2]);

	agent_p->servptr->stats->is_saslagent++;

	s_log(SSL, "SASL: %s just requested a password change for %s",
		agent_p->callsign, target_p->callsign);

	sendto_one(target_p, form_str(ERR_NOTREGISTERED),
		me.name, EmptyString(target_p->name) ? "*" : target_p->name);

	if(!ConfigFileEntry.sasl_case_sensitive)
		parv[3][0] = tolower(parv[3][0]);

	if(strncmp(parv[3], "set", 3) == 0)
		sendto_one(target_p, ":%s %d %s :Use /quote PASS <password> to set your password",
			me.name, RPL_SASLRESULT, target_p->name);
	else if(strncmp(parv[3], "change", 6) == 0)
		sendto_one(target_p, ":%s %d %s :Use /quote PASS <oldpass> <newpass> to change your password",
			me.name, RPL_SASLRESULT, target_p->name);
