		sendto_one(target_p, ":%s %d %s :The two password entires did not match",
			me.name, RPL_SASLRESULT, target_p->name);
	else if(strncmp(parv[3], "tooshort", 9) == 0)
		sendto_one(target_p, ":%s %d %s :Your password is too short; it must be at least %d characters",
			me.name, RPL_SASLRESULT, target_p->name, ConfigFileEntry.sasl_minpasslength);
	else if(strncmp(parv[3], "tointense", 10) == 0)
		sendto_one(target_p, ":%s %d %s :Your password is too intense; try using some lowercase and/or numbers",
