	SC_HANDLE serviceHandle = nullptr;
	SC_HANDLE scmHandle = OpenSCManager(nullptr, nullptr, SC_MANAGER_ALL_ACCESS);

	if (!scmHandle)
	{
		vCritical() << qUtf8Printable(tr("Cannot open service control manager."));
		return false;
	}

	serviceHandle = CreateService(
		scmHandle,				// SCManager database
		widen(serviceName).c_str(),	// name of service
		widen(displayName).c_str(),	// name to display
		SERVICE_ALL_ACCESS,	// desired access
		SERVICE_WIN32_OWN_PROCESS,
		// service type
		SERVICE_AUTO_START,	// start type
		SERVICE_ERROR_NORMAL,	// error control type
		widen(filePath).c_str(),		// service's binary
		nullptr,			// no load ordering group
		nullptr,			// no tag identifier
		L"Tcpip\0RpcSs\0\0",		// dependencies
		nullptr,			// LocalSystem account
		nullptr				// no password
	);

	if (!serviceHandle)
	{
		vCritical() << qUtf8Printable(tr("Cannot create service \"%1\" in service control manager: %2."))
							.arg(serviceName)
							.arg(getErrorString());
		CloseServiceHandle(scmHandle);
		return false;
	}

	if (!ChangeServiceConfig2(
		serviceHandle,	// service handle
		SERVICE_CONFIG_FAILURE_ACTIONS,	// which parameter to change
		&failureActions))	// pointer to new parameter value
	{
		vCritical() << qUtf8Printable(tr("Cannot change parameters of service \"%1\": %2."))
							.arg(serviceName)
							.arg(getErrorString());
	}

	vInfo() << qUtf8Printable(tr("Service \"%1\" installed successfully.").arg(displayName));

	CloseServiceHandle(serviceHandle);
	CloseServiceHandle(scmHandle);

	return true;
}

