static void test_nghttp2_session_memusage(void) {
  nghttp2_session *session;
  nghttp2_session_callbacks callbacks;
  nghttp2_outbound_item *item;
  nghttp2_stream *stream;

  memset(&callbacks, 0, sizeof(nghttp2_session_callbacks));
  callbacks.send_callback = null_send_callback;

  nghttp2_session_client_new(&session, &callbacks, NULL);
  stream = open_sent_stream(session, 1);
  CU_ASSERT(0 == nghttp2_session_add_rst_stream(session, stream, NGHTTP2_NO_ERROR));
  item = nghttp2_session_get_net_ob_item(session);
  CU_ASSERT(NGHTTP2_RST_STREAM == item->frame.hd.type);
  CU_ASSERT(1 == item->frame.rst_stream.stream_id);
  CU_ASSERT(0 == nghttp2_session_memusage(session));
  nghttp2_session_del(session);
