  const uint8_t *p1, *p2;
  int diff;
  size_t i;

  p1 = buf1;
  p2 = buf2;

  for (i = 0; i < len; ++i) {
    if (p1[i] != p2[i]) {
      diff = (p1[i] - p2[i]);
      CU_FAIL_at_line("buffer mismatch", __FILE__, __LINE__, diff);
      break;
    }
  }
