HTTPserver::HTTPserver( const std::string& address, const std::string& port, bool use_http, bool self_signed ) :
  webserver{ address, port, use_http, self_signed },
  ssl_cert_{},
  ssl_key_{},
  mg_mgr_{},
  mg_serve_dir_cfg_{},
  http_port_{},
  https_port_{}
{
  mg_mgr_init( &mg_mgr_ );

  // Try to load SSL cert and key
  try {
    load_ssl_cert_and_key();
  }
  catch ( const std::runtime_error& e ) {
    // Rethrow with more information
    throw std::runtime_error{ std::string{ "Could not load SSL certificate and key: " } + e.what() };
  }

  // Check if we have a certificate
  const bool have_cert{ !ssl_cert_.empty() && !ssl_key_.empty() };

  // Set port to 0 to disable
  uint16_t http_p = static_cast<uint16_t>( std::stoul( port ) );
  uint16_t https_p = 0;

  // Swap ports if https first
  if ( !use_http ) {
    std::swap( http_p, https_p );
  }

  // Initialize mongoose with empty config
  struct mg_mgr mgr = {};
  struct mg_connection* c;
  struct mg_addr addr;
  ( void )self_signed;

  mg_mgr_init( &mgr );

  // Setup HTTP server
  c = mg_bind( &mgr, std::to_string( http_p ).c_str(), ( use_http ? MG_F_LISTEN : 0 ) );
  if ( c == nullptr ) {
    throw std::runtime_error{ "Could not create server" };
  }
  mg_set_protocol_http( c );

  // Log all HTTP requests
  mg_register_http_handler( c, nullptr, nullptr, []( struct mg_connection* c,
                                                       int ev,
                                                       void* ev_data,
                                                       void* user_data ) {
    if ( ev == MG_EV_HTTP_REQUEST ) {
      struct mg_http_message* hm = (struct mg_http_message*) ev_data;
      LOG( DEBUG ) << c->label << " HTTP "
                   << (char*) hm->method.p << " " << (char*) hm->uri.p
                   << " (" << (int) hm->status_code << ")";
    }
  } );

  http_port_ = mg_get_listening_port( c );

  // Setup HTTPS server if we have a certificate
  if ( have_cert ) {
    c = mg_bind( &mgr, std::to_string( https_p ).c_str(), ( MG_F_LISTEN | MG_F_SSL ) );
    if ( c == nullptr ) {
      throw std::runtime_error{ "Could not create HTTPS server" };
    }
    mg_set_protocol_http( c );
    ssl_ports_.insert( mg_get_listening_port( c ) );
  }

  // Save port numbers
  http_port_ = mg_get_listening_port( c );
  https_port_ = ( have_cert ? mg_get_listening_port( c ) : 0 );

  // Allow user to override ports
  http_port_ = static_cast<uint16_t>( std::stoul( config_lookup( "server.http_port", std::to_string( http_port_ ) ) ) );
  https_port_ = static_cast<uint16_t>( std::stoul( config_lookup( "server.https_port", std::to_string( https_port_ ) ) ) );

  // Initialize config
  mg_serve_dir_cfg_.root_dir = ".";
  mg_serve_dir_cfg_.list_dir = 1;
  mg_serve_dir_cfg_.show_files = 1;
  mg_serve_dir_cfg_.autoindex = "auto";
  mg_serve_dir_cfg_.mime_types = mime_types;

  // Add /static handler that serves files from /static directory
  mg_bind( &mgr, ":static", MG_F_LISTEN ).then( []( struct mg_connection* c ) {
    mg_set_protocol_http_websocket( c );
  } ).et( []( const std::exception& e ) {
    LOG( ERR ) << "static handler: " << e.what();
  } );

  // Add /serve handler that serves directory
  mg_bind( &mgr, ":serve", MG_F_LISTEN ).then( [this]( struct mg_connection* c ) {
    mg_set_protocol_http_websocket( c );
    c->ev_handler = mg_serve_dir_handler;
    c->ev_data = &mg_serve_dir_cfg_;
  } ).et( []( const std::exception& e ) {
    LOG( ERR ) << "serve handler: " << e.what();
  } );

  // Start the HTTP server thread
  running_ = true;
  server_thread_ = std::thread{ [this] { event_loop(); } };
} // HTTPserver::HTTPserver()

